-- Schema for Domain: engineering | Business: Manufacturing | Version: v1_ecm
-- Generated on: 2026-04-16 07:42:33

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `manufacturing_ecm`.`engineering` COMMENT 'Owns the complete product engineering lifecycle including CAD/CAM models, BOM (Bill of Materials), BoP (Bill of Process), PLM/PDM records, ECN/ECO change management, DFM/DFA analysis, DFMEA/PFMEA documentation, and prototype development. SSOT for product structure, technical specifications, drawings, and engineering change workflows for automation systems and electrification solutions.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`engineering_bom` (
    `engineering_bom_id` BIGINT COMMENT 'Unique system-generated identifier for the Bill of Materials header record. Serves as the primary key for the BOM entity across all integrated systems including SAP PP and Siemens Teamcenter.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: bom.material_number is a STRING reference to the component/assembly this BOM defines. Replacing with a proper FK component_id → component.component_id normalizes the relationship. material_number is r',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: bom.ecn_number is a STRING reference to the ECN that authorized the BOM revision. Replacing with FK ecn_id → ecn.ecn_id enforces referential integrity for the change management workflow. ecn_number is',
    `alternative_bom` STRING COMMENT 'SAP alternative BOM counter (01–99) that distinguishes multiple BOMs for the same material/plant combination, enabling variant or alternative production structures for the same finished good or sub-assembly.. Valid values are `^[0-9]{2}$`',
    `approved_by` STRING COMMENT 'Name or user ID of the authorized approver who released this BOM revision for production use. Part of the formal BOM approval and release workflow in Siemens Teamcenter PLM and SAP PP, ensuring compliance with ISO 9001 document control requirements.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this BOM revision was formally approved and released by the authorized approver. Provides an auditable timestamp for regulatory compliance, quality management system (QMS) traceability, and engineering change management records.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity of the parent assembly for which all component quantities in the BOM are specified. Typically 1 unit but may be set to a batch size (e.g., 100 units) for process manufacturing or high-volume production to improve precision in component quantity calculations.',
    `base_unit_of_measure` STRING COMMENT 'Unit of measure corresponding to the base quantity of the parent assembly (e.g., EA for each, PC for piece, KG for kilogram). Aligns with SAP base unit of measure (MEINS) in the material master.. Valid values are `EA|PC|KG|G|L|M|M2|M3|SET|ROLL|BOX`',
    `category` STRING COMMENT 'SAP BOM category (STLTY) classifying the object type to which the BOM is assigned. Material BOMs define product structures; Equipment BOMs support plant maintenance (PM) and asset management; Functional Location BOMs define site-level structures; WBS BOMs support project-based manufacturing (ETO/MTO).. Valid values are `material_bom|equipment_bom|functional_location_bom|document_structure|wbs_bom`',
    `change_number` STRING COMMENT 'SAP Engineering Change Management (ECM) change number used to control time-phased BOM changes in SAP PP. Enables change-controlled BOM modifications where component additions, deletions, or quantity changes are governed by an approved change record.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `component_count` STRING COMMENT 'Total number of direct child components (line items) defined in this BOM header. Provides a quick indicator of BOM complexity and is used for completeness validation during BOM release and change management reviews.. Valid values are `^[0-9]+$`',
    `costing_relevance` BOOLEAN COMMENT 'Indicates whether this BOM is included in product cost calculations (standard cost estimate) in SAP CO-PC (Product Costing). When true, the BOM components and quantities are used to calculate the Cost of Goods Sold (COGS) and standard cost for the parent material.. Valid values are `true|false`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the primary country where the product defined by this BOM is manufactured. Required for customs declarations, CE Marking compliance, RoHS/REACH regulatory reporting, and export control classification.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this BOM record was initially created in the source system (SAP PP or Siemens Teamcenter). Used for audit trail, data lineage, and lifecycle tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Free-text description of the BOM, providing additional context about the product structure, intended application, or special configuration. Sourced from the BOM header text in SAP PP or the item description in Siemens Teamcenter.',
    `engineering_responsibility` STRING COMMENT 'Name or identifier of the engineering team, department, or responsible engineer who owns this BOM. Used for change management routing, approval workflows, and accountability tracking in Siemens Teamcenter PLM.',
    `export_control_classification` STRING COMMENT 'Export Control Classification Number (ECCN) or Harmonized System (HS) code assigned to the product defined by this BOM. Required for export license determination, trade compliance, and customs documentation for multinational shipments of automation systems and electrification solutions.. Valid values are `^[A-Z0-9-.]{1,20}$`',
    `is_configurable` BOOLEAN COMMENT 'Indicates whether this BOM is a configurable/variant BOM (SAP variant configuration) that supports multiple product configurations from a single super-BOM. Relevant for Assemble-to-Order (ATO) and Engineer-to-Order (ETO) automation systems and electrification solutions.. Valid values are `true|false`',
    `is_phantom_assembly` BOOLEAN COMMENT 'Indicates whether this BOM represents a phantom assembly — a logical grouping of components that does not physically exist as a stocked sub-assembly. Phantom assemblies are exploded through in MRP and production orders, with their components planned directly at the parent level.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 two-letter language code indicating the language in which the BOM description and component texts are maintained. Supports multilingual BOM management for global manufacturing operations across multiple countries and regions.. Valid values are `^[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent modification to this BOM record in the source system. Used for change tracking, delta processing in the Databricks Silver layer, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `level` STRING COMMENT 'Depth level of this BOM within the overall product structure hierarchy. Level 0 represents the top-level finished good; Level 1 represents direct sub-assemblies; deeper levels represent lower-tier components. Used for multi-level BOM explosion in MRP and costing.. Valid values are `^[0-9]+$`',
    `manufacturing_strategy` STRING COMMENT 'Manufacturing execution strategy associated with this BOM, indicating how the parent assembly is produced relative to customer demand. Drives MRP planning parameters, lead time calculations, and order management behavior in SAP PP and Siemens Opcenter MES.. Valid values are `make_to_stock|make_to_order|assemble_to_order|engineer_to_order|configure_to_order`',
    `notes` STRING COMMENT 'Free-text field for engineering notes, special instructions, or contextual remarks associated with this BOM. May include DFM/DFA considerations, APQP notes, PPAP requirements, or special manufacturing constraints relevant to the product structure.',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the BOM, used in engineering and production documents. Corresponds to the BOM number in SAP PP (CS01/CS02) and Siemens Teamcenter BOM Management.. Valid values are `^BOM-[A-Z0-9]{3,20}$`',
    `plant_code` STRING COMMENT 'Four-character SAP plant code identifying the manufacturing facility or production site for which this BOM is valid. A BOM may have plant-specific variants to reflect local production capabilities, tooling, or supplier substitutions.. Valid values are `^[A-Z0-9]{4}$`',
    `product_name` STRING COMMENT 'Human-readable name of the parent product, finished good, or sub-assembly for which this BOM is defined. Sourced from the material master description in SAP MM or the item name in Siemens Teamcenter PLM.',
    `production_version` STRING COMMENT 'SAP production version identifier linking this BOM to a specific routing/work center combination for a given plant. Enables multiple production methods (e.g., different lines or processes) for the same material, each with its own BOM and routing pairing.. Valid values are `^[A-Z0-9]{4}$`',
    `regulatory_compliance_flags` STRING COMMENT 'Pipe-delimited set of regulatory compliance certifications applicable to the product defined by this BOM. Supports compliance reporting for RoHS (Restriction of Hazardous Substances), REACH (Registration, Evaluation, Authorisation and Restriction of Chemicals), CE Marking, and UL (Underwriters Laboratories) certification requirements.. Valid values are `rohs_compliant|reach_compliant|ce_marked|ul_certified|none`',
    `released_timestamp` TIMESTAMP COMMENT 'Date and time when this BOM was formally released to production, making it available for use in MRP runs, production orders, and manufacturing execution in Siemens Opcenter MES. Distinct from approval timestamp — release may follow approval after additional validation steps.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `revision_level` STRING COMMENT 'Engineering revision identifier (e.g., A, B, C, 01, 02) indicating the version of the BOM. Incremented upon each approved Engineering Change Notice (ECN) or Engineering Change Order (ECO) that modifies the product structure.. Valid values are `^[A-Z0-9]{1,10}$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this BOM record originated. Supports data lineage tracking and conflict resolution in the Databricks Silver layer when BOMs are synchronized between SAP S/4HANA PP and Siemens Teamcenter PLM.. Valid values are `SAP_S4HANA|TEAMCENTER|OPCENTER|MANUAL`',
    `status` STRING COMMENT 'Current lifecycle status of the BOM record. Controls whether the BOM is available for use in production planning (MRP), manufacturing execution (MES), or procurement. Released BOMs are active for production; Frozen BOMs are locked for costing; Obsolete/Superseded BOMs are retired.. Valid values are `draft|in_review|approved|released|frozen|obsolete|superseded`',
    `teamcenter_item_code` STRING COMMENT 'Cross-reference identifier of the corresponding BOM or product structure item in Siemens Teamcenter PLM. Enables bidirectional traceability between the SAP PP BOM and the engineering BOM (eBOM) managed in Teamcenter for PLM/PDM alignment.. Valid values are `^[A-Z0-9-]{1,50}$`',
    `type` STRING COMMENT 'Classification of the BOM by its intended use in the product lifecycle. Engineering BOM (eBOM) reflects design intent from PLM/PDM; Manufacturing BOM (mBOM) reflects production structure from MES/ERP; Service BOM supports after-sales and MRO; Sales BOM supports order configuration; Costing BOM supports COGS calculation; Planning BOM supports MRP/MRP II.. Valid values are `engineering_bom|manufacturing_bom|service_bom|sales_bom|costing_bom|planning_bom`',
    `usage` STRING COMMENT 'SAP BOM usage indicator that determines in which business context the BOM is applied (e.g., production orders, plant maintenance work orders, sales order processing, product costing). Corresponds to SAP BOM Usage field (STLAN) in CS01.. Valid values are `production|engineering|universal|plant_maintenance|sales|costing|spare_parts`',
    `valid_from_date` DATE COMMENT 'Date from which this BOM revision becomes effective and valid for use in production planning, MRP runs, and manufacturing execution. Supports time-phased BOM management aligned with Engineering Change Notice (ECN) effectivity dates.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'Date after which this BOM revision is no longer valid for production planning or manufacturing execution. Used to manage BOM supersession when a new revision is released via ECN/ECO. A null value indicates the BOM is open-ended and currently active.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_engineering_bom PRIMARY KEY(`engineering_bom_id`)
) COMMENT 'Bill of Materials header record defining the structured product assembly hierarchy for each finished good, sub-assembly, or configurable automation system. Captures BOM type (engineering BOM, manufacturing BOM, service BOM), effectivity dates, revision level, BOM status, and the owning product or assembly. Links to Siemens Teamcenter BOM Management and SAP PP BOM. SSOT for product structure definitions.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`bom_line` (
    `bom_line_id` BIGINT COMMENT 'Unique surrogate identifier for each individual BOM line item record in the silver layer lakehouse. Serves as the primary key for the bom_line data product.',
    `component_id` BIGINT COMMENT 'Reference to the child component or sub-assembly material master record defined on this BOM line. Identifies the specific part, raw material, or sub-assembly consumed at this level of the product structure.',
    `ecn_id` BIGINT COMMENT 'Reference to the Engineering Change Notice (ECN) or Engineering Change Order (ECO) that authorized the creation or modification of this BOM line item. Supports full change traceability and audit compliance.',
    `engineering_bom_id` BIGINT COMMENT 'Reference to the parent BOM header to which this line item belongs. Enables multi-level BOM explosion and parent-child component hierarchy traversal for MRP and production planning.',
    `parent_material_component_id` BIGINT COMMENT 'Reference to the parent assembly or finished good material master record that owns this BOM line. Supports multi-level BOM explosion by linking child components to their immediate parent assembly.',
    `alternative_item_group` STRING COMMENT 'Groups multiple BOM line items that are interchangeable alternatives for the same functional requirement. During MRP and production order creation, the system selects the preferred or available alternative based on priority and stock availability. Supports substitute component management and supply chain flexibility.. Valid values are `^[A-Z0-9]{1,2}$`',
    `alternative_item_priority` STRING COMMENT 'Numeric priority rank within an alternative item group, where lower numbers indicate higher preference (1 = first choice). Used by MRP and production planning to determine which substitute component to consume first when multiple alternatives are defined for the same functional position.. Valid values are `^[1-9][0-9]?$`',
    `alternative_item_usage_probability` DECIMAL(18,2) COMMENT 'The probability percentage (0–100) that this alternative component will be selected over other alternatives in the same group during production planning. Used by MRP to distribute planned requirements across alternative components proportionally, supporting multi-source procurement strategies.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `bom_item_number` STRING COMMENT 'Sequential item number assigned to this BOM line within the parent BOM header, typically in increments of 10 (e.g., 0010, 0020). Used for ordering and referencing line items within the BOM structure in SAP PP.. Valid values are `^[0-9]{4,6}$`',
    `bom_level` STRING COMMENT 'The hierarchical depth level of this component within the multi-level BOM structure, where level 0 is the finished good, level 1 is the first-tier sub-assembly, and so on. Used for BOM explosion reporting, MRP low-level code assignment, and production scheduling sequencing.. Valid values are `^[0-9]{1,3}$`',
    `bom_usage` STRING COMMENT 'Defines the business purpose for which this BOM is used, corresponding to SAP BOM usage keys (e.g., 1=Production, 2=Engineering/Design, 3=Universal, 4=Plant Maintenance, 5=Sales, 6=Costing). Determines which BOM is selected during MRP, costing, sales order processing, and maintenance planning.. Valid values are `production|engineering|universal|plant_maintenance|sales|costing|spare_parts`',
    `component_number` STRING COMMENT 'The manufacturer or internal part number of the child component as defined in the material master or PLM system. Used for procurement, inventory lookup, and cross-referencing with supplier catalogs and engineering drawings.. Valid values are `^[A-Z0-9-.]{1,40}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this BOM line record was originally created in the source system. Used for audit trail, change history analysis, and data lineage tracking in compliance with ISO 9001 document control requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `effectivity_end_date` DATE COMMENT 'The date after which this BOM line item is no longer valid for production planning and MRP explosion. Used to phase out obsolete components following an Engineering Change Notice (ECN) while maintaining historical BOM traceability for previously manufactured products.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_start_date` DATE COMMENT 'The date from which this BOM line item becomes valid and active for use in production planning and MRP explosion. Supports date-effective BOM management for engineering change implementation, ensuring new component versions are introduced at the correct production date.. Valid values are `^d{4}-d{2}-d{2}$`',
    `find_number` STRING COMMENT 'Balloon or find number referencing the components callout position on the engineering drawing or assembly diagram. Used by manufacturing engineers and quality inspectors to locate the component on the drawing during First Article Inspection (FAI) and assembly.. Valid values are `^[A-Z0-9]{1,10}$`',
    `fixed_quantity_indicator` BOOLEAN COMMENT 'Indicates whether the component quantity on this BOM line is fixed regardless of the production order quantity (true) or variable and proportional to the order quantity (false). Fixed quantities are used for setup materials, tooling, or components consumed once per batch regardless of batch size.. Valid values are `true|false`',
    `is_bulk_material` BOOLEAN COMMENT 'Indicates whether this BOM line item is a bulk material (e.g., adhesives, lubricants, solder paste, wire) that is consumed in variable quantities and typically not individually issued to production orders. Bulk materials are often backflushed or managed via replenishment rather than discrete picking.. Valid values are `true|false`',
    `is_co_product` BOOLEAN COMMENT 'Indicates whether this BOM line item is a co-product or by-product produced alongside the primary output of the manufacturing process. Co-products have positive quantity and receive cost allocation; by-products may have negative cost impact. Relevant for process manufacturing and chemical/electrification solution production.. Valid values are `true|false`',
    `is_phantom_assembly` BOOLEAN COMMENT 'Indicates whether this BOM line represents a phantom assembly — a logical grouping of components that is not physically stocked or produced as a discrete item but is exploded through during MRP to directly consume its child components. Common in modular product structures and configurable BOMs.. Valid values are `true|false`',
    `issue_location` STRING COMMENT 'The warehouse storage location from which this component is issued to the production order or work order. Drives automatic goods issue (backflush) and pick list generation in SAP WM/WMS and Infor WMS for shop floor material replenishment.',
    `item_category` STRING COMMENT 'Classification of the BOM line item type as defined in SAP PP. Stock items (L) are warehouse-managed materials; non-stock items (N) are procured directly to the order; document items (D) reference engineering documents; phantom assemblies (P) are logical groupings not physically stocked; variable-size items (R) have variable dimensions.. Valid values are `stock|non_stock|document|variable_size|class|text|intra_material|phantom`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this BOM line record in the source system. Supports incremental data loading, change detection, and audit trail requirements for engineering change management and quality management system (QMS) compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `long_text` STRING COMMENT 'Extended descriptive text or engineering notes associated with this BOM line item. May include assembly instructions, special handling requirements, quality inspection notes, or engineering change justifications visible to production planners and shop floor operators.',
    `operation_activity_number` STRING COMMENT 'The routing operation or activity number to which this BOM component is assigned for consumption. Links the component to the specific manufacturing step in the Bill of Process (BoP) where it is consumed, enabling accurate work-in-progress (WIP) tracking and operation-level material staging.. Valid values are `^[0-9]{4}$`',
    `operation_lead_time_offset` DECIMAL(18,2) COMMENT 'The number of days (positive or negative) by which the component requirement date is offset from the production order start date. Used in multi-level scheduling to stage component availability at the correct operation step, supporting JIT (Just-In-Time) material staging on the shop floor.',
    `plant_code` STRING COMMENT 'The SAP plant code identifying the manufacturing facility or production site for which this BOM line is valid. BOMs can be plant-specific to accommodate local sourcing, manufacturing processes, or regional regulatory requirements across the multinational enterprise.. Valid values are `^[A-Z0-9]{4}$`',
    `procurement_type` STRING COMMENT 'Indicates whether the component on this BOM line is manufactured in-house (make), externally procured (buy), or can be sourced either way. Drives MRP planning logic to generate either planned production orders or purchase requisitions for the component.. Valid values are `in_house|external|both`',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of the child component required to produce one unit of the parent assembly as specified on this BOM line. Used directly by MRP (Material Requirements Planning) to calculate gross requirements and by production planning for work order component staging.. Valid values are `^[0-9]+(.[0-9]{1,6})?$`',
    `reference_designator` STRING COMMENT 'Alphanumeric label identifying the specific physical location(s) of a component on a printed circuit board (PCB) or assembly drawing (e.g., R1, C12, U5). Critical for electronics manufacturing, PCB assembly, and automated optical inspection (AOI) processes.',
    `scrap_factor_percent` DECIMAL(18,2) COMMENT 'The anticipated scrap or yield loss percentage for this component during the manufacturing process, expressed as a percentage (e.g., 5.00 = 5%). MRP inflates the gross requirement by this factor to account for expected material loss, ensuring sufficient components are procured or issued to production orders.. Valid values are `^(100(.0{1,4})?|[0-9]{1,2}(.[0-9]{1,4})?)$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this BOM line record was sourced (e.g., SAP PP for production BOMs, Siemens Teamcenter for engineering/design BOMs). Supports data lineage tracking and reconciliation between PLM and ERP BOM structures in the silver layer.. Valid values are `SAP_PP|TEAMCENTER|OPCENTER|MANUAL`',
    `source_system_key` STRING COMMENT 'The natural or composite key of this BOM line record as it exists in the originating source system (e.g., SAP BOM number + item number + plant, or Teamcenter BOM line UID). Enables traceability back to the system of record and supports delta load reconciliation in the lakehouse ingestion pipeline.',
    `special_procurement_type` STRING COMMENT 'Specifies a special procurement strategy for this component, such as subcontracting (component sent to external vendor for processing), consignment stock, inter-plant stock transfer, or direct production. Overrides the standard procurement type for specific supply chain scenarios.. Valid values are `consignment|subcontracting|stock_transfer|direct_production|phantom`',
    `status` STRING COMMENT 'Current lifecycle status of this BOM line item. Active lines are included in MRP explosion and production planning. Pending approval lines are awaiting ECN authorization. Obsolete lines are retained for historical traceability but excluded from planning runs.. Valid values are `active|inactive|pending_approval|obsolete|superseded|in_review`',
    `supply_area` STRING COMMENT 'The production supply area or supermarket location on the shop floor where this component is staged for consumption at the work center. Supports Kanban and JIT (Just-In-Time) material flow management in Siemens Opcenter MES and SAP PP.',
    `unit_of_measure` STRING COMMENT 'The unit of measure in which the component quantity is expressed on this BOM line (e.g., EA for each, KG for kilogram, M for meter, L for liter). Must align with the base unit of measure defined in the components material master to ensure accurate MRP calculations.. Valid values are `EA|KG|G|LB|M|MM|CM|L|ML|M2|M3|PC|SET|ROL|BOX|PAL|HR|MIN`',
    CONSTRAINT pk_bom_line PRIMARY KEY(`bom_line_id`)
) COMMENT 'Individual line-item within a Bill of Materials defining each child component, quantity, unit of measure, reference designator, find number, item category (stock, non-stock, document), scrap factor, and effectivity date range. Supports multi-level BOM explosion for MRP and production planning. Sourced from Siemens Teamcenter BOM line items and SAP PP BOM item records.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`bop` (
    `bop_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a Bill of Process header record in the Databricks Silver Layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Bill of Process (BOP) defines manufacturing operations for a component. Production planning, work instruction systems, and shop floor control use this to determine how to manufacture the component wit',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: bop.ecn_reference is a STRING reference to the ECN that authorized the routing change. Replacing with FK ecn_id → ecn.ecn_id enforces referential integrity for change management. ecn_reference is redu',
    `eco_id` BIGINT COMMENT 'Foreign key linking to engineering.eco. Business justification: bop.eco_reference is a STRING reference to the ECO that authorized the routing implementation. Replacing with FK eco_id → eco.eco_id enforces referential integrity. eco_reference is redundant once the',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.bom. Business justification: bop.linked_bom_number is a STRING reference to the BOM this routing is linked to. A BOP defines the manufacturing process for a specific BOM structure. Replacing with FK bom_id → bom.bom_id enforces t',
    `approved_by` STRING COMMENT 'Name or employee identifier of the process engineer or engineering authority who formally approved this Bill of Process for production release. Required for ISO 9001 document control and audit trail compliance.',
    `approved_date` DATE COMMENT 'Date on which this Bill of Process revision was formally approved for production release by the authorized process engineer or engineering authority. Supports ISO 9001 document control and change management audit requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity for which the Bill of Process operations and time values are defined (e.g., 1 unit, 100 units). All operation times and resource requirements in the BoP are scaled relative to this base quantity during production order creation.. Valid values are `^d{1,10}(.d{1,3})?$`',
    `base_unit_of_measure` STRING COMMENT 'Unit of measure corresponding to the base quantity for this Bill of Process (e.g., EA for each, PC for piece, KG for kilogram). Aligns with SAP unit of measure configuration and ISO 80000 measurement standards.. Valid values are `EA|PC|KG|L|M|M2|M3|SET|BOX|PAL`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the manufacturing plant or facility where this Bill of Process is executed. Used for trade compliance, customs declarations, CE marking, and country-of-origin labeling requirements in multinational operations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this Bill of Process record was first created in the source PLM or ERP system. Supports data lineage, audit trail, and ISO 9001 document control requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `cycle_time_seconds` DECIMAL(18,2) COMMENT 'Total elapsed time to complete one full execution of the Bill of Process from first operation start to last operation completion, expressed in seconds. Used for capacity planning, OEE calculation, and production scheduling in Siemens Opcenter MES and SAP PP.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `description` STRING COMMENT 'Detailed narrative description of the manufacturing process defined by this BoP, including scope, key process steps, and intended assembly or sub-assembly. Supports operator understanding and process documentation requirements under ISO 9001.',
    `effectivity_end_date` DATE COMMENT 'Date after which this Bill of Process revision is no longer valid for new production orders. Supports date-effective routing expiry in SAP PP and ensures superseded processes are not applied to new manufacturing orders.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_start_date` DATE COMMENT 'Date from which this Bill of Process revision becomes valid for production use. Used in date-effective routing selection in SAP PP and MES scheduling to ensure the correct process version is applied to production orders.. Valid values are `^d{4}-d{2}-d{2}$`',
    `environmental_classification` STRING COMMENT 'Environmental impact classification of the manufacturing process, indicating whether it generates waste, emissions, requires chemical handling, or is energy-intensive. Supports ISO 14001 environmental management compliance and EPA reporting obligations.. Valid values are `standard|waste_generating|emissions_producing|chemical_handling|energy_intensive`',
    `finished_product_number` STRING COMMENT 'SAP material number or PLM part number of the finished assembly or sub-assembly produced by this Bill of Process. Provides direct linkage to the product master in SAP MM/PP and Siemens Teamcenter for production planning and scheduling.',
    `is_concurrent_operations_allowed` BOOLEAN COMMENT 'Flag indicating whether operations within this Bill of Process may be executed in parallel (concurrently) rather than strictly sequentially. Enables parallel scheduling in Siemens Opcenter MES and SAP PP finite scheduling.. Valid values are `true|false`',
    `is_preferred_routing` BOOLEAN COMMENT 'Flag indicating whether this Bill of Process is the preferred (primary) routing for the associated finished or semi-finished product. When true, this BoP is selected by default during production order creation in SAP PP unless overridden.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 two-letter language code for the primary language in which this BoP documentation and work instructions are authored (e.g., EN, DE, ZH, FR). Supports multilingual shop floor documentation in global manufacturing operations.. Valid values are `^[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this Bill of Process record in the source system. Used for incremental data loading in the Databricks Silver Layer and change detection in downstream MES and ERP integrations.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead_time_days` DECIMAL(18,2) COMMENT 'Total planned manufacturing lead time for the process in calendar days, from order release to completion. Used in SAP MRP/MRP II scheduling, ATP/CTP calculations, and delivery promise management.. Valid values are `^d{1,5}(.d{1,2})?$`',
    `lot_size_max` DECIMAL(18,2) COMMENT 'Maximum production quantity for which this Bill of Process is valid. Production orders exceeding this quantity may require splitting or use of an alternate routing. Used in SAP PP lot-size-dependent scheduling.. Valid values are `^d{1,10}(.d{1,3})?$`',
    `lot_size_min` DECIMAL(18,2) COMMENT 'Minimum production quantity for which this Bill of Process is valid. Production orders below this quantity may require a different routing or process variant. Used in SAP PP lot-size-dependent scheduling and MRP planning.. Valid values are `^d{1,10}(.d{1,3})?$`',
    `manufacturing_strategy` STRING COMMENT 'Production strategy governing how this process is triggered: Make to Stock (MTS), Make to Order (MTO), Assemble to Order (ATO), or Engineer to Order (ETO). Determines how the BoP is linked to demand signals in SAP PP/MRP and Siemens Opcenter MES.. Valid values are `MTS|MTO|ATO|ETO`',
    `name` STRING COMMENT 'Descriptive human-readable name for the Bill of Process, summarizing the assembly or sub-assembly manufacturing process it defines (e.g., Motor Drive Assembly – Standard Process). Used in MES scheduling and shop floor documentation.',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the Bill of Process, used in PLM, MES, and ERP systems to reference the process structure. Corresponds to the routing number in SAP PP and the BoP document number in Siemens Teamcenter.. Valid values are `^BOP-[A-Z0-9]{3,20}$`',
    `plant_code` STRING COMMENT 'Four-character SAP plant code identifying the manufacturing facility where this Bill of Process is valid and executed. Supports multi-plant, multinational operations and plant-specific routing assignments.. Valid values are `^[A-Z0-9]{4}$`',
    `process_classification` STRING COMMENT 'Classification of the manufacturing process type: discrete (individual units), process (batch/continuous), repetitive (high-volume standard), project (one-off), or continuous. Determines scheduling and execution methodology in SAP PP and Siemens Opcenter MES.. Valid values are `discrete|process|repetitive|project|continuous`',
    `process_type` STRING COMMENT 'Classification of the BoP indicating whether it represents the standard production process, an alternate routing, a rework process, a prototype build, or a pilot run. Drives routing selection logic in SAP PP and Siemens Opcenter MES.. Valid values are `standard|alternate|rework|prototype|pilot`',
    `product_family` STRING COMMENT 'Product family or product line classification to which the finished assembly produced by this BoP belongs (e.g., Drive Systems, Switchgear, Automation Controllers). Supports aggregate production planning and portfolio-level reporting.',
    `production_version` STRING COMMENT 'SAP production version identifier linking this BoP to a specific combination of BOM and routing for a finished or semi-finished product. Enables alternative production scenarios (e.g., different work centers or batch sizes) within SAP PP/MRP.. Valid values are `^[A-Z0-9]{1,4}$`',
    `quality_inspection_plan_number` STRING COMMENT 'Reference to the SAP QM inspection plan or Siemens Opcenter quality plan associated with this Bill of Process. Links the process structure to mandatory quality checkpoints, AQL sampling plans, and SPC control points required by the QMS.',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the version of the Bill of Process (e.g., A, B, 01, 02). Incremented upon each approved Engineering Change Order (ECO) affecting the process structure. Aligns with PLM revision management in Siemens Teamcenter.. Valid values are `^[A-Z0-9]{1,10}$`',
    `safety_classification` STRING COMMENT 'Safety classification of the manufacturing process defined by this BoP, indicating special handling, access control, or environmental requirements (e.g., hazardous materials, ESD-sensitive components, cleanroom conditions). Supports OSHA and ISO 45001 compliance.. Valid values are `standard|hazardous|restricted_access|cleanroom|esd_sensitive`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this Bill of Process record originates (e.g., Siemens Teamcenter PLM, SAP S/4HANA PP, Siemens Opcenter MES). Supports data lineage and master data governance in the Databricks Lakehouse.. Valid values are `teamcenter|sap_pp|opcenter|manual`',
    `status` STRING COMMENT 'Lifecycle status of the Bill of Process record, controlling its availability for production use. Only BoPs in released status are eligible for MES execution and SAP PP order creation. Managed through the ECO/ECN change workflow in Siemens Teamcenter.. Valid values are `draft|in_review|approved|released|obsolete|superseded`',
    `takt_time_seconds` DECIMAL(18,2) COMMENT 'The available production time divided by customer demand rate, expressed in seconds. Defines the required pace of production for this process to meet customer demand. A fundamental Lean Manufacturing metric used in line balancing and capacity planning.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `total_operation_count` STRING COMMENT 'Total number of manufacturing operations (process steps) defined within this Bill of Process. Provides a quick structural indicator of process complexity and is used in MES work order generation and shop floor documentation.. Valid values are `^[0-9]+$`',
    `work_center_category` STRING COMMENT 'Category of the primary work center type associated with this Bill of Process, indicating the dominant manufacturing technology or process family. Used for capacity planning aggregation and shop floor routing in SAP PP and Siemens Opcenter MES.. Valid values are `assembly|machining|welding|painting|testing|packaging|inspection|fabrication|pressing|other`',
    CONSTRAINT pk_bop PRIMARY KEY(`bop_id`)
) COMMENT 'Bill of Process header record defining the sequence of manufacturing operations, work centers, and process steps required to produce a finished assembly or sub-assembly. Captures process type (standard, alternate), revision level, effectivity dates, cycle time, takt time, and linkage to the corresponding engineering BOM. SSOT for process structure feeding Siemens Opcenter MES and SAP PP routing.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`bop_operation` (
    `bop_operation_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying an individual operation step within a Bill of Process. Serves as the primary key for this entity in the Databricks Silver Layer.',
    `bop_id` BIGINT COMMENT 'Foreign key linking to engineering.bop. Business justification: bop_operation is a child record of bop — each operation step belongs to a Bill of Process header. Without this FK, bop_operation is siloed from its parent. This is the fundamental parent-child relatio',
    `ot_system_id` BIGINT COMMENT 'Foreign key linking to technology.ot_system. Business justification: Bill of Process operations execute on specific OT systems (PLCs, SCADA, MES). Manufacturing engineering defines which operational technology system controls each production operation for execution and',
    `pfmea_id` BIGINT COMMENT 'Foreign key linking to engineering.pfmea. Business justification: bop_operation.pfmea_reference_number is a STRING reference to the PFMEA that analyzes failure modes for this operation. Replacing with FK pfmea_id → pfmea.pfmea_id enforces the PFMEA-to-operation trac',
    `skill_id` BIGINT COMMENT 'Foreign key linking to workforce.skill. Business justification: Bill of Process operations specify required operator skills (welding, CNC programming, inspection) for workforce planning, training needs analysis, and production scheduling based on available qualifi',
    `tooling_equipment_id` BIGINT COMMENT 'Foreign key linking to engineering.tooling_equipment. Business justification: BOP operations specify required tooling and equipment. Production scheduling and maintenance systems use this to ensure correct tools are available, calibrated, and assigned to workstations before ope',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity to which the standard time values (machine time, labor time) apply. For example, a machine time of 5 minutes per base quantity of 100 pieces. Corresponds to SAP PP BMSCH field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `base_quantity_unit` STRING COMMENT 'Unit of measure for the base quantity (e.g., EA for each, PC for pieces, KG for kilograms). Aligns with SAP unit of measure configuration and ISO 80000 measurement standards.. Valid values are `EA|PC|KG|M|M2|M3|L|HR|MIN|SET`',
    `control_key` STRING COMMENT 'SAP PP control key (e.g., PP01, PP03, QM01) that governs the scheduling, costing, confirmation, and quality inspection behavior of the operation. Determines whether the operation is relevant for capacity planning, external processing, or quality inspection.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the work center performing this operation. Used for cost allocation, COGS (Cost of Goods Sold) calculation, and financial reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this BoP operation record was first created in the source system. Used for audit trail, data lineage, and change history tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the external processing price (e.g., USD, EUR, CNY). Supports multi-currency operations in multinational manufacturing environments.. Valid values are `^[A-Z]{3}$`',
    `ecn_reference_number` STRING COMMENT 'Reference number of the Engineering Change Notice (ECN) or Engineering Change Order (ECO) that introduced or last modified this operation. Provides full traceability of process changes to engineering change management records.',
    `effective_from_date` DATE COMMENT 'Date from which this operation version becomes valid and can be used in production planning and execution. Supports date-effective routing management and Engineering Change Notice (ECN) implementation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'Date after which this operation version is no longer valid. Used to manage operation version supersession during Engineering Change Order (ECO) implementation and routing revision cycles.. Valid values are `^d{4}-d{2}-d{2}$`',
    `external_processing_price` DECIMAL(18,2) COMMENT 'Standard price per unit for externally processed operations performed by a subcontractor. Used in product costing and purchase order creation for subcontracting. Corresponds to SAP PP PEINH/PREIS fields.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `hazardous_material_relevant` BOOLEAN COMMENT 'Flag indicating whether this operation involves handling of hazardous materials, chemicals, or substances subject to REACH, RoHS, or OSHA regulations. Triggers mandatory safety documentation and PPE requirements on the shop floor.. Valid values are `true|false`',
    `inspection_characteristic_group` STRING COMMENT 'Code or identifier of the inspection characteristic group (master inspection characteristic catalog) assigned to this operation for in-process quality control. Defines the measurement parameters and tolerances to be checked.',
    `inspection_relevant` BOOLEAN COMMENT 'Flag indicating whether this operation requires a quality inspection step (in-process inspection). When true, inspection characteristics and AQL (Acceptable Quality Level) parameters must be defined for this operation.. Valid values are `true|false`',
    `interoperation_time_min` DECIMAL(18,2) COMMENT 'Standard wait and move time in minutes between this operation and the next operation in the routing. Includes queue time, move time, and wait time. Used in lead time calculation and scheduling. Corresponds to SAP PP interoperation times.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `labor_time_min` DECIMAL(18,2) COMMENT 'Standard labor time in minutes per base quantity unit required for this operation. Used for workforce planning, labor cost calculation, and takt time analysis. Corresponds to SAP PP ARBZE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this BoP operation record in the source system. Supports incremental data loading, change detection, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `long_text` STRING COMMENT 'Detailed narrative description of the operation including step-by-step instructions, safety notes, and quality requirements. Supports shop floor instruction generation and Standard Operating Procedure (SOP) documentation.',
    `machine_time_min` DECIMAL(18,2) COMMENT 'Standard machine processing time in minutes per base quantity unit for this operation. Used for capacity planning, OEE (Overall Equipment Effectiveness) calculation, and production scheduling. Corresponds to SAP PP BEAZE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `maximum_lot_size` DECIMAL(18,2) COMMENT 'Maximum production quantity that can be processed in a single run of this operation. Constrains batch sizes for capacity and quality management purposes.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `minimum_lot_size` DECIMAL(18,2) COMMENT 'Minimum production quantity that can be processed in a single run of this operation. Used in production planning and scheduling to enforce batch size constraints.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `nc_program_number` STRING COMMENT 'Identifier of the CNC (Computer Numerical Control) or NC program used to execute this operation on automated machinery. Links to the CAM (Computer-Aided Manufacturing) system for program retrieval.',
    `number_of_resources` STRING COMMENT 'Number of parallel machines or labor resources required to execute this operation simultaneously. Used for capacity planning and scheduling. Corresponds to SAP PP ANZZL field.. Valid values are `^[1-9][0-9]*$`',
    `operation_description` STRING COMMENT 'Short descriptive text for the operation step, summarizing the manufacturing activity performed (e.g., Weld Frame Assembly, CNC Milling – Housing, Final Inspection). Corresponds to SAP PP LTXA1 field.',
    `operation_number` STRING COMMENT 'Sequential numeric identifier for the operation step within the routing or Bill of Process, typically in increments of 10 (e.g., 0010, 0020, 0030). Corresponds to the SAP PP routing operation number (VORNR) and Teamcenter process step sequence number.. Valid values are `^[0-9]{4}$`',
    `operation_type` STRING COMMENT 'Classification of the operation indicating whether it is performed in-house, by an external subcontractor, or as a quality inspection step. Drives procurement and costing logic.. Valid values are `in_house|external|subcontracting|inspection|rework`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this operation is performed. Supports multi-plant BoP management for multinational operations.',
    `scheduling_type` STRING COMMENT 'Determines the scheduling direction for this operation in production planning — forward scheduling (from start date), backward scheduling (from required finish date), or current date. Corresponds to SAP PP scheduling parameters.. Valid values are `forward|backward|current_date`',
    `setup_time_min` DECIMAL(18,2) COMMENT 'Standard setup time in minutes required to prepare the work center for this operation, including tooling changeover and machine configuration. Used in capacity planning, scheduling, and SMED (Single-Minute Exchange of Dies) analysis. Corresponds to SAP PP RUSTE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `sop_reference_number` STRING COMMENT 'Document number or identifier of the Standard Operating Procedure (SOP) governing the execution of this operation. Links to the document management system for shop floor instruction retrieval.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this BoP operation was sourced (e.g., SAP_PP for SAP S/4HANA PP routing, TEAMCENTER for Siemens Teamcenter manufacturing process steps). Supports data lineage and reconciliation.. Valid values are `SAP_PP|TEAMCENTER|OPCENTER|MANUAL`',
    `standard_cost_activity_type` STRING COMMENT 'SAP CO activity type code used to assign standard costs to this operation (e.g., machine hours, labor hours). Links the operation to cost center accounting and product costing. Corresponds to SAP CO LSTAR field.',
    `status` STRING COMMENT 'Current lifecycle status of the BoP operation record. Active operations are available for production order assignment; obsolete operations are retained for historical traceability but cannot be used in new routings.. Valid values are `active|inactive|draft|under_review|obsolete`',
    `subcontracting_vendor_code` STRING COMMENT 'Vendor or supplier code for externally processed operations where the operation is performed by a subcontractor. Applicable when operation_type is external or subcontracting. Corresponds to SAP PP external processing vendor.',
    `teardown_time_min` DECIMAL(18,2) COMMENT 'Standard teardown or post-processing time in minutes required after the operation is completed, including cleaning, tool removal, and work center reset. Corresponds to SAP PP ABRUE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `tooling_list_reference` STRING COMMENT 'Reference identifier for the tooling list or production resource/tool (PRT) assignment associated with this operation. Specifies jigs, fixtures, cutting tools, and gauges required. Corresponds to SAP PP PRT assignment.',
    `version_number` STRING COMMENT 'Version identifier for this operation step, incremented when the operation is revised through the engineering change process. Enables version-controlled routing management and historical comparison.. Valid values are `^[A-Z0-9.]+$`',
    `work_center_code` STRING COMMENT 'Alphanumeric code identifying the work center (machine, production line, or labor group) where this operation is performed. Corresponds to SAP PP ARBPL field and links to the work center master data.',
    `work_center_name` STRING COMMENT 'Human-readable name of the work center where the operation is executed (e.g., CNC Cell 3, Welding Station A, Final Assembly Line 2). Supports shop floor reporting and scheduling.',
    CONSTRAINT pk_bop_operation PRIMARY KEY(`bop_operation_id`)
) COMMENT 'Individual operation step within a Bill of Process defining the work center, operation description, standard values (setup time, machine time, labor time), control key, inspection characteristics, tooling requirements, and SOP reference. Supports PFMEA linkage and shop floor instruction generation. Sourced from SAP PP routing operations and Teamcenter manufacturing process steps.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`cad_model` (
    `cad_model_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a CAD/CAM design model record within the PLM/PDM system. Serves as the primary key for the cad_model data product in the Databricks Silver layer.',
    `application_id` BIGINT COMMENT 'Foreign key linking to technology.application. Business justification: CAD models are created and managed in specific engineering applications (AutoCAD, SolidWorks, CATIA). Engineering teams need to track which application owns each model for compatibility and licensing.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: cad_model.material_number is a STRING reference to the component/part this CAD model represents in the PLM/PDM system. Replacing with FK component_id → component.component_id establishes the authorita',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: cad_model.ecn_number is a STRING reference to the ECN that authorized the CAD model revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design geometry. ecn_num',
    `plm_lifecycle_state_id` BIGINT COMMENT 'Foreign key linking to engineering.plm_lifecycle_state. Business justification: cad_model.lifecycle_state is a STRING that should reference the authoritative PLM lifecycle state reference table. Replacing with FK plm_lifecycle_state_id → plm_lifecycle_state.plm_lifecycle_state_id',
    `bounding_box_x_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the X-axis in millimeters, representing the width of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning (e.g., pallet/container sizing).',
    `bounding_box_y_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the Y-axis in millimeters, representing the depth of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning.',
    `bounding_box_z_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the Z-axis in millimeters, representing the height of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning.',
    `cad_tool` STRING COMMENT 'Name of the CAD/CAM software application used to create and maintain the model (e.g., Siemens NX, CATIA V5/V6, SolidWorks). Determines file format compatibility, interoperability requirements, and licensing needs for downstream engineering and manufacturing processes.. Valid values are `NX|CATIA|SolidWorks|Creo|AutoCAD|Inventor|ANSYS|Simcenter|Fusion360|Other`',
    `cad_tool_version` STRING COMMENT 'Version or release number of the CAD/CAM software used to create or last modify the model (e.g., NX 2206, CATIA V5 R31). Critical for file compatibility management, migration planning, and ensuring models can be opened by the correct software version in the engineering environment.',
    `checked_out_by` STRING COMMENT 'Username or employee ID of the engineer who currently has the CAD model checked out for editing in the PLM/PDM system. A checked-out model is locked for exclusive editing. Null if the model is not currently checked out. Corresponds to Teamcenter Checked Out By.',
    `checkout_timestamp` TIMESTAMP COMMENT 'Date and time when the CAD model was checked out from the PLM/PDM vault for editing. Used to track concurrent engineering activities, identify long-running checkouts that may block other engineers, and support audit trails.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `classification_code` STRING COMMENT 'Standardized classification code assigned to the CAD model based on the companys engineering parts classification system (e.g., eCl@ss, UNSPSC, or internal taxonomy). Enables design reuse, variant management, and supplier sourcing by grouping similar components.',
    `component_type` STRING COMMENT 'Classification of the engineering component or assembly represented by the CAD model. Determines BOM structure, procurement strategy (make vs. buy), and applicable design standards. assembly models link to child part models via the BOM hierarchy in PLM.. Valid values are `part|assembly|sub_assembly|standard_part|purchased_part|raw_material|tooling|fixture|packaging`',
    `coordinate_system` STRING COMMENT 'Type of coordinate system used to define the geometry of the CAD model (e.g., Cartesian, Cylindrical). Ensures correct spatial orientation when integrating models into assemblies, simulation environments, or digital twin platforms.. Valid values are `cartesian|cylindrical|spherical`',
    `country_of_origin` STRING COMMENT 'Three-letter ISO country code indicating the country where the component represented by this CAD model is designed or manufactured (e.g., DEU, USA, CHN). Used for export control compliance (ITAR/EAR), customs declarations, and regional regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the CAD model record was first created in the PLM/PDM system. Provides the starting point for the models audit trail and lifecycle history. Corresponds to Teamcenter Creation Date metadata.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `design_owner` STRING COMMENT 'Name or employee identifier of the responsible design engineer who owns and maintains the CAD model. Accountable for model accuracy, revision control, and release approvals. Corresponds to the Teamcenter Owning User field.',
    `dfa_status` STRING COMMENT 'Current status of the Design for Assembly (DFA) analysis for this CAD model. Evaluates the ease of assembly, part count reduction opportunities, and assembly process compatibility. Relevant for assembly-type models and sub-assemblies.. Valid values are `not_started|in_progress|passed|failed|waived`',
    `dfm_status` STRING COMMENT 'Current status of the Design for Manufacturability (DFM) analysis for this CAD model. Indicates whether the design has been reviewed for manufacturing feasibility, cost optimization, and process compatibility. A passed status is typically required before release to production.. Valid values are `not_started|in_progress|passed|failed|waived`',
    `digital_twin_reference` STRING COMMENT 'Identifier linking this CAD model to its corresponding digital twin instance on the Siemens MindSphere IIoT platform. Enables real-time correlation between the design geometry and operational asset behavior for predictive maintenance and performance optimization.',
    `export_control_class` STRING COMMENT 'Export control classification code assigned to the CAD model, indicating whether the design data is subject to export regulations (e.g., ITAR USML category, EAR ECCN code, or EAR99 for unrestricted). Critical for controlling access to design data shared with international suppliers or subsidiaries.',
    `file_format` STRING COMMENT 'Native or neutral file format of the CAD model dataset (e.g., STEP, IGES, JT, NX native). Determines interoperability with downstream systems including CAM, FEA simulation, and supplier collaboration. STEP (ISO 10303) is the preferred neutral exchange format for cross-system sharing.. Valid values are `STEP|IGES|JT|NX|CATIA|SolidWorks|DXF|DWG|STL|OBJ|PDF|PARASOLID|Other`',
    `file_name` STRING COMMENT 'Full file name of the CAD model dataset as stored in the PLM/PDM vault, including file extension (e.g., motor_housing_v2.prt, drive_shaft_asm.CATProduct). Used for file retrieval, version tracking, and integration with CAM and simulation tools.',
    `file_size_mb` DECIMAL(18,2) COMMENT 'Size of the CAD model file in megabytes as stored in the PLM vault. Used for storage capacity planning, data migration scoping, and identifying oversized models that may impact system performance or collaboration efficiency.',
    `freeze_date` DATE COMMENT 'Date on which the CAD model was frozen, preventing further modifications. Typically aligned with production launch milestones (e.g., PPAP approval, SOP - Start of Production). A frozen model can only be changed via a formal ECO process.. Valid values are `^d{4}-d{2}-d{2}$`',
    `is_master_model` BOOLEAN COMMENT 'Boolean flag indicating whether this CAD model is designated as the master geometry model for the component or assembly. The master model is the authoritative source for all downstream derivations (drawings, simulations, CAM programs). Only one master model should exist per component revision.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent modification to the CAD model record in the PLM/PDM system. Used for change tracking, synchronization with downstream systems (SAP, MES), and audit compliance. Corresponds to Teamcenter Last Modified Date.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `mass_kg` DECIMAL(18,2) COMMENT 'Calculated mass of the component or assembly as derived from the CAD model geometry and assigned material properties, expressed in kilograms. Used for structural analysis, logistics weight calculations, BOM costing, and compliance with weight-sensitive design requirements.',
    `model_name` STRING COMMENT 'Human-readable descriptive name of the CAD/CAM model as defined by the design engineer. Typically reflects the component or assembly name (e.g., Motor Housing Assembly, Drive Shaft Bracket). Corresponds to Teamcenter Item Name.',
    `model_number` STRING COMMENT 'Business-assigned alphanumeric identifier for the CAD/CAM model as registered in the PLM/PDM system. Used for cross-referencing with BOM, ECN/ECO, and engineering documentation. Corresponds to the Teamcenter Item ID.. Valid values are `^[A-Z0-9-.]{3,50}$`',
    `model_type` STRING COMMENT 'Classification of the CAD model by its geometric or representational type. Determines the applicable CAD tools, downstream processes (e.g., CAM toolpath generation, FEA simulation), and BOM linkage. 3d_solid is the primary type for CNC machining and DFM analysis.. Valid values are `3d_solid|3d_surface|2d_drawing|assembly|simulation|wiring_diagram|schematic|point_cloud|mesh`',
    `obsolescence_date` DATE COMMENT 'Date on which the CAD model revision was marked as obsolete, indicating it has been superseded by a newer revision or the component has been discontinued. Used for lifecycle management, archive planning, and BOM cleanup.. Valid values are `^d{4}-d{2}-d{2}$`',
    `owning_group` STRING COMMENT 'Name of the engineering team, department, or organizational group responsible for the CAD model (e.g., Mechanical Design, Electrical Engineering, Automation Systems). Used for workload distribution, access control, and organizational reporting in PLM.',
    `primary_material` STRING COMMENT 'Name or code of the primary engineering material assigned to the CAD model (e.g., Aluminum 6061-T6, Stainless Steel 316L, ABS Plastic). Drives material requirements planning (MRP), cost estimation, and compliance checks for REACH/RoHS regulations.',
    `product_line` STRING COMMENT 'Name of the product line or product family to which the designed component or assembly belongs (e.g., Automation Systems, Electrification Solutions, Smart Infrastructure). Supports portfolio-level reporting and PLM product structure navigation.',
    `project_code` STRING COMMENT 'Alphanumeric code identifying the engineering project or program under which the CAD model was created. Links the model to project planning, resource allocation, and CAPEX tracking in SAP PS (Project System). Supports APQP phase tracking.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `release_date` DATE COMMENT 'Date on which the CAD model revision was formally released (approved and promoted to released lifecycle state) in the PLM system. Marks the point at which the design is authorized for use in manufacturing, procurement, and BOM structures.. Valid values are `^d{4}-d{2}-d{2}$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the version of the CAD model (e.g., A, B, C, 01, 02). Incremented upon each approved engineering change. Corresponds to Teamcenter Item Revision ID and is critical for configuration management and BOM accuracy.. Valid values are `^[A-Z0-9]{1,10}$`',
    `surface_finish` STRING COMMENT 'Required surface finish or roughness specification for the component as defined in the CAD model (e.g., Ra 1.6 µm, Anodized, Powder Coated). Drives manufacturing process selection, quality inspection criteria, and supplier specifications.',
    `tolerance_class` STRING COMMENT 'General tolerance class applied to the CAD model for dimensions not individually toleranced (e.g., Fine, Medium, Coarse per ISO 2768). Determines manufacturing precision requirements, process selection, and inspection rigor. Critical for DFM analysis.. Valid values are `fine|medium|coarse|very_coarse|custom`',
    `unit_of_measure` STRING COMMENT 'Base unit of measurement used in the CAD model geometry (e.g., MM for millimeters, IN for inches). Critical for dimensional accuracy, interoperability with CAM systems, and compliance with regional engineering standards. Must be consistent across all models in an assembly.. Valid values are `MM|CM|M|IN|FT|DEG`',
    CONSTRAINT pk_cad_model PRIMARY KEY(`cad_model_id`)
) COMMENT 'Master record for CAD/CAM design models and 3D geometry files managed within the PLM/PDM system. Captures model number, CAD tool (e.g., NX, CATIA, SolidWorks), file format, revision, lifecycle state (in-work, released, frozen), design owner, associated component or assembly, model type (3D solid, 2D drawing, simulation), and digital twin linkage. Sourced from Siemens Teamcenter Document Management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`drawing` (
    `drawing_id` BIGINT COMMENT 'Unique surrogate identifier for each engineering drawing record in the lakehouse silver layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `cad_model_id` BIGINT COMMENT 'Foreign key linking to engineering.cad_model. Business justification: engineering_drawing.cad_model_reference is a STRING reference to the associated CAD model from which the drawing was derived. Replacing with FK cad_model_id → cad_model.cad_model_id enforces the PLM r',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: engineering_drawing.part_number is a STRING reference to the component this drawing documents. Replacing with FK component_id → component.component_id establishes the authoritative drawing-to-part rel',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: engineering_drawing.ecn_number is a STRING reference to the ECN that authorized the drawing revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for controlled engin',
    `approved_by` STRING COMMENT 'Name or employee identifier of the authorized approver who released the drawing for production or procurement use. Establishes formal engineering authority and sign-off accountability.',
    `assembly_level` STRING COMMENT 'Position of the depicted item within the product structure hierarchy. Indicates whether the drawing represents a top-level assembly, sub-assembly, individual component, or purchased part.. Valid values are `top_level_assembly|sub_assembly|component|raw_material|purchased_part`',
    `cad_format` STRING COMMENT 'Native or exchange file format of the CAD model or drawing file (e.g., Siemens NX, CATIA, STEP, PDF). Determines software compatibility for viewing, editing, and downstream manufacturing use.. Valid values are `NX|CATIA|SolidWorks|AutoCAD|STEP|IGES|DXF|DWG|PDF|other`',
    `checked_by` STRING COMMENT 'Name or employee identifier of the engineer who performed the technical check/peer review of the drawing. Part of the mandatory drawing approval workflow per quality management standards.',
    `confidentiality_level` STRING COMMENT 'Information security classification of the drawing content. Controls access permissions, distribution rights, and handling requirements for the drawing across internal teams, suppliers, and customers.. Valid values are `public|internal|confidential|restricted|top_secret`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the engineering site where the drawing was originally created. Relevant for export control compliance, intellectual property jurisdiction, and regulatory certification.. Valid values are `^[A-Z]{3}$`',
    `created_date` DATE COMMENT 'Calendar date on which the drawing was originally created in the PLM system. Used for drawing age analysis, audit trails, and compliance with document retention policies.. Valid values are `^d{4}-d{2}-d{2}$`',
    `drawn_by` STRING COMMENT 'Name or employee identifier of the engineer or drafter who created the drawing. Captured in the drawing title block for accountability and traceability per engineering documentation standards.',
    `export_control_classification` STRING COMMENT 'Export control classification of the drawing and its associated technology under US EAR (Export Administration Regulations) or ITAR (International Traffic in Arms Regulations). Governs distribution of drawings to foreign nationals and international sites.. Valid values are `EAR99|ECCN_[A-Z][0-9][A-Z][0-9]{3}|ITAR|no_restriction|under_review`',
    `is_controlled_document` BOOLEAN COMMENT 'Indicates whether the drawing is a controlled document subject to formal change management, revision control, and distribution tracking per the quality management system. Controlled drawings require ECN authorization for any modification.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 language code of the drawing annotations and title block text (e.g., en, de, zh-CN, fr). Supports multilingual drawing management for global manufacturing sites and international customer deliveries.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_date` DATE COMMENT 'Date on which the drawing record was most recently updated in the PLM system. Supports change tracking, audit compliance, and identification of recently revised drawings.. Valid values are `^d{4}-d{2}-d{2}$`',
    `material_specification` STRING COMMENT 'Primary material specification or standard called out on the drawing (e.g., ASTM A36, DIN EN 10025, AL6061-T6). Drives material procurement, supplier qualification, and incoming inspection requirements.',
    `number` STRING COMMENT 'Formal alphanumeric identifier assigned to the engineering drawing per company numbering standards. Used as the primary business key for cross-system reference in Teamcenter PLM and SAP DMS.. Valid values are `^[A-Z0-9-.]{3,50}$`',
    `obsolescence_date` DATE COMMENT 'Date on which the drawing was formally declared obsolete or superseded. Prevents use of outdated drawings in manufacturing and supports document lifecycle management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `originating_department` STRING COMMENT 'Engineering department or design team responsible for creating and owning the drawing (e.g., Mechanical Engineering, Electrical Engineering, Systems Engineering). Supports ownership accountability and routing.',
    `paper_size` STRING COMMENT 'Standard paper or sheet size designation for the drawing (ISO A-series or ANSI letter sizes). Governs print and reproduction specifications for physical drawing distribution.. Valid values are `A0|A1|A2|A3|A4|A|B|C|D|E|F`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility for which the drawing is primarily applicable. Supports plant-specific drawing distribution and manufacturing execution.. Valid values are `^[A-Z0-9]{2,10}$`',
    `product_line` STRING COMMENT 'Business product line or product family to which the drawn component or assembly belongs (e.g., automation systems, electrification solutions, smart infrastructure). Supports portfolio-level drawing management and reporting.',
    `projection_method` STRING COMMENT 'Orthographic projection convention used in the drawing (first-angle per ISO/European practice or third-angle per ANSI/US practice). Critical for correct interpretation of multi-view drawings across global manufacturing sites.. Valid values are `first_angle|third_angle`',
    `regulatory_compliance_flags` STRING COMMENT 'Applicable regulatory compliance certifications or directives that the drawn component or assembly must satisfy (e.g., CE Marking, RoHS, REACH, UL). Drives compliance documentation and design constraint requirements.. Valid values are `CE|RoHS|REACH|UL|CSA|ATEX|IECEx|none|multiple`',
    `release_date` DATE COMMENT 'Date on which the drawing was formally approved and released for use in production, procurement, or field operations. Marks the transition from engineering control to manufacturing control.. Valid values are `^d{4}-d{2}-d{2}$`',
    `revision_level` STRING COMMENT 'Current revision identifier of the drawing (e.g., A, B, C or 01, 02). Tracks the engineering change history and ensures the correct version is used in production and procurement.. Valid values are `^[A-Z0-9]{1,5}$`',
    `scale` STRING COMMENT 'Nominal drawing scale expressed as a ratio (e.g., 1:1, 1:2, 2:1, NTS for Not to Scale). Defines the proportional relationship between the drawn representation and the actual object dimensions.',
    `sheet_count` STRING COMMENT 'Total number of sheets comprising the complete engineering drawing package. Used for document completeness verification during review, approval, and distribution.. Valid values are `^[1-9][0-9]*$`',
    `sheet_number` STRING COMMENT 'Identifies the specific sheet within a multi-sheet drawing set (e.g., sheet 1 of 5). Enables precise reference to individual drawing sheets during manufacturing and inspection.. Valid values are `^[0-9]{1,3}$`',
    `status` STRING COMMENT 'Current lifecycle status of the engineering drawing within the PLM workflow. Controls whether the drawing may be used for production, procurement, or field installation activities.. Valid values are `draft|in_review|approved|released|obsolete|superseded|on_hold|cancelled`',
    `superseded_by_drawing_number` STRING COMMENT 'Drawing number of the newer drawing that replaces this drawing when it is obsolete or superseded. Enables forward navigation through the drawing revision history for configuration management.. Valid values are `^[A-Z0-9-.]{3,50}$`',
    `surface_finish` STRING COMMENT 'Surface finish or surface texture requirement specified on the drawing (e.g., Ra 1.6 µm, 63 µin RMS). Governs machining, grinding, and coating process requirements for manufactured components.',
    `title` STRING COMMENT 'Official descriptive title of the engineering drawing as it appears in the title block. Identifies the subject component, assembly, or system depicted.',
    `tolerance_standard` STRING COMMENT 'Governing dimensional and geometric tolerance standard applied to the drawing. Ensures consistent interpretation of tolerances by manufacturing, quality, and supplier teams.. Valid values are `ASME_Y14.5|ISO_1101|ISO_2768|DIN_ISO_2768|company_standard|other`',
    `type` STRING COMMENT 'Classification of the engineering drawing by its technical purpose. Determines the applicable drafting standards, review workflow, and downstream usage in manufacturing, installation, or maintenance.. Valid values are `assembly|detail|schematic|wiring_diagram|installation|layout|fabrication|erection|piping|pneumatic|hydraulic|block_diagram|flow_diagram`',
    `unit_of_measure` STRING COMMENT 'Primary dimensional unit used throughout the drawing (millimeters, inches, etc.). Prevents measurement interpretation errors across global manufacturing and supplier facilities.. Valid values are `mm|inch|cm|m`',
    `weight_kg` DECIMAL(18,2) COMMENT 'Nominal weight of the component or assembly depicted in the drawing, expressed in kilograms. Used for logistics planning, structural analysis, packaging design, and shipping documentation.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    CONSTRAINT pk_drawing PRIMARY KEY(`drawing_id`)
) COMMENT 'Master record for formal engineering drawings and technical documents including assembly drawings, detail drawings, wiring diagrams, and schematics. Captures drawing number, title, revision level, drawing type, sheet count, scale, tolerance standard, approval status, release date, and associated component or assembly. Managed in Siemens Teamcenter Document Management and linked to SAP DMS.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`ecn` (
    `ecn_id` BIGINT COMMENT 'Unique surrogate identifier for the Engineering Change Notice record in the Databricks Silver Layer. Primary key for the ecn data product.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the lead engineer assigned ownership and accountability for driving the ECN through the approval and implementation process. May differ from the initiator when changes are escalated or reassigned.',
    `engineering_change_request_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_change_request. Business justification: ecn.ecr_reference_number is a STRING reference to the ECR that initiated this ECN. The ECN is the child of the ECR in the change management workflow (ECR → ECN → ECO). Replacing with FK engineering_ch',
    `initiator_employee_id` BIGINT COMMENT 'Employee identifier of the engineer or technical staff member who formally initiated and submitted the Engineering Change Notice in Teamcenter. Used for accountability tracking, workload analysis, and change governance reporting.',
    `actual_implementation_cost` DECIMAL(18,2) COMMENT 'Actual total cost incurred to implement the engineering change upon completion. Compared against estimated_implementation_cost for variance analysis, budget control, and continuous improvement of change cost estimation accuracy.',
    `affected_item_description` STRING COMMENT 'Human-readable description of the primary affected component, assembly, drawing, or process document. Provides context for reviewers and approvers without requiring a PLM system lookup.',
    `affected_item_number` STRING COMMENT 'Primary part number, assembly number, drawing number, or BOM node identifier that is the subject of the engineering change. Represents the main item being modified. Links to the PLM/PDM product structure in Teamcenter.',
    `affected_item_type` STRING COMMENT 'Classification of the primary item being changed: component (individual part), assembly/sub_assembly (multi-part structure), drawing (2D/3D technical drawing), bom (Bill of Materials structure), process (manufacturing process/BoP), document (SOP, specification), software (firmware/embedded code), or tooling (jigs, fixtures, dies).. Valid values are `component|assembly|sub_assembly|drawing|bom|process|document|software|tooling`',
    `approval_date` DATE COMMENT 'Date on which the Engineering Change Notice received final approval from the Engineering Change Board (ECB) or designated approval authority. Marks the transition from review to authorized implementation status.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the final approving authority (e.g., Chief Engineer, Engineering Change Board chairperson) who authorized the ECN. Required for audit trail and regulatory compliance documentation.',
    `bom_revision_from` STRING COMMENT 'The current BOM or drawing revision level that is being superseded by this engineering change. Enables before/after comparison and revision history tracking in Teamcenter PLM.',
    `bom_revision_to` STRING COMMENT 'The new BOM or drawing revision level that will be established upon implementation of this engineering change. Defines the target state of the product structure post-change.',
    `capa_reference_number` STRING COMMENT 'Reference identifier of the CAPA record in the Quality Management System that triggered this ECN, when the change is driven by a corrective or preventive action. Provides traceability between quality events and engineering changes per ISO 9001 requirements.',
    `change_reason` STRING COMMENT 'Business driver or root cause triggering the Engineering Change Notice. CAPA-driven changes link to corrective/preventive actions; obsolescence indicates end-of-life component replacement; regulatory_compliance reflects REACH, RoHS, CE Marking, or other mandates. Critical for change governance and traceability.. Valid values are `capa_driven|cost_reduction|obsolescence|customer_request|regulatory_compliance|quality_improvement|design_optimization|supplier_change|safety_improvement|warranty_reduction`',
    `change_type` STRING COMMENT 'Classification of the engineering change by its primary nature: design (geometry, tolerances, CAD), process (manufacturing method, BoP), material (raw material substitution), regulatory (compliance-driven), software (firmware/embedded), documentation (drawing/SOP update), or safety (hazard mitigation). Drives routing and approval authority.. Valid values are `design|process|material|regulatory|software|documentation|safety`',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated implementation cost and actual implementation cost fields. Supports multi-currency reporting for multinational operations (e.g., USD, EUR, CNY, GBP).. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the ECN record was first created in Teamcenter, including draft records not yet submitted. Supports full lifecycle audit trail from initial creation through implementation.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether the engineering change requires formal notification to customers per contractual obligations or regulatory requirements. When true, triggers customer communication workflow in Salesforce CRM and may require customer approval before implementation.. Valid values are `true|false`',
    `description` STRING COMMENT 'Detailed narrative describing the full scope, rationale, and technical details of the proposed engineering change. Supports engineering review, impact assessment, and regulatory documentation.',
    `disposition_of_existing_stock` STRING COMMENT 'Decision on how to handle existing inventory of the affected component or assembly after the engineering change is implemented. Drives warehouse and inventory management actions in Infor WMS and SAP S/4HANA WM to prevent use of obsolete parts.. Valid values are `use_as_is|rework|scrap|return_to_supplier|quarantine|pending_decision`',
    `eco_reference_number` STRING COMMENT 'Reference number of the Engineering Change Order (ECO) issued to authorize and execute the physical implementation of this ECN. The ECO is the downstream execution document that follows ECN approval in the change management workflow.',
    `effectivity_type` STRING COMMENT 'Method by which the engineering change becomes effective in production: date_effectivity (change applies from a specific date), serial_number_effectivity (change applies from a specific serial number), lot_effectivity (change applies from a specific production lot), or unit_effectivity (change applies to specific unit numbers). Critical for production control and spare parts management.. Valid values are `date_effectivity|serial_number_effectivity|lot_effectivity|unit_effectivity`',
    `effectivity_value` STRING COMMENT 'The specific value defining when the change becomes effective, interpreted according to effectivity_type. For date_effectivity, this is a date string; for serial_number_effectivity, this is the first serial number; for lot_effectivity, this is the lot number. Enables precise production cutover control.',
    `estimated_implementation_cost` DECIMAL(18,2) COMMENT 'Estimated total cost to implement the engineering change, including engineering labor, tooling modifications, material write-offs, qualification testing, and production line changeover. Used for change prioritization, CAPEX/OPEX planning, and ROI analysis.',
    `implementation_date_actual` DATE COMMENT 'Date on which the engineering change was fully implemented and the new revision became effective in production. Used for on-time delivery measurement, change cycle time analytics, and regulatory compliance records.. Valid values are `^d{4}-d{2}-d{2}$`',
    `implementation_date_planned` DATE COMMENT 'Target date by which the engineering change is planned to be fully implemented in production. Used for production planning, material procurement scheduling in SAP MRP, and milestone tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `initiator_name` STRING COMMENT 'Full name of the engineer or technical staff member who initiated the Engineering Change Notice. Retained for display in reports and approval documents where the employee ID alone is insufficient for human-readable audit trails.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the ECN record in Teamcenter. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and for detecting concurrent modification conflicts.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `number` STRING COMMENT 'Human-readable, business-facing unique identifier for the Engineering Change Notice as assigned by Teamcenter Change Management. Used for cross-system referencing, audit trails, and communication with engineering, procurement, and manufacturing teams.. Valid values are `^ECN-[0-9]{4}-[0-9]{6}$`',
    `owning_department` STRING COMMENT 'Organizational department responsible for the engineering change, such as Product Engineering, R&D, Manufacturing Engineering, or Quality. Used for workload distribution, cost allocation, and departmental KPI reporting.',
    `plant_code` STRING COMMENT 'SAP S/4HANA plant code identifying the manufacturing facility or site where the engineering change will be implemented. Supports multi-site change management for multinational operations.',
    `priority` STRING COMMENT 'Business priority level assigned to the ECN indicating urgency of implementation. Critical priority typically indicates safety, regulatory, or production-stopping issues requiring immediate action. Drives scheduling of review boards and implementation timelines.. Valid values are `critical|high|medium|low`',
    `regulatory_compliance_impact` BOOLEAN COMMENT 'Indicates whether the engineering change affects the products compliance status with applicable regulations such as RoHS, REACH, CE Marking, UL certification, or IEC standards. When true, triggers compliance re-evaluation and potential re-certification activities.. Valid values are `true|false`',
    `regulatory_reference` STRING COMMENT 'Specific regulatory standard, directive, or compliance requirement driving the engineering change, such as RoHS Directive 2011/65/EU, REACH Regulation (EC) No 1907/2006, CE Marking Directive, UL certification requirement, or OSHA standard. Populated when change_reason is regulatory_compliance.',
    `rejection_reason` STRING COMMENT 'Free-text explanation provided by the reviewer or approver when an ECN is rejected. Documents the specific technical, commercial, or compliance reasons for rejection to guide the initiator in revising and resubmitting the change request.',
    `requires_dfmea_update` BOOLEAN COMMENT 'Indicates whether the engineering change necessitates an update to the Design Failure Mode and Effects Analysis (DFMEA) document. Ensures risk assessment documentation remains current and aligned with the changed design.. Valid values are `true|false`',
    `requires_pfmea_update` BOOLEAN COMMENT 'Indicates whether the engineering change requires an update to the Process Failure Mode and Effects Analysis (PFMEA) document. Ensures manufacturing process risk documentation is updated to reflect changed process steps or parameters.. Valid values are `true|false`',
    `requires_ppap` BOOLEAN COMMENT 'Indicates whether the engineering change requires a Production Part Approval Process submission to the customer or internal quality authority before the changed part can be used in production. Mandatory for automotive and aerospace supply chain compliance.. Valid values are `true|false`',
    `safety_impact` BOOLEAN COMMENT 'Indicates whether the engineering change has a potential impact on product safety, operator safety, or end-user safety. When true, triggers mandatory safety review and may require additional regulatory approvals (CE Marking, UL certification, OSHA compliance review).. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which the ECN record was ingested into the Databricks Silver Layer. Supports data lineage tracking and multi-source reconciliation in the lakehouse architecture.. Valid values are `teamcenter|sap_s4hana|manual`',
    `status` STRING COMMENT 'Current lifecycle state of the ECN within the Teamcenter Change Management workflow. Tracks progression from initial draft through engineering review board approval to physical implementation on the shop floor. Drives downstream actions in SAP S/4HANA MM/PP modules.. Valid values are `draft|submitted|under_review|approved|rejected|on_hold|implemented|cancelled|closed`',
    `submitted_timestamp` TIMESTAMP COMMENT 'Precise date and time when the Engineering Change Notice was formally submitted for review in Teamcenter. Used for change cycle time measurement, SLA compliance tracking, and audit trail.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `title` STRING COMMENT 'Short, descriptive title summarizing the nature of the proposed engineering change. Used in dashboards, approval workflows, and search interfaces within Teamcenter and SAP S/4HANA.',
    CONSTRAINT pk_ecn PRIMARY KEY(`ecn_id`)
) COMMENT 'Engineering Change Notice header record capturing the formal initiation and approval of a proposed change to a component, BOM, drawing, or process. Records ECN number, change title, change type (design, process, material, regulatory), initiator, priority, affected items, reason for change (e.g., CAPA-driven, cost reduction, obsolescence), estimated implementation cost, and current workflow state (draft, review, approved, rejected, implemented). SSOT for engineering change governance in Teamcenter Change Management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`eco` (
    `eco_id` BIGINT COMMENT 'Unique surrogate identifier for the Engineering Change Order record in the lakehouse silver layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: eco.ecn_number is a STRING reference to the parent ECN that this ECO implements. The ECO is the formal authorization child of the ECN (ECN proposes, ECO authorizes implementation). Replacing with FK e',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Engineering Change Orders require a designated responsible engineer to manage implementation, coordinate cross-functional activities, and ensure completion. Change management boards track ownership fo',
    `actual_cost` DECIMAL(18,2) COMMENT 'Actual total cost incurred to implement the engineering change, captured upon completion. Compared against estimated_cost for variance analysis and continuous improvement of change cost estimation accuracy.',
    `affected_bom_revisions` STRING COMMENT 'Comma-separated list or description of the Bill of Materials (BOM) revision identifiers that are created or updated as a result of this ECO. Provides traceability between the change order and specific BOM versions in SAP PP and Teamcenter.',
    `affected_drawing_revisions` STRING COMMENT 'Comma-separated list or description of the engineering drawing revision identifiers (CAD/CAM drawings) that are updated as part of this ECO. Ensures drawing version control traceability in Teamcenter PDM.',
    `affected_part_numbers` STRING COMMENT 'Comma-separated list of material/part numbers (SAP material numbers or Teamcenter item IDs) directly affected by this engineering change. Used for impact analysis and to identify all downstream BOM assemblies requiring update.',
    `affected_routing_revisions` STRING COMMENT 'Comma-separated list or description of the production routing (Bill of Process/BoP) revision identifiers updated by this ECO. Routing changes affect work center assignments, operation sequences, and standard times in SAP PP.',
    `approved_date` DATE COMMENT 'The date on which the ECO received final authorization to proceed with implementation. Marks the transition from approval workflow to release for manufacturing execution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `change_class` STRING COMMENT 'Severity classification of the engineering change. Class 1 (Major) changes affect form, fit, or function and require full PPAP re-submission; Class 2 (Minor) changes require limited validation; Class 3 (Administrative) changes are documentation-only.. Valid values are `class_1_major|class_2_minor|class_3_administrative`',
    `change_type` STRING COMMENT 'Classification of the type of engineering change being implemented. Determines which downstream systems (SAP PP BOM, Teamcenter drawings, routing) must be updated and which approval workflows are triggered.. Valid values are `design_change|process_change|material_substitution|drawing_revision|bom_revision|routing_revision|specification_change|regulatory_compliance|cost_reduction|quality_improvement|safety_improvement|customer_request`',
    `completed_date` DATE COMMENT 'The actual date on which all implementation tasks for the ECO were confirmed complete, including BOM updates, drawing revisions, routing changes, and shop floor verification. Used for cycle time analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary country where this engineering change is being implemented. Supports multi-country regulatory compliance tracking and regional reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated and actual cost fields (e.g., USD, EUR, GBP). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `customer_approval_required` BOOLEAN COMMENT 'Indicates whether formal written customer approval must be obtained before the engineering change can be implemented. Applicable for changes to customer-specific designs or regulated products under customer quality agreements.. Valid values are `true|false`',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether the customer must be formally notified of this engineering change prior to or upon implementation. Required for changes affecting form, fit, or function on customer-specific products or under contractual SLA obligations.. Valid values are `true|false`',
    `description` STRING COMMENT 'Detailed narrative describing the technical change being implemented, including what is changing, why it is changing, and the expected outcome. Supports traceability and regulatory audit requirements.',
    `disposition_of_stock` STRING COMMENT 'Defines how existing finished goods and raw material inventory affected by the change are to be handled. Determines whether pre-change stock can be consumed, must be reworked, or must be scrapped.. Valid values are `use_as_is|rework|scrap|return_to_supplier|hold_for_review|consume_before_effectivity`',
    `disposition_of_wip` STRING COMMENT 'Defines how existing Work in Progress (WIP) inventory and in-process assemblies are to be handled at the time the engineering change becomes effective. Drives shop floor instructions and material disposition in SAP MM/PP.. Valid values are `use_as_is|rework|scrap|return_to_supplier|hold_for_review`',
    `effectivity_date` DATE COMMENT 'The calendar date on which the engineering change becomes effective in production, applicable when effectivity_type is date_based. Used to schedule BOM and routing updates in SAP PP and Teamcenter.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_lot_number_from` STRING COMMENT 'The starting production lot number from which the engineering change becomes effective, applicable when effectivity_type is lot_based. All lots at or above this number incorporate the change.',
    `effectivity_serial_number_from` STRING COMMENT 'The starting serial number from which the engineering change becomes effective, applicable when effectivity_type is serial_number_based. All units with serial numbers at or above this value incorporate the change.',
    `effectivity_type` STRING COMMENT 'Defines the method by which the engineering change becomes effective in production. Date-based effectivity triggers on a calendar date; serial-number-based triggers at a specific unit; lot-based triggers at a specific production lot. Drives SAP PP BOM and routing effectivity configuration.. Valid values are `date_based|serial_number_based|lot_based|unit_based|immediate`',
    `estimated_cost` DECIMAL(18,2) COMMENT 'Estimated total cost to implement the engineering change, including engineering labor, tooling, material scrap/rework, and validation costs. Used for change impact assessment, CAPEX/OPEX planning, and ROI analysis.',
    `implementation_deadline` DATE COMMENT 'The mandatory completion date by which all BOM revisions, drawing revisions, routing revisions, and shop floor updates must be fully implemented. Used for scheduling, escalation management, and compliance tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `number` STRING COMMENT 'Human-readable, business-facing identifier for the Engineering Change Order as assigned by the PLM/PDM system (Siemens Teamcenter). Used for cross-system referencing in SAP PP, shop floor communications, and audit trails.. Valid values are `^ECO-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `originating_department` STRING COMMENT 'The organizational department that initiated the engineering change request (e.g., Product Engineering, Quality, Manufacturing, Customer Service). Used for change volume analytics and departmental accountability reporting.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or facilities where the engineering change must be implemented. Supports multi-plant rollout coordination and plant-specific BOM/routing updates.',
    `ppap_level` STRING COMMENT 'The PPAP submission level required for this engineering change, ranging from Level 1 (Part Submission Warrant only) to Level 5 (full documentation retained at customer location). Determined by customer requirements and change classification.. Valid values are `level_1|level_2|level_3|level_4|level_5|not_applicable`',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process (PPAP) submission is required for this engineering change, typically mandated for Class 1 (Major) changes affecting form, fit, or function for automotive or regulated customers.. Valid values are `true|false`',
    `priority` STRING COMMENT 'Business priority assigned to the ECO, reflecting urgency of implementation. Critical priority ECOs (e.g., safety or regulatory-driven) are fast-tracked through approval and implementation workflows.. Valid values are `critical|high|medium|low`',
    `reason_code` STRING COMMENT 'Standardized reason code indicating the primary business driver for the engineering change. Used for root cause analysis, change trend reporting, and CAPA linkage.. Valid values are `safety|regulatory_compliance|quality_defect|cost_reduction|customer_request|design_improvement|supplier_change|obsolescence|warranty_issue|manufacturing_issue|drawing_error|other`',
    `regulatory_driven` BOOLEAN COMMENT 'Indicates whether this engineering change is mandated by a regulatory requirement (e.g., RoHS/REACH compliance, CE Marking, UL certification, OSHA safety requirement). Regulatory-driven ECOs receive elevated priority and mandatory completion tracking.. Valid values are `true|false`',
    `regulatory_reference` STRING COMMENT 'Specific regulatory standard, directive, or requirement number that mandates this engineering change (e.g., RoHS 2011/65/EU, REACH SVHC List Update, CE Marking EN 60204-1). Populated only when regulatory_driven is true.',
    `released_date` DATE COMMENT 'The date on which the ECO was formally released to manufacturing and the updated BOM/routing/drawings were published in SAP PP and Teamcenter for shop floor execution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `requested_date` DATE COMMENT 'The date on which the ECO was formally requested or initiated. Used for lead time analysis and change management performance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the lead engineer accountable for coordinating and completing the ECO implementation. This is the primary point of contact for all technical questions related to the change.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this ECO record was sourced (e.g., Siemens Teamcenter PLM, SAP S/4HANA). Supports data lineage tracking and reconciliation in the lakehouse silver layer.. Valid values are `teamcenter|sap_s4hana|manual|other`',
    `source_system_code` STRING COMMENT 'The native identifier of this ECO record in the originating operational system (e.g., Teamcenter Change Order UID or SAP Change Number). Enables bidirectional traceability between the lakehouse and the system of record.',
    `status` STRING COMMENT 'Current lifecycle status of the ECO, tracking its progression from initial drafting through approval, release to manufacturing, implementation, and closure. Drives workflow routing in Teamcenter and SAP PP.. Valid values are `draft|submitted|under_review|approved|released|in_implementation|completed|cancelled|on_hold`',
    `title` STRING COMMENT 'Short, descriptive title summarizing the nature and scope of the engineering change. Used in dashboards, approval workflows, and stakeholder communications.',
    CONSTRAINT pk_eco PRIMARY KEY(`eco_id`)
) COMMENT 'Engineering Change Order record representing the formal authorization and implementation instruction derived from an approved ECN. Captures ECO number, linked ECN, implementation scope (affected BOM revisions, drawing revisions, routing revisions), effectivity type (date-based, serial number-based, lot-based), implementation deadline, responsible engineer, and completion status. Drives BOM and routing updates in SAP PP and Teamcenter.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`change_affected_item` (
    `change_affected_item_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each association record between an engineering change (ECN/ECO) and a specific affected item (component, BOM, drawing, routing, or document) within the Siemens Teamcenter PLM change management module.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Change affected items identify components impacted by ECO/ECN. Change management teams use this to assess impact and coordinate implementation across production.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: change_affected_item.ecn_number is a STRING reference to the ECN this affected item is associated with. change_affected_item is the association record linking ECNs/ECOs to affected items. Replacing wi',
    `eco_id` BIGINT COMMENT 'Foreign key linking to engineering.eco. Business justification: change_affected_item.eco_number is a STRING reference to the ECO this affected item is associated with. Replacing with FK eco_id → eco.eco_id enforces referential integrity for the ECO-to-affected-ite',
    `inspection_plan_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_plan. Business justification: Engineering changes affect inspection plans when component specifications change. Change management tracks which inspection plans require updates to reflect new tolerances or characteristics.',
    `sales_order_id` BIGINT COMMENT 'Foreign key linking to order.sales_order. Business justification: Engineering changes must track affected open sales orders to determine if order amendments, customer notifications, or delivery schedule changes are required.',
    `affected_plant_codes` STRING COMMENT 'Comma-separated list of SAP plant codes for all manufacturing facilities where this affected item is produced or used, and where the engineering change must be implemented. Supports global change rollout coordination across multinational manufacturing sites.',
    `bom_position` STRING COMMENT 'The BOM line item position or component item number within the parent assemblys Bill of Materials where this affected item resides. Enables precise identification of the structural location of the change within the product hierarchy.',
    `capa_reference` STRING COMMENT 'Reference number of the associated Corrective and Preventive Action (CAPA) record in the Quality Management System (QMS) that triggered or is linked to this engineering change for the affected item. Enables traceability between quality events and engineering change actions.',
    `change_action` STRING COMMENT 'The specific action to be performed on the affected item as a result of the engineering change. Revise updates an existing item to a new revision; Create introduces a new item; Obsolete retires an item from active use; Supersede replaces one item with another; Incorporate merges changes into an existing revision; Cancel voids a previously planned change.. Valid values are `revise|create|obsolete|supersede|incorporate|cancel`',
    `change_description` STRING COMMENT 'Detailed narrative description of what specifically changed for this affected item, including the nature of the modification, the technical rationale, and any relevant engineering justification. Provides the human-readable explanation of the change for engineers, quality auditors, and regulatory reviewers.',
    `change_reason_code` STRING COMMENT 'Standardized code categorizing the primary business reason driving the engineering change for this affected item. Supports root cause analysis, change trend reporting, and CAPA (Corrective and Preventive Action) linkage in the QMS.. Valid values are `design_error|customer_requirement|regulatory_compliance|cost_reduction|supplier_change|quality_improvement|obsolescence|safety|performance|standardization|other`',
    `cost_impact_category` STRING COMMENT 'High-level classification of the financial impact of the engineering change on this affected item. Indicates whether the change is expected to reduce, maintain, or increase the cost of the item, supporting financial impact assessment and CAPEX/OPEX planning.. Valid values are `cost_reduction|cost_neutral|cost_increase|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this change affected item association record was created in the PLM/PDM system. Provides the audit trail entry point for the change record lifecycle.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated cost impact value (e.g., USD, EUR, GBP, CNY). Supports multi-currency financial reporting in global manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `disposition_action` STRING COMMENT 'The required disposition for existing inventory or work-in-progress (WIP) stock of the affected item at the time the change is implemented. Determines whether existing stock should be used as-is, reworked to the new revision, scrapped, returned to supplier, retrofitted in the field, or held pending further review.. Valid values are `use_as_is|rework|scrap|return_to_supplier|retrofit|hold_for_review`',
    `effectivity_date` DATE COMMENT 'The calendar date from which the engineering change becomes effective for this affected item when date-based effectivity is used. Drives production scheduling, procurement cutover, and inventory disposition decisions in SAP S/4HANA MRP.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_serial_number` STRING COMMENT 'The manufacturing serial number from which the engineering change becomes effective when serial-number-based effectivity is used. Ensures that units produced at or after this serial number incorporate the change, while earlier units retain the previous configuration.',
    `effectivity_type` STRING COMMENT 'Defines the method by which the engineering change becomes effective for this item. Date effectivity applies the change from a specific calendar date; serial number effectivity applies from a specific unit serial number; lot effectivity applies from a specific production lot; unit effectivity applies to specific unit numbers; immediate applies without a scheduled effectivity point.. Valid values are `date_effectivity|serial_number_effectivity|lot_effectivity|unit_effectivity|immediate`',
    `estimated_cost_impact` DECIMAL(18,2) COMMENT 'The estimated financial impact (positive or negative) of implementing the engineering change on this affected item, expressed in the transaction currency. Negative values indicate cost savings; positive values indicate cost increases. Used for change approval financial justification.',
    `form_fit_function_flag` BOOLEAN COMMENT 'Indicates whether the engineering change affects the form, fit, or function of the affected item. A true value triggers mandatory customer notification, PPAP re-submission, and regulatory re-evaluation workflows in accordance with customer-specific requirements and quality standards.. Valid values are `true|false`',
    `impact_level` STRING COMMENT 'Assessment of the severity and scope of the engineering change impact on this affected item. Critical changes affect form, fit, or function and may require customer notification or regulatory re-approval; major changes affect performance or interchangeability; minor changes are non-functional improvements; cosmetic changes affect appearance only.. Valid values are `critical|major|minor|cosmetic`',
    `implementation_date` DATE COMMENT 'The actual date on which the engineering change was physically implemented for this affected item in the production environment. Distinguishes the planned effectivity date from the actual execution date for change tracking and audit purposes.. Valid values are `^d{4}-d{2}-d{2}$`',
    `implementation_status` STRING COMMENT 'Current status of the engineering change implementation for this specific affected item. Tracks the lifecycle from initial identification through verification, enabling program managers and engineers to monitor change execution progress across all affected items.. Valid values are `pending|in_progress|implemented|verified|rejected|on_hold|cancelled`',
    `item_name` STRING COMMENT 'The descriptive name or title of the affected item (e.g., part description, drawing title, document name) as recorded in the PLM/PDM system. Provides human-readable identification alongside the item number.',
    `item_number` STRING COMMENT 'The unique part number, document number, or identifier of the specific item affected by the engineering change, as maintained in the PLM/PDM or ERP system (SAP S/4HANA MM or Teamcenter). This is the primary business key for the affected object.',
    `item_type` STRING COMMENT 'Classification of the item affected by the engineering change. Indicates whether the affected object is a component, assembly, Bill of Materials (BOM), engineering drawing, manufacturing routing, controlled document, tooling, specification, software artifact, or firmware image.. Valid values are `component|assembly|bom|drawing|routing|document|tool|specification|software|firmware`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this change affected item record was most recently updated in the PLM/PDM system. Supports change audit trails, data lineage tracking, and incremental data pipeline processing in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `ncr_reference` STRING COMMENT 'Reference number of the Non-Conformance Report (NCR) associated with this affected item change record. Links the engineering change to the specific quality non-conformance event that necessitated the design or process modification.',
    `new_revision` STRING COMMENT 'The revision identifier assigned to the affected item after the engineering change is implemented. Represents the updated configuration baseline and is used for release control and downstream BOM/routing updates.. Valid values are `^[A-Z0-9]{1,10}$`',
    `old_revision` STRING COMMENT 'The revision identifier (e.g., A, B, 01, REV-C) of the affected item prior to the engineering change being applied. Establishes the baseline from which the change is made and supports full revision history traceability.. Valid values are `^[A-Z0-9]{1,10}$`',
    `owning_plant_code` STRING COMMENT 'The SAP plant code or facility identifier of the manufacturing plant responsible for implementing the change on this affected item. Supports multi-plant change management and ensures the correct facility executes the change in global manufacturing operations.',
    `parent_item_number` STRING COMMENT 'The part number or identifier of the parent assembly or document that directly contains or references the affected item. Supports where-used analysis and impact assessment across the product structure when evaluating the scope of an engineering change.',
    `planned_implementation_date` DATE COMMENT 'The originally scheduled date for implementing the engineering change on this affected item. Used for program planning, resource scheduling, and on-time delivery tracking. Compared against the actual implementation date to measure change execution performance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `regulatory_approval_required` BOOLEAN COMMENT 'Indicates whether the engineering change to this affected item requires formal approval from an external regulatory body (e.g., CE Marking re-assessment, UL re-certification, RoHS/REACH compliance re-evaluation) before the change can be released to production.. Valid values are `true|false`',
    `regulatory_approval_status` STRING COMMENT 'Current status of the regulatory approval process for the engineering change on this affected item. Tracks whether external certification or compliance re-evaluation has been initiated, submitted to the authority, approved, or rejected.. Valid values are `not_required|pending|submitted|approved|rejected|conditionally_approved`',
    `responsible_engineer` STRING COMMENT 'The name or employee identifier of the design or process engineer accountable for implementing and verifying the engineering change on this specific affected item. Establishes clear ownership for change execution and audit trail purposes.',
    `safety_critical_flag` BOOLEAN COMMENT 'Indicates whether the affected item is classified as safety-critical, requiring mandatory safety review, DFMEA/PFMEA update, and regulatory authority notification before the change can be implemented. Applies to items subject to CE Marking, UL certification, ISO 45001, or OSHA requirements.. Valid values are `true|false`',
    `sequence_number` STRING COMMENT 'Numeric sequence number defining the order in which affected items within the same ECN/ECO should be processed or implemented. Ensures correct sequencing of interdependent changes across multiple affected items within a single engineering change.. Valid values are `^[0-9]+$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this change affected item record originated. Supports data lineage tracking and multi-system reconciliation in the Databricks Lakehouse Silver Layer.. Valid values are `teamcenter|sap_s4hana|opcenter|manual`',
    `verification_date` DATE COMMENT 'The date on which verification of the engineering change was completed for this affected item. Used to confirm that the change has been validated before the item is released for full production use.. Valid values are `^d{4}-d{2}-d{2}$`',
    `verification_method` STRING COMMENT 'The engineering verification method required to confirm that the change has been correctly implemented and meets design intent for this affected item. First Article Inspection (FAI) is commonly required for safety-critical or form-fit-function changes.. Valid values are `test|inspection|analysis|demonstration|similarity|first_article_inspection|none`',
    `verification_status` STRING COMMENT 'Current status of the verification activity for this affected item following change implementation. Indicates whether the required verification (test, inspection, FAI) has been completed successfully, is in progress, has failed, or has been formally waived.. Valid values are `not_started|in_progress|passed|failed|waived`',
    CONSTRAINT pk_change_affected_item PRIMARY KEY(`change_affected_item_id`)
) COMMENT 'Association record linking an ECN or ECO to each specific item (component, BOM, drawing, routing, document) affected by the engineering change. Captures the affected item type, item identifier, old revision, new revision, change action (revise, obsolete, create), and implementation status. Enables full traceability of what changed, when, and why across the product structure.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`dfmea` (
    `dfmea_id` BIGINT COMMENT 'Unique system-generated identifier for the DFMEA record within the enterprise data platform. Serves as the primary key for all downstream references and linkages.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: dfmea.part_number is a STRING reference to the component being analyzed in the Design FMEA. Replacing with FK component_id → component.component_id establishes the authoritative DFMEA-to-component tra',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: dfmea.ecn_reference is a STRING reference to the ECN that triggered or is associated with this DFMEA update. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design ri',
    `feedback_id` BIGINT COMMENT 'Foreign key linking to service.service_feedback. Business justification: Design FMEA incorporates field failure data from service feedback. Engineering uses actual service issues to identify failure modes and improve product reliability.',
    `fmea_id` BIGINT COMMENT 'Foreign key linking to quality.fmea. Business justification: Design FMEA is a specialized type of FMEA managed in quality systems. Engineering references the quality FMEA framework for risk assessment methodology and tracking.',
    `hazard_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.hazard_assessment. Business justification: Design FMEA must reference formal hazard assessments to ensure product designs address identified workplace hazards. Engineering uses HSE hazard data to inform failure mode analysis and design control',
    `project_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_project. Business justification: dfmea.project_code is a STRING reference to the engineering project under which this DFMEA was conducted. Replacing with FK engineering_project_id → engineering_project.engineering_project_id establis',
    `rd_risk_id` BIGINT COMMENT 'Foreign key linking to research.rd_risk. Business justification: Design FMEAs incorporate risks identified during R&D phase. Engineering uses R&D risk assessments to inform failure mode analysis, ensuring research-identified technical risks are mitigated in product',
    `action_completion_date` DATE COMMENT 'Actual date on which the recommended action was completed and verified. Used to measure APQP schedule adherence and close open DFMEA action items.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `action_priority` STRING COMMENT 'Action Priority classification (H=High, M=Medium, L=Low) per the AIAG-VDA FMEA Handbook, used alongside RPN to determine urgency of recommended actions. High priority requires immediate action regardless of RPN value.. Valid values are `H|M|L`',
    `action_taken` STRING COMMENT 'Description of the actual corrective or preventive action implemented to address the failure mode. Recorded after completion to close the DFMEA action loop and support CAPA documentation.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering manager or quality authority who formally approved the DFMEA document for release.',
    `apqp_phase` STRING COMMENT 'The APQP phase during which this DFMEA was created or last updated. Phase 1=Plan and Define, Phase 2=Product Design and Development, Phase 3=Process Design and Development, Phase 4=Product and Process Validation, Phase 5=Feedback Assessment and Corrective Action.. Valid values are `phase_1|phase_2|phase_3|phase_4|phase_5`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the engineering site or manufacturing location where the design is being developed. Supports multinational regulatory compliance tracking (e.g., CE Marking for EU, UL for USA).. Valid values are `^[A-Z]{3}$`',
    `customer_name` STRING COMMENT 'Name of the external customer or internal program for which this DFMEA is being prepared. Relevant for PPAP submissions and customer-specific requirements (CSR).',
    `design_control_detection` STRING COMMENT 'Current design controls in place to detect the failure mode or cause before the product reaches the customer (e.g., prototype testing, FEA simulation, design review checklist, First Article Inspection (FAI)). Addresses detection-type controls per AIAG-VDA Step 5.',
    `design_control_prevention` STRING COMMENT 'Current design controls in place to prevent the failure cause from occurring (e.g., design standard XYZ applied, material specification review, DFM analysis completed). Addresses prevention-type controls per AIAG-VDA Step 5.',
    `detection_rating` STRING COMMENT 'Numeric rating (1–10) assessing the ability of current design controls to detect the failure cause or failure mode before product release. A rating of 10 indicates no detection capability; 1 indicates near-certain detection.. Valid values are `^([1-9]|10)$`',
    `failure_cause` STRING COMMENT 'The specific design deficiency or root cause mechanism that leads to the failure mode (e.g., insufficient wall thickness, incorrect material specification, inadequate clearance between mating parts). Identified through DFMEA root cause analysis.',
    `failure_effect` STRING COMMENT 'The consequence of the failure mode on the next higher-level assembly, end customer, or end user. Describes what the customer experiences if the failure mode occurs (e.g., loss of motor control, vehicle does not start, operator injury).',
    `failure_mode` STRING COMMENT 'The specific manner in which the design element could potentially fail to meet its intended function or design intent (e.g., fracture under load, electrical short circuit, corrosion of contact surface). Core DFMEA field per AIAG-VDA Step 3.',
    `last_revised_date` DATE COMMENT 'Date of the most recent revision to the DFMEA document. Tracks the currency of the risk assessment and supports document control requirements.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `model_year` STRING COMMENT 'The model year or product generation to which this DFMEA applies. Used for product lifecycle tracking and APQP milestone alignment.. Valid values are `^[0-9]{4}$`',
    `number` STRING COMMENT 'Business-assigned alphanumeric identifier for the DFMEA document, used for cross-referencing in APQP deliverables, PPAP packages, and Teamcenter PLM. Unique within the organization.. Valid values are `^DFMEA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `occurrence_rating` STRING COMMENT 'Numeric rating (1–10) estimating the likelihood that the failure cause will occur and result in the failure mode. A rating of 10 indicates near-certain occurrence; 1 indicates extremely unlikely. Based on historical data, design similarity, and engineering judgment.. Valid values are `^([1-9]|10)$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or engineering site responsible for the product design covered by this DFMEA. Supports multi-site and multinational operations.',
    `ppap_submission_required` BOOLEAN COMMENT 'Indicates whether this DFMEA is required as part of a PPAP submission package to the customer. When true, the DFMEA must meet customer-specific requirements (CSR) for PPAP level compliance.. Valid values are `true|false`',
    `preparation_date` DATE COMMENT 'Date on which the DFMEA was initially prepared and documented. Used for APQP timeline tracking and document control.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `prepared_by` STRING COMMENT 'Name or employee identifier of the engineer or analyst who originally prepared and authored the DFMEA document.',
    `recommended_action` STRING COMMENT 'Specific corrective or preventive action recommended to reduce severity, occurrence, or detection ratings for high-priority failure modes. May include design changes, additional testing, material substitution, or tolerance revisions.',
    `regulatory_compliance_flag` BOOLEAN COMMENT 'Indicates whether this DFMEA addresses failure modes related to regulatory compliance requirements such as RoHS, REACH, CE Marking, UL certification, or OSHA/EPA mandates. Triggers mandatory compliance review workflow.. Valid values are `true|false`',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the design engineer responsible for implementing the recommended action and updating the DFMEA. Assigned per AIAG-VDA Step 6 accountability requirements.',
    `revised_detection_rating` STRING COMMENT 'Updated detection rating after implementation of recommended actions. Reflects improved detection capability post-mitigation.. Valid values are `^([1-9]|10)$`',
    `revised_occurrence_rating` STRING COMMENT 'Updated occurrence rating after implementation of recommended actions. Reflects the reduced likelihood of the failure cause occurring post-mitigation.. Valid values are `^([1-9]|10)$`',
    `revised_rpn` STRING COMMENT 'Recalculated Risk Priority Number (Revised S × Revised O × Revised D) after corrective actions have been implemented. Used to confirm risk reduction and validate DFMEA closure.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `revised_severity_rating` STRING COMMENT 'Updated severity rating after implementation of recommended actions. Reflects the residual risk level post-mitigation. Compared against original severity to demonstrate risk reduction effectiveness.. Valid values are `^([1-9]|10)$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the current version of the DFMEA document (e.g., A, B, C, 01, 02). Incremented upon each approved Engineering Change Notice (ECN) or design update.. Valid values are `^[A-Z0-9]{1,5}$`',
    `rpn` STRING COMMENT 'Risk Priority Number calculated as the product of Severity × Occurrence × Detection ratings (S × O × D). Ranges from 1 to 1000. Used to prioritize failure modes requiring corrective action. Note: AIAG-VDA also uses Action Priority (AP) as a complementary risk metric.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `safety_critical` BOOLEAN COMMENT 'Indicates whether any failure mode in this DFMEA has a severity rating of 9 or 10, classifying it as safety-critical or regulatory-critical. Safety-critical DFMEAs require mandatory escalation and additional design validation per ISO 26262, IEC 61508, or applicable product safety standards.. Valid values are `true|false`',
    `scope_description` STRING COMMENT 'Narrative description of the specific component, assembly, or system covered by this DFMEA, including functional boundaries and interfaces considered in the analysis.',
    `scope_level` STRING COMMENT 'Defines the hierarchical level of the design analysis scope: component (individual part), subsystem (grouped components), assembly (full assembly), or system (complete product system). Determines the depth and breadth of the FMEA analysis.. Valid values are `component|subsystem|system|assembly`',
    `severity_rating` STRING COMMENT 'Numeric rating (1–10) indicating the seriousness of the failure effect on the customer or end user. A rating of 10 indicates a safety-critical failure with no warning; 1 indicates no discernible effect. Defined per AIAG-VDA severity criteria.. Valid values are `^([1-9]|10)$`',
    `status` STRING COMMENT 'Current lifecycle status of the DFMEA record: draft (initial creation), in_review (under engineering review), approved (formally approved and baselined), closed (all actions completed), obsolete (superseded by a newer revision).. Valid values are `draft|in_review|approved|closed|obsolete`',
    `target_completion_date` DATE COMMENT 'Planned date by which the recommended action must be completed and verified. Used for APQP milestone tracking and PPAP readiness assessment.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `teamcenter_document_code` STRING COMMENT 'Unique document identifier assigned by Siemens Teamcenter PLM for the DFMEA document object. Enables direct traceability to the authoritative source document in the PLM/PDM system.',
    `title` STRING COMMENT 'Descriptive title of the DFMEA document, typically referencing the product, component, or assembly being analyzed (e.g., Motor Drive Assembly DFMEA – Electrification Module).',
    CONSTRAINT pk_dfmea PRIMARY KEY(`dfmea_id`)
) COMMENT 'Design Failure Mode and Effects Analysis record capturing the structured risk assessment of potential design failures for a component or assembly. Records DFMEA number, revision, scope (component or system level), each failure mode, potential effect, severity rating, potential cause, occurrence rating, current design controls, detection rating, RPN (Risk Priority Number), recommended actions, and responsible engineer. Supports APQP and PPAP deliverables. Managed in Teamcenter and linked to quality domain.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`pfmea` (
    `pfmea_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each PFMEA record in the Databricks Silver Layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: pfmea.product_part_number is a STRING reference to the component/part being analyzed in the Process FMEA. Replacing with FK component_id → component.component_id establishes the authoritative PFMEA-to',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: pfmea.ecn_reference is a STRING reference to the ECN associated with this PFMEA update. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for process risk analysis. ecn_ref',
    `fmea_id` BIGINT COMMENT 'Foreign key linking to quality.fmea. Business justification: Process FMEA is a specialized FMEA type managed in quality systems. Manufacturing engineering uses quality FMEA structure for process risk analysis and mitigation tracking.',
    `hazard_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.hazard_assessment. Business justification: Process FMEA integrates HSE hazard assessments to evaluate process failure modes that could create safety risks. Manufacturing engineers reference hazard assessments when designing process controls an',
    `action_completion_date` DATE COMMENT 'Actual date on which the recommended action was completed and evidence of implementation was recorded. Used to close out action items in CAPA workflows and update the PFMEA with revised ratings.. Valid values are `^d{4}-d{2}-d{2}$`',
    `action_priority` STRING COMMENT 'AIAG-VDA 2019 Action Priority classification (High/Medium/Low) derived from the combination of Severity, Occurrence, and Detection ratings using the AP lookup table. Supersedes sole reliance on RPN for prioritization in the updated PFMEA methodology.. Valid values are `high|medium|low`',
    `action_responsibility` STRING COMMENT 'Name or role of the person or team responsible for implementing the recommended action. Used for accountability tracking in CAPA workflows and PFMEA review meetings.',
    `action_target_date` DATE COMMENT 'Target date by which the recommended action must be completed and verified. Monitored in SAP QM CAPA tracking and PFMEA review cycles to ensure timely risk mitigation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approval_date` DATE COMMENT 'Date on which the PFMEA document was formally approved and released for production use. Establishes the effective date for quality control plan alignment and PPAP submission records.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the quality or engineering authority who formally approved the PFMEA document for release. Required for PPAP Level 3/4 submission and customer-facing quality documentation.',
    `bop_operation_name` STRING COMMENT 'Human-readable name of the manufacturing operation from the Bill of Process (BoP) being analyzed, such as Robotic MIG Welding, CNC Milling, or Electrification Module Assembly.',
    `bop_operation_number` STRING COMMENT 'Reference to the specific manufacturing operation within the Bill of Process (BoP) that this PFMEA record analyzes. Links the risk assessment to the process step in Siemens Opcenter MES and SAP PP routing.',
    `capa_number` STRING COMMENT 'Reference number of the linked Corrective and Preventive Action (CAPA) record in SAP QM or the Quality Management System (QMS). Establishes traceability between the PFMEA risk item and the formal corrective action workflow.. Valid values are `^CAPA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `control_plan_number` STRING COMMENT 'Reference number of the associated SPC Control Plan that incorporates the detection controls and inspection frequencies derived from this PFMEA. Links PFMEA outputs to Siemens Opcenter quality inspection plans.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the PFMEA record was first created in the system. Used for audit trail, data lineage tracking, and PFMEA lifecycle reporting in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `current_detection_control` STRING COMMENT 'Description of existing process controls designed to detect the failure mode or failure cause before the product reaches the next operation or customer (e.g., In-process CMM inspection, Vision system check, SPC control chart monitoring).',
    `current_prevention_control` STRING COMMENT 'Description of existing process controls designed to prevent the failure cause or failure mode from occurring (e.g., Poka-Yoke fixture, Operator SOP training, Incoming material inspection). Supports Poka-Yoke and error-proofing documentation.',
    `detection_rating` STRING COMMENT 'Numeric rating (1–10) assessing the ability of current detection controls to identify the failure cause or failure mode before the product leaves the process. A rating of 1 indicates near-certain detection; 10 indicates no detection capability.. Valid values are `^([1-9]|10)$`',
    `failure_cause` STRING COMMENT 'Root cause or mechanism by which the failure mode could occur in the process. Describes the specific process deficiency, variation source, or error condition (e.g., Worn electrode tip, Operator setup error, Material hardness variation).',
    `failure_effect` STRING COMMENT 'Description of the consequence or impact of the failure mode on the next operation, end customer, or product quality. Used to justify the severity rating and drive prioritization of corrective actions.',
    `failure_mode` STRING COMMENT 'Description of the specific way in which the process could potentially fail to meet its intended function or process requirement. Core element of the PFMEA risk assessment (e.g., Insufficient weld penetration, Incorrect torque applied).',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the PFMEA record. Supports change detection in ETL pipelines, audit compliance, and version control within the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead` STRING COMMENT 'Name or employee identifier of the lead process engineer responsible for authoring, maintaining, and updating the PFMEA document. Primary point of contact for PFMEA-related quality inquiries.',
    `model_year` STRING COMMENT 'Model year or program year associated with the product or platform for which this PFMEA was developed. Used for APQP program tracking and PPAP submission documentation.. Valid values are `^[0-9]{4}$`',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of the PFMEA to ensure it remains current with process changes, quality data trends, and engineering change orders. Supports proactive risk management per IATF 16949 requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `number` STRING COMMENT 'Business-assigned document control number for the PFMEA, used for cross-referencing in quality management systems, Siemens Teamcenter PLM, and SAP QM. Follows the enterprise document numbering convention.. Valid values are `^PFMEA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `occurrence_rating` STRING COMMENT 'Numeric rating (1–10) estimating the likelihood or frequency of the failure cause occurring during production. Based on historical process data, Statistical Process Control (SPC) data, or engineering judgment per AIAG-VDA criteria.. Valid values are `^([1-9]|10)$`',
    `plant_code` STRING COMMENT 'Code identifying the manufacturing plant or facility where the process being analyzed is executed. Supports multi-site PFMEA management and plant-level quality reporting across global operations.',
    `process_function` STRING COMMENT 'The intended function or purpose of the process step being analyzed, describing what the operation is designed to achieve (e.g., Join two steel components with specified weld penetration depth).',
    `process_step` STRING COMMENT 'Detailed description of the specific process step or sub-operation within the BoP operation being analyzed in this PFMEA record. Provides granular context for the failure mode analysis.',
    `recommended_action` STRING COMMENT 'Specific corrective or preventive action recommended to reduce the severity, occurrence, or detection rating of the identified failure mode. Drives CAPA initiation in SAP QM and Siemens Opcenter quality workflows.',
    `revised_detection_rating` STRING COMMENT 'Updated detection rating (1–10) after implementation of the recommended action. Reflects improved detection capability resulting from new inspection methods, SPC controls, or automated detection systems.. Valid values are `^([1-9]|10)$`',
    `revised_occurrence_rating` STRING COMMENT 'Updated occurrence rating (1–10) after implementation of the recommended action. Reflects the reduced likelihood of the failure cause occurring following process improvements or error-proofing measures.. Valid values are `^([1-9]|10)$`',
    `revised_rpn` STRING COMMENT 'Recalculated Risk Priority Number (Revised S × Revised O × Revised D) after completion of recommended actions. Demonstrates risk reduction effectiveness and supports PFMEA closure criteria.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `revised_severity_rating` STRING COMMENT 'Updated severity rating (1–10) after implementation of the recommended action. Reflects the residual risk level post-mitigation and is used to recalculate the revised RPN for the PFMEA record.. Valid values are `^([1-9]|10)$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the current version of the PFMEA document. Incremented upon each approved Engineering Change Notice (ECN) or process change that impacts the risk assessment.. Valid values are `^[A-Z]{1,3}$|^[0-9]{1,3}$`',
    `rpn` STRING COMMENT 'Risk Priority Number calculated as the product of Severity × Occurrence × Detection ratings (range 1–1000). Used to prioritize failure modes requiring corrective action. High RPN values trigger mandatory CAPA initiation per quality management policy.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `severity_rating` STRING COMMENT 'Numeric rating (1–10) assessing the seriousness of the failure effect on the customer or next process. A rating of 10 indicates a safety or regulatory compliance impact. Defined per AIAG-VDA severity evaluation criteria.. Valid values are `^([1-9]|10)$`',
    `status` STRING COMMENT 'Current lifecycle status of the PFMEA document. Controls workflow routing in Siemens Teamcenter PLM and determines whether the PFMEA is active for production use in Siemens Opcenter MES quality inspection plans.. Valid values are `draft|in_review|approved|released|obsolete|superseded`',
    `team_members` STRING COMMENT 'Comma-separated list of names or employee IDs of cross-functional team members who participated in the PFMEA development session. Documents team composition for APQP and PPAP submission requirements.',
    `title` STRING COMMENT 'Descriptive title of the PFMEA document, typically referencing the process, product family, or manufacturing operation being analyzed (e.g., Welding Process PFMEA – Automation Frame Assembly).',
    `work_center` STRING COMMENT 'SAP work center or Opcenter resource identifier where the manufacturing operation is performed. Provides traceability from the PFMEA risk item to the physical production resource on the shop floor.',
    CONSTRAINT pk_pfmea PRIMARY KEY(`pfmea_id`)
) COMMENT 'Process Failure Mode and Effects Analysis record capturing the structured risk assessment of potential process failures for each manufacturing operation in the Bill of Process. Records PFMEA number, revision, linked BOP operation, failure mode, potential effect on product quality, severity, potential cause, occurrence, current process controls, detection rating, RPN, recommended actions, and CAPA linkage. Feeds SPC control plans and Opcenter quality inspection plans.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`engineering_prototype` (
    `engineering_prototype_id` BIGINT COMMENT 'Unique system-generated identifier for each prototype record within the engineering domain. Serves as the primary key for all prototype-related data and linkages.',
    `apqp_project_id` BIGINT COMMENT 'Foreign key linking to quality.apqp_project. Business justification: Prototypes are built during APQP Phase 2 and 3 for design verification. Engineering tracks prototype builds against APQP project timelines and deliverable requirements.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Prototype builds must document which technician or engineer constructed the unit for quality traceability, skill assessment, and issue resolution when prototype defects are discovered.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: prototype.component_number is a STRING reference to the component being prototyped. Replacing with FK component_id → component.component_id establishes the authoritative prototype-to-component traceab',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Prototypes are often built for specific customer validation, testing, or approval before production. Engineering tracks which customer the prototype is intended for to manage delivery, feedback collec',
    `dfmea_id` BIGINT COMMENT 'Foreign key linking to engineering.dfmea. Business justification: prototype.dfmea_number is a STRING reference to the DFMEA that informed the prototype design. Replacing with FK dfmea_id → dfmea.dfmea_id establishes the DFMEA-to-prototype traceability required for d',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: prototype.ecn_number is a STRING reference to the ECN associated with this prototype build. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for prototype development. ecn',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Prototype builds are funded through internal orders for R&D cost collection. Finance tracks all prototype materials, labor, and testing costs against the internal order for project accounting.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Prototypes are built on production equipment to validate manufacturability. Engineering tracks which equipment produced prototypes to correlate design performance with equipment capability and process',
    `project_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_project. Business justification: prototype.project_number is a STRING reference to the engineering project under which this prototype was built. Replacing with FK engineering_project_id → engineering_project.engineering_project_id es',
    `actual_build_cost` DECIMAL(18,2) COMMENT 'Actual total cost incurred to build the prototype, captured from SAP CO/PP cost collection. Compared against estimated cost for budget variance analysis and R&D cost management.',
    `apqp_phase` STRING COMMENT 'The APQP phase gate to which this prototype is associated, enabling tracking of prototype activities against the structured product quality planning lifecycle mandated by automotive and industrial manufacturing standards.. Valid values are `phase_1_plan_and_define|phase_2_product_design_and_development|phase_3_process_design_and_development|phase_4_product_and_process_validation|phase_5_feedback_assessment_and_corrective_action`',
    `build_date` DATE COMMENT 'The date on which the prototype build was completed or initiated. Used for APQP milestone tracking, design timeline analysis, and engineering change correlation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `build_quantity` STRING COMMENT 'The number of physical or virtual prototype units authorized and built for this prototype record. Used for material planning, cost tracking, and test coverage analysis.. Valid values are `^[1-9][0-9]*$`',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated and actual build cost values (e.g., USD, EUR, CNY). Supports multi-currency reporting in global manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the prototype record was first created in the system, captured in ISO 8601 format with timezone offset. Used for audit trail and data lineage tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Detailed narrative describing the purpose, scope, and key characteristics of the prototype, including design intent and validation objectives.',
    `design_revision` STRING COMMENT 'The specific design revision or version of the component or assembly drawing that was in effect at the time this prototype was built. Critical for traceability and change management under ECN/ECO workflows.. Valid values are `^[A-Z0-9]{1,10}$`',
    `dfa_classification` STRING COMMENT 'Assessment of the prototype design against Design for Assembly principles, evaluating ease of assembly, part count optimization, and assembly error-proofing (Poka-Yoke) compliance.. Valid values are `dfa_compliant|dfa_conditional|dfa_non_compliant|not_assessed`',
    `dfm_classification` STRING COMMENT 'Assessment of the prototype design against Design for Manufacturability principles, indicating whether the design can be efficiently and cost-effectively manufactured at scale.. Valid values are `dfm_compliant|dfm_conditional|dfm_non_compliant|not_assessed`',
    `disposition` STRING COMMENT 'Final disposition decision for the prototype after testing and evaluation are complete. Determines whether the prototype is retained for reference, scrapped, repurposed, or archived per engineering records management policy.. Valid values are `retain|scrap|return_to_supplier|repurpose|archive|pending_disposition`',
    `engineering_team` STRING COMMENT 'Name or code of the engineering team or department responsible for this prototype, such as Automation Systems R&D or Electrification Solutions Engineering. Supports resource and workload reporting.',
    `estimated_build_cost` DECIMAL(18,2) COMMENT 'Estimated total cost to build the prototype, including materials, labor, and tooling. Used for R&D budget tracking, CAPEX planning, and cost-of-development analysis.',
    `fai_number` STRING COMMENT 'Reference to the First Article Inspection record associated with this prototype, confirming that the production process produces a part conforming to engineering drawings and specifications.',
    `fai_status` STRING COMMENT 'Current status of the First Article Inspection process for this prototype, indicating whether FAI has been initiated, completed, approved, or waived by engineering authority.. Valid values are `not_required|pending|in_progress|approved|rejected|waived`',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether the prototype materials and substances have been assessed and confirmed compliant with the EU REACH regulation governing chemical safety in manufactured products.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether the prototype design and materials have been verified to comply with the EU RoHS Directive restricting the use of hazardous substances in electrical and electronic equipment.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the prototype record, used for change tracking, audit compliance, and data freshness monitoring in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `location` STRING COMMENT 'Physical location or facility where the prototype is built, stored, or undergoing testing. Includes plant code, lab designation, or storage area identifier for asset tracking and logistics.',
    `name` STRING COMMENT 'Descriptive name of the prototype, typically reflecting the product or assembly being validated (e.g., Alpha Drive Controller Unit Rev B). Used for display and search in PLM and engineering portals.',
    `number` STRING COMMENT 'Human-readable, business-assigned identifier for the prototype, used across engineering, PLM, and MES systems for cross-functional reference and traceability. Typically generated by Siemens Teamcenter PLM.. Valid values are `^PROTO-[A-Z0-9]{4,20}$`',
    `planned_build_date` DATE COMMENT 'The originally scheduled date for completing the prototype build, used for schedule adherence tracking and APQP phase gate milestone management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility responsible for building or testing this prototype. Enables multi-site tracking and cost allocation in global operations.. Valid values are `^[A-Z0-9]{2,10}$`',
    `ppap_level` STRING COMMENT 'The PPAP submission level required for this prototype, defining the extent of documentation and physical samples to be submitted for customer or internal approval prior to production release.. Valid values are `level_1|level_2|level_3|level_4|level_5|not_applicable`',
    `ppap_status` STRING COMMENT 'Current status of the PPAP submission process for this prototype, tracking progress from initiation through customer or internal approval. Required for production release authorization.. Valid values are `not_started|in_progress|submitted|approved|rejected|interim_approval`',
    `product_line` STRING COMMENT 'The product line or product family to which this prototype belongs (e.g., Industrial Automation, Electrification Solutions, Smart Infrastructure). Supports portfolio-level reporting and resource allocation.',
    `regulatory_compliance_scope` STRING COMMENT 'Comma-separated list of regulatory standards or certifications that this prototype must demonstrate compliance with (e.g., CE Marking, RoHS, REACH, UL, IEC 62443). Drives compliance testing requirements.',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the lead engineer accountable for the prototype design, build, and validation activities. Used for accountability tracking and APQP gate review ownership.',
    `status` STRING COMMENT 'Current lifecycle status of the prototype, tracking its progression from planning through build, testing, and final disposition. Drives APQP phase gate reviews and engineering workflow actions.. Valid values are `planned|in_build|in_test|completed|scrapped|on_hold`',
    `target_market` STRING COMMENT 'The intended end-market or application segment for the product being prototyped. Informs design requirements, regulatory compliance needs, and go-to-market planning.. Valid values are `factory_automation|building_automation|transportation|energy|urban_infrastructure|general_industrial`',
    `test_completion_date` DATE COMMENT 'The date on which all formal testing activities for this prototype were concluded. Used for test cycle duration analysis and phase gate closure.. Valid values are `^d{4}-d{2}-d{2}$`',
    `test_objectives` STRING COMMENT 'Narrative description of the specific engineering, functional, or performance objectives that this prototype is intended to validate. Drives test plan development and acceptance criteria definition.',
    `test_plan_number` STRING COMMENT 'Reference identifier for the formal test plan document governing the validation activities for this prototype. Links to the test management system or PLM document repository.',
    `test_result` STRING COMMENT 'Overall outcome of the prototype testing activities against the defined test objectives and acceptance criteria. Drives disposition decisions and APQP phase gate approvals.. Valid values are `pass|fail|conditional_pass|inconclusive|not_tested`',
    `test_start_date` DATE COMMENT 'The date on which formal testing of the prototype commenced. Used for test cycle duration tracking and APQP milestone reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `type` STRING COMMENT 'Classification of the prototype by its maturity and purpose within the product development lifecycle. Breadboard and proof-of-concept are early-stage; alpha and beta represent iterative design validation; pre-production is the final form-fit-function build. Virtual prototypes are digital simulation models.. Valid values are `breadboard|proof_of_concept|alpha|beta|pre_production|virtual|functional_model`',
    CONSTRAINT pk_engineering_prototype PRIMARY KEY(`engineering_prototype_id`)
) COMMENT 'Master record for physical and virtual prototypes developed during the product design and validation lifecycle. Captures prototype number, prototype type (breadboard, alpha, beta, pre-production), associated component or assembly, build quantity, build date, design revision at build, test objectives, prototype status (planned, in-build, in-test, completed, scrapped), and linkage to FAI and validation test records. Supports APQP phase gate tracking.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`design_validation_test` (
    `design_validation_test_id` BIGINT COMMENT 'Unique system-generated identifier for each design validation or verification test record within the engineering domain.',
    `apqp_project_id` BIGINT COMMENT 'Foreign key linking to quality.apqp_project. Business justification: Design validation tests are APQP deliverables in Phase 3 (Product/Process Development). Engineering tracks DVT completion as required APQP milestones for product launch approval.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: design_validation_test.component_part_number is a STRING reference to the component being validated. Replacing with FK component_id → component.component_id establishes the authoritative test-to-compo',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: design_validation_test.ecn_number is a STRING reference to the ECN associated with this validation test. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design valida',
    `engineering_prototype_id` BIGINT COMMENT 'Foreign key linking to engineering.prototype. Business justification: design_validation_test.prototype_identifier is a STRING reference to the prototype being tested. Design validation tests are performed on prototypes. Replacing with FK prototype_id → prototype.prototy',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Design validation testing costs (lab time, materials, equipment) are collected against internal orders. Finance tracks testing expenses for R&D capitalization decisions and project cost control.',
    `safety_audit_id` BIGINT COMMENT 'Foreign key linking to hse.safety_audit. Business justification: Design validation tests for safety-critical components must reference HSE safety audits that identified testing requirements. Engineering uses audit findings to define validation test protocols for sa',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Validation tests must be conducted by qualified test engineers. Quality systems require documented test performer for traceability, certification verification, and regulatory compliance (ISO 9001, IAT',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Design validation requires calibrated test equipment. Engineering teams must reference asset management to verify equipment calibration status, capability, and availability before conducting validatio',
    `acceptance_criteria_max` DECIMAL(18,2) COMMENT 'Maximum acceptable value for the measured parameter as defined by the test standard or engineering specification. Used to determine pass/fail outcome.',
    `acceptance_criteria_min` DECIMAL(18,2) COMMENT 'Minimum acceptable value for the measured parameter as defined by the test standard or engineering specification. Used to determine pass/fail outcome.',
    `actual_end_date` DATE COMMENT 'Actual date on which the design validation test was completed, used for cycle time analysis and regulatory submission timelines.. Valid values are `^d{4}-d{2}-d{2}$`',
    `actual_start_date` DATE COMMENT 'Actual date on which the design validation test commenced, used for schedule variance analysis and PPAP documentation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering or quality authority who formally approved the test results and disposition, required for PPAP and regulatory submissions.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the test result was formally approved by the authorized engineering or quality authority, providing an audit trail for regulatory compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `ce_marking_applicable` BOOLEAN COMMENT 'Indicates whether this test is required to support CE Marking compliance for the product, per applicable EU directives (e.g., Low Voltage Directive, EMC Directive, Machinery Directive).. Valid values are `true|false`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the design validation test record was first created in the system, providing an audit trail for data governance and compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `deviation_description` STRING COMMENT 'Detailed description of any deviations, anomalies, or non-conformances observed during the test, including conditions that differed from the test plan or standard requirements.',
    `deviation_disposition` STRING COMMENT 'Formal disposition decision for any test deviation, determining whether a waiver is granted, a retest is required, or a design change must be initiated via ECN/ECO.. Valid values are `none|waiver_granted|retest_required|design_change_required|use_as_is|scrap`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the design validation test record was last updated, supporting change tracking and data lineage in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `measured_value` DECIMAL(18,2) COMMENT 'Primary measured or observed value recorded during the test (e.g., voltage, temperature, force, emissions level). Unit of measure is captured in measured_value_unit.',
    `measured_value_unit` STRING COMMENT 'Unit of measure for the primary measured value (e.g., V, A, °C, dBμV/m, N, Pa, Hz), aligned with SI units and test standard requirements.',
    `ncr_number` STRING COMMENT 'Reference number of the Non-Conformance Report (NCR) raised as a result of a test failure or deviation, linking the test record to the formal quality management corrective action process.',
    `planned_start_date` DATE COMMENT 'Scheduled start date for the design validation test, used for resource planning and APQP milestone tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `ppap_applicable` BOOLEAN COMMENT 'Indicates whether this test result is required as part of a Production Part Approval Process (PPAP) submission to a customer or internal quality gate.. Valid values are `true|false`',
    `regulatory_submission_flag` BOOLEAN COMMENT 'Indicates whether this test result is included in a regulatory submission package (e.g., CE Marking technical file, UL certification application, PPAP submission to customer).. Valid values are `true|false`',
    `result` STRING COMMENT 'Overall outcome of the design validation test. Conditional pass indicates the test passed with documented deviations or waivers. Inconclusive indicates insufficient data to determine pass or fail.. Valid values are `pass|fail|conditional_pass|inconclusive|waived`',
    `revision` STRING COMMENT 'Revision level of the test record, incremented when test parameters, scope, or results are formally amended via an Engineering Change Notice (ECN).. Valid values are `^[A-Z]{1,3}[0-9]{0,3}$`',
    `source_system` STRING COMMENT 'Operational system of record from which this design validation test record originated (e.g., Siemens Teamcenter PLM, Siemens Opcenter MES Quality, SAP QM), supporting data lineage in the lakehouse.. Valid values are `Teamcenter|Opcenter|SAP_QM|Manual|MindSphere|Other`',
    `status` STRING COMMENT 'Current lifecycle status of the design validation test record, from planning through completion or cancellation.. Valid values are `planned|in_progress|completed|cancelled|on_hold|pending_review`',
    `test_duration_days` STRING COMMENT 'Total number of calendar days the test ran from actual start to actual end date, used for test planning benchmarking and resource utilization analysis.. Valid values are `^[0-9]+$`',
    `test_engineer` STRING COMMENT 'Name or employee identifier of the lead engineer responsible for executing and documenting the design validation test.',
    `test_facility_accreditation` STRING COMMENT 'Accreditation number or certification identifier of the test facility (e.g., A2LA, NVLAP, ILAC accreditation number), required for regulatory submissions and CE Marking technical files.',
    `test_facility_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the test facility is located, supporting multi-national regulatory compliance tracking.. Valid values are `^[A-Z]{3}$`',
    `test_facility_name` STRING COMMENT 'Name of the laboratory or test facility where the test was conducted, which may be an internal facility or an accredited third-party laboratory (e.g., UL, TÜV, Intertek).',
    `test_number` STRING COMMENT 'Human-readable business identifier for the test record, used for cross-referencing in PPAP packages, CE Marking dossiers, and UL certification submissions.. Valid values are `^DVT-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `test_phase` STRING COMMENT 'Product development phase during which the test is conducted, aligned with the Advanced Product Quality Planning (APQP) gate structure.. Valid values are `concept|prototype|pre_production|pilot|production_validation|post_launch`',
    `test_report_document_ref` STRING COMMENT 'Document management system reference or URL to the full test report stored in Siemens Teamcenter PLM or the enterprise document management system.',
    `test_report_number` STRING COMMENT 'Reference number of the formal test report document issued by the test facility or internal engineering team, used for regulatory submissions and PPAP packages.',
    `test_standard` STRING COMMENT 'Industry or regulatory standard governing the test methodology and acceptance criteria (e.g., IEC 61000-4-2, UL 508A, EN 55032, ISO 11452, CE Marking Directive 2014/30/EU).',
    `test_standard_clause` STRING COMMENT 'Specific clause, section, or sub-requirement within the referenced test standard that this test validates, enabling precise traceability to regulatory requirements.',
    `test_type` STRING COMMENT 'Classification of the test type performed. DVT (Design Validation Test), DVP&R (Design Verification Plan and Report), EMC (Electromagnetic Compatibility), environmental stress, functional, safety, reliability, performance, dimensional, or material testing.. Valid values are `DVT|DVP&R|EMC|environmental_stress|functional|safety|reliability|performance|dimensional|material`',
    `title` STRING COMMENT 'Descriptive title of the design validation or verification test, summarizing the test objective and scope for engineering and quality teams.',
    `ul_certification_applicable` BOOLEAN COMMENT 'Indicates whether this test is required to support UL (Underwriters Laboratories) product safety certification for the North American market.. Valid values are `true|false`',
    CONSTRAINT pk_design_validation_test PRIMARY KEY(`design_validation_test_id`)
) COMMENT 'Record of a formal design validation or verification test performed on a prototype or pre-production unit. Captures test ID, test type (DVT, DVP&R, EMC, environmental stress, functional), test standard referenced (IEC, UL, CE), test facility, test date range, pass/fail result, measured values, acceptance criteria, deviations noted, and linkage to the prototype and component under test. Supports CE Marking, UL certification, and PPAP documentation.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`product_specification` (
    `product_specification_id` BIGINT COMMENT 'Unique surrogate identifier for the product specification record in the Databricks Silver Layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: product_specification.part_number is a STRING reference to the component this specification applies to. Replacing with FK component_id → component.component_id establishes the authoritative spec-to-co',
    `drawing_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_drawing. Business justification: product_specification.drawing_number is a STRING reference to the engineering drawing that this specification is associated with. Replacing with FK engineering_drawing_id → engineering_drawing.enginee',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: product_specification.ecn_number is a STRING reference to the ECN that authorized this specification revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for product',
    `applicable_standard` STRING COMMENT 'Primary industry or regulatory standard that governs this specification parameter (e.g., IEC 61131-2, EN 60204-1, ISO 9283, CE Marking Directive 2006/42/EC, RoHS Directive 2011/65/EU). Supports regulatory traceability and compliance reporting.',
    `approval_status` STRING COMMENT 'Formal approval workflow status of the specification record. Approved specifications are authorized for use in design, procurement, and manufacturing. Distinct from lifecycle status; captures the approval gate outcome.. Valid values are `pending|approved|rejected|conditionally_approved|withdrawn`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering authority who formally approved the specification. Required for regulatory traceability and design review records under ISO 9001 and PPAP.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the specification was formally approved by the designated engineering authority. Recorded in ISO 8601 format with timezone offset for global operations.',
    `ce_marking_relevant` BOOLEAN COMMENT 'Indicates whether this specification parameter contributes to CE Marking conformity assessment for the European market. CE-relevant parameters must be verified and documented in the Technical File.. Valid values are `true|false`',
    `country_of_applicability` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the primary country or market for which this specification applies. Relevant for region-specific regulatory requirements (e.g., CE for EU, UL for USA, CCC for China).. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the specification record was first created in the source system. Provides audit trail for specification lifecycle management and regulatory documentation.',
    `description` STRING COMMENT 'Detailed narrative description of the specification scope, purpose, and applicability. Provides context for design engineers, quality teams, and regulatory reviewers.',
    `effective_from_date` DATE COMMENT 'Date from which this specification revision becomes the authoritative design baseline for production, procurement, and quality inspection. Supports time-bounded specification validity management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'Date on which this specification revision expires or is superseded by a newer revision. Null indicates the specification is currently active with no planned expiry.. Valid values are `^d{4}-d{2}-d{2}$`',
    `is_critical_characteristic` BOOLEAN COMMENT 'Indicates whether this specification parameter is designated as a Critical Characteristic (CC) or Key Characteristic (KC) requiring enhanced control, SPC monitoring, and mandatory documentation in the Control Plan. Critical characteristics directly impact safety, regulatory compliance, or product function.. Valid values are `true|false`',
    `is_safety_relevant` BOOLEAN COMMENT 'Indicates whether this specification parameter has direct implications for product safety, operator safety, or end-user safety. Safety-relevant parameters require additional review, documentation, and regulatory approval under CE Marking, UL, and ISO 45001.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 language code of the specification document (e.g., en, de, zh-CN, fr). Supports multilingual documentation management for global engineering teams.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the specification record in the source system. Used for incremental data loading, change detection, and audit trail maintenance in the Silver Layer.',
    `maximum_value` DECIMAL(18,2) COMMENT 'Absolute maximum acceptable value for the parameter, representing the hard upper bound. Used in design verification, test planning, and quality inspection to define pass/fail criteria.',
    `minimum_value` DECIMAL(18,2) COMMENT 'Absolute minimum acceptable value for the parameter, representing the hard lower bound beyond which the product fails to meet specification. Distinct from tolerance_lower which is a deviation from nominal.',
    `nominal_value` STRING COMMENT 'The target or ideal value for the specification parameter (e.g., 24, 85, 500). Stored as STRING to accommodate numeric, alphanumeric, and enumerated nominal values across diverse parameter types.',
    `parameter_name` STRING COMMENT 'Name of the specific technical parameter being specified (e.g., Input Voltage, Operating Temperature, Tensile Strength, IP Protection Rating). Each specification record captures one parameter for traceability granularity.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or site for which this specification is applicable. Supports multi-plant, multinational operations where specifications may vary by production site.. Valid values are `^[A-Z0-9]{2,10}$`',
    `product_family` STRING COMMENT 'The product family or product line to which this specification applies (e.g., SIMATIC S7 Controllers, SINUMERIK CNC Systems, SIRIUS Motor Starters). Enables specification reuse and family-level compliance reporting.',
    `reach_relevant` BOOLEAN COMMENT 'Indicates whether this specification parameter is subject to REACH (Registration, Evaluation, Authorisation and Restriction of Chemicals) regulation, applicable to chemical composition and substance-of-very-high-concern (SVHC) thresholds.. Valid values are `true|false`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier (e.g., A, B, C, 01, 02) indicating the version of the specification. Incremented upon each approved engineering change. Aligns with PLM revision management in Siemens Teamcenter.. Valid values are `^[A-Z0-9]{1,5}$`',
    `rohs_relevant` BOOLEAN COMMENT 'Indicates whether this specification parameter is relevant to RoHS (Restriction of Hazardous Substances) compliance, particularly for material composition specifications governing restricted substances such as lead, mercury, cadmium, and hexavalent chromium.. Valid values are `true|false`',
    `secondary_standards` STRING COMMENT 'Additional standards, directives, or regulations applicable to this specification parameter beyond the primary standard (e.g., UL 508A, ANSI/NEMA ICS 1). Stored as a delimited list for multinational compliance coverage.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this specification record was ingested (e.g., Siemens Teamcenter PLM, SAP S/4HANA). Supports data lineage and reconciliation in the Databricks Lakehouse.. Valid values are `teamcenter|sap_s4hana|opcenter|manual|legacy`',
    `specification_category` STRING COMMENT 'Engineering discipline category of the specification parameter. Enables domain-specific filtering and routing to the appropriate engineering team for review and verification.. Valid values are `electrical|mechanical|thermal|chemical|optical|software|dimensional|structural|electromagnetic|acoustic`',
    `specification_number` STRING COMMENT 'Formal business identifier for the product specification document, typically assigned by the PLM/PDM system (Siemens Teamcenter). Used for cross-referencing in engineering change notices (ECN), design reviews, and regulatory submissions.. Valid values are `^[A-Z]{2,6}-SPEC-[0-9]{4,10}(-[A-Z0-9]+)?$`',
    `specification_type` STRING COMMENT 'Classification of the specification by its engineering purpose. Functional specs define what the product must do; interface specs define integration points; material specs define composition; environmental specs define operating conditions; safety and regulatory specs define compliance requirements.. Valid values are `functional|interface|material|environmental|performance|safety|regulatory|process|test`',
    `status` STRING COMMENT 'Current lifecycle status of the specification record. Controls whether the specification is active for design, manufacturing, and procurement use. Released specifications are the authoritative design baseline.. Valid values are `draft|in_review|approved|released|obsolete|superseded|on_hold`',
    `teamcenter_item_code` STRING COMMENT 'Native item identifier from Siemens Teamcenter PLM system, serving as the source system reference key for the specification document. Enables bidirectional traceability between the Silver Layer and the PLM system of record.',
    `title` STRING COMMENT 'Descriptive title of the product specification document, summarizing the product or component and the nature of the specification (e.g., Servo Drive Unit – Functional Performance Specification).',
    `tolerance_lower` DECIMAL(18,2) COMMENT 'Minimum allowable deviation below the nominal value for the specification parameter. Used in SPC and inspection to define the lower specification limit (LSL). Null if not applicable.',
    `tolerance_upper` DECIMAL(18,2) COMMENT 'Maximum allowable deviation above the nominal value for the specification parameter. Used in Statistical Process Control (SPC) and inspection to define the upper specification limit (USL). Null if not applicable (e.g., enumerated parameters).',
    `unit_of_measure` STRING COMMENT 'Engineering unit associated with the nominal value and tolerances (e.g., V for volts, °C for degrees Celsius, MPa for megapascals, mm for millimeters, kg for kilograms). Follows SI unit conventions.',
    `verification_method` STRING COMMENT 'Method by which compliance with this specification parameter is verified during design validation and production quality inspection (e.g., test, analysis, inspection, demonstration). Aligns with APQP and PPAP verification planning.. Valid values are `test|analysis|inspection|demonstration|simulation|review`',
    CONSTRAINT pk_product_specification PRIMARY KEY(`product_specification_id`)
) COMMENT 'Master record for formal product technical specifications defining the functional, performance, environmental, and regulatory requirements for a product or component. Captures specification number, revision, specification type (functional, interface, material, environmental), applicable standards (IEC 61131, CE, RoHS, REACH), parameter name, nominal value, tolerance, unit of measure, and approval status. SSOT for design requirements traceability.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`material_specification` (
    `material_specification_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a material specification record in the silver layer lakehouse. Serves as the primary key for all downstream joins and references.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: material_specification.ecn_reference_number is a STRING reference to the ECN that authorized this material specification revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management trac',
    `applicable_standard` STRING COMMENT 'The primary industry or international standard governing the material specification, such as ASTM A36, DIN EN 10025, EN 573-3, or ISO 6892. Defines the normative requirements that the material must meet.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering or quality authority who formally approved this material specification revision. Required for audit trail and regulatory compliance under ISO 9001 document control requirements.',
    `approved_supplier_list_ref` STRING COMMENT 'Reference identifier linking this material specification to the corresponding Approved Supplier List (ASL) record in SAP Ariba or SAP S/4HANA MM. Ensures procurement is restricted to qualified and audited suppliers for this material.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the material specification was formally approved by the authorized engineering or quality representative. Provides a precise audit trail for document control and regulatory compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `base_material` STRING COMMENT 'The primary elemental or compound material, such as Steel, Aluminum, Copper, Polypropylene, or Epoxy Resin. Provides the foundational material identity before alloy or grade qualification.',
    `chemical_composition_spec` STRING COMMENT 'Structured text or JSON-serialized representation of the required chemical composition limits (min/max percentages by weight) for key elements such as C, Mn, Si, Cr, Ni, Cu, Fe. Stored as a structured string for Silver layer compatibility.',
    `conflict_minerals_flag` BOOLEAN COMMENT 'Indicates whether the material contains conflict minerals (tin, tantalum, tungsten, gold — 3TG) sourced from conflict-affected and high-risk areas (CAHRAs). Triggers supply chain due diligence and reporting obligations under EU Conflict Minerals Regulation and SEC Rule 13p-1.. Valid values are `true|false`',
    `country_of_origin_restriction` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes from which sourcing of this material is restricted or prohibited, based on export control regulations, trade compliance, or supply chain risk policies.. Valid values are `^[A-Z]{3}(,[A-Z]{3})*$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the material specification record was first created in the source system. Used for audit trail, data lineage, and change history tracking in the Silver layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `density_kg_per_m3` DECIMAL(18,2) COMMENT 'Nominal density of the material expressed in kilograms per cubic meter (kg/m³). Used in weight calculations for BOM costing, shipping logistics, and structural analysis in CAD/CAM systems.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `description` STRING COMMENT 'Detailed narrative description of the material specification including intended application, key characteristics, and any special notes relevant to procurement or manufacturing use.',
    `effective_from_date` DATE COMMENT 'The date from which this revision of the material specification is valid and approved for use in procurement and manufacturing. Supports time-bounded specification management and change effectivity control.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'The date on which this revision of the material specification expires or is superseded. A null value indicates the specification is currently active with no defined expiry. Used to manage specification lifecycle and prevent use of obsolete standards.. Valid values are `^d{4}-d{2}-d{2}$`',
    `elongation_min_percent` DECIMAL(18,2) COMMENT 'Minimum required elongation at break expressed as a percentage, indicating the materials ductility. Used in mechanical property verification during incoming inspection and First Article Inspection (FAI).. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `en10204_certificate_type` STRING COMMENT 'Specifies the EN 10204 material test certificate type required for metallic materials: 2.1 (Declaration of Compliance), 2.2 (Test Report), 3.1 (Inspection Certificate by manufacturer), or 3.2 (Inspection Certificate by independent body). Critical for traceability in regulated industries.. Valid values are `2.1|2.2|3.1|3.2|not_applicable`',
    `grade_designation` STRING COMMENT 'Specific grade or alloy designation of the material as defined by the applicable standard, such as 6061-T6, Grade 304, S235JR, or A36. Uniquely identifies the material within its standard family.',
    `hardness_max` DECIMAL(18,2) COMMENT 'Maximum allowable hardness value for the material. Paired with hardness_min to define the acceptable hardness range for incoming inspection and supplier qualification.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `hardness_min` DECIMAL(18,2) COMMENT 'Minimum required hardness value for the material. The hardness scale (HRC, HRB, HV, HB) is specified in the hardness_scale attribute. Used in incoming inspection and quality assurance.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `hardness_scale` STRING COMMENT 'The hardness measurement scale used for the hardness_min and hardness_max values (e.g., Rockwell C, Vickers, Brinell). Ensures correct interpretation of hardness requirements during inspection.. Valid values are `HRC|HRB|HRA|HV|HB|Shore_A|Shore_D|other`',
    `hazardous_material_class` STRING COMMENT 'UN/GHS hazardous material classification code for the material if applicable (e.g., Class 3 Flammable Liquid, Class 8 Corrosive). Drives storage, handling, and transportation requirements under OSHA HazCom and EPA regulations.',
    `incoming_inspection_plan_ref` STRING COMMENT 'Reference to the quality inspection plan in SAP S/4HANA QM module that governs incoming material inspection for this specification. Defines sampling procedures, test methods, and acceptance criteria (AQL) applied at goods receipt.',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether the material complies with the EU REACH Regulation (EC) No 1907/2006 regarding Registration, Evaluation, Authorisation and Restriction of Chemicals. Flags whether the material contains Substances of Very High Concern (SVHC) above threshold.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether the material meets the EU Restriction of Hazardous Substances (RoHS) Directive 2011/65/EU requirements, restricting the use of lead, mercury, cadmium, hexavalent chromium, PBB, PBDE, and other substances. Mandatory for products sold in the EU market.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the material specification record in the source system. Supports incremental data loading, change detection, and audit trail requirements in the Databricks Silver layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `material_group` STRING COMMENT 'SAP material group code used to classify materials for procurement, reporting, and spend analytics. Aligns with the enterprise commodity taxonomy managed in SAP Ariba for sourcing and supplier management.',
    `material_type` STRING COMMENT 'High-level classification of the material by physical or chemical category. Drives storage conditions, handling requirements, and applicable regulatory compliance checks (e.g., RoHS for electronic components, REACH for chemicals).. Valid values are `ferrous_metal|non_ferrous_metal|polymer|composite|ceramic|elastomer|adhesive|lubricant|chemical|electronic_component|purchased_part|raw_material|other`',
    `name` STRING COMMENT 'Descriptive short name of the material specification, such as Low-Carbon Steel Sheet Grade A or Aluminum Alloy 6061-T6 Bar Stock. Used for display in procurement and engineering systems.',
    `operating_temp_max_c` DECIMAL(18,2) COMMENT 'Maximum operating temperature in degrees Celsius at which the material maintains its specified mechanical and physical properties. Used in thermal analysis and material selection for electrification and industrial automation components.. Valid values are `^-?[0-9]+(.[0-9]{1,2})?$`',
    `operating_temp_min_c` DECIMAL(18,2) COMMENT 'Minimum operating temperature in degrees Celsius at which the material maintains its specified mechanical and physical properties. Critical for material selection in automation systems deployed in cold environments.. Valid values are `^-?[0-9]+(.[0-9]{1,2})?$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or site for which this material specification is applicable. Supports multi-plant operations where material standards may vary by production location or regional regulatory requirements.',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the current version of the material specification. Incremented upon each approved Engineering Change Notice (ECN) or Engineering Change Order (ECO) affecting the specification.. Valid values are `^[A-Z0-9]{1,5}$`',
    `sds_reference_number` STRING COMMENT 'Reference number or document identifier for the Safety Data Sheet (SDS) associated with this material, as required by OSHA HazCom Standard (29 CFR 1910.1200) and EU REACH Regulation. Links to the document management system for retrieval.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this material specification record was sourced or originated. Supports data lineage tracking and reconciliation in the Databricks Silver layer lakehouse.. Valid values are `SAP_S4HANA|TEAMCENTER|OPCENTER|MANUAL|other`',
    `specification_number` STRING COMMENT 'Business-facing unique identifier for the material specification, typically assigned by the engineering or quality organization. Used for cross-referencing in procurement, incoming inspection, and supplier qualification documents.. Valid values are `^MS-[A-Z0-9]{3,10}-[0-9]{4,8}$`',
    `standard_body` STRING COMMENT 'The standards development organization (SDO) that published the applicable standard for this material specification. Used to filter and group specifications by regional or international standards alignment.. Valid values are `ASTM|DIN|EN|ISO|ANSI|JIS|BS|GB|NIST|IEC|UL|other`',
    `status` STRING COMMENT 'Lifecycle status of the material specification indicating whether it is actively approved for use in procurement and manufacturing, under engineering review, superseded by a newer revision, or withdrawn from use.. Valid values are `draft|under_review|approved|superseded|obsolete|withdrawn`',
    `surface_roughness_max_um` DECIMAL(18,2) COMMENT 'Maximum allowable surface roughness expressed in micrometers (µm Ra) as required by the material specification. Relevant for sealing surfaces, bearing interfaces, and precision-machined components.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `surface_treatment` STRING COMMENT 'Required surface treatment or coating specification for the material, such as zinc plating, anodizing, passivation, powder coating, or hot-dip galvanizing. Defines the surface condition required for corrosion protection or functional performance.',
    `svhc_flag` BOOLEAN COMMENT 'Indicates whether the material contains one or more Substances of Very High Concern (SVHC) as listed on the ECHA Candidate List under REACH. Triggers mandatory disclosure obligations when concentration exceeds 0.1% w/w.. Valid values are `true|false`',
    `teamcenter_document_code` STRING COMMENT 'Unique document identifier in Siemens Teamcenter PLM system for the master specification document (drawing, datasheet, or specification PDF). Enables direct retrieval of the authoritative specification document from the PLM/PDM system.',
    `temper_condition` STRING COMMENT 'Heat treatment, temper, or condition designation of the material (e.g., T6, T651, H32, annealed, normalized, quenched and tempered). Defines the mechanical property state resulting from processing.',
    `tensile_strength_min_mpa` DECIMAL(18,2) COMMENT 'Minimum required ultimate tensile strength of the material expressed in megapascals (MPa), as specified by the applicable standard. Used in incoming inspection and supplier qualification to verify mechanical property compliance.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `test_certificate_requirement` STRING COMMENT 'Specifies the type of material test certificate or documentation required from the supplier at delivery. Options include mill certificates (EN 10204 3.1/3.2), certificates of conformance, third-party test reports, or First Article Inspection (FAI) reports.. Valid values are `none|mill_certificate|certificate_of_conformance|third_party_test_report|first_article_inspection|all`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which the material is procured and inventoried (e.g., KG for kilogram, M for meter, PC for piece, SHT for sheet). Aligns with SAP S/4HANA MM unit of measure configuration.. Valid values are `KG|G|T|M|MM|M2|M3|L|PC|ROL|SHT|BAR|other`',
    `yield_strength_min_mpa` DECIMAL(18,2) COMMENT 'Minimum required yield strength (0.2% proof stress) of the material expressed in megapascals (MPa). Critical for structural and load-bearing component qualification in automation and electrification systems.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    CONSTRAINT pk_material_specification PRIMARY KEY(`material_specification_id`)
) COMMENT 'Master record defining approved material standards and chemical composition requirements for raw materials and purchased components used in manufacturing. Captures material specification number, material type, applicable standard (ASTM, DIN, EN), chemical composition limits, mechanical property requirements, surface treatment, RoHS/REACH compliance status, and approved supplier list reference. Feeds procurement qualification and incoming inspection.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`approved_manufacturer` (
    `approved_manufacturer_id` BIGINT COMMENT 'Unique surrogate identifier for each Approved Manufacturer List (AML) / Approved Vendor List (AVL) entry in the Databricks Silver layer.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Approved Manufacturer List (AML) entries require documented approval by authorized procurement or quality engineers. Supplier quality management systems track who approved each manufacturer for audit ',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: approved_manufacturer.component_number is a STRING reference to the component on the Approved Manufacturer List (AML). Replacing with FK component_id → component.component_id establishes the authorita',
    `procurement_supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: Approved manufacturer references supplier - normalize by replacing supplier_number text with FK to procurement.supplier',
    `third_party_risk_id` BIGINT COMMENT 'Foreign key linking to compliance.third_party_risk. Business justification: Approved manufacturers undergo third-party risk assessments for compliance, financial stability, and supply chain security. Engineering references compliance-managed risk profiles during supplier sele',
    `aml_type` STRING COMMENT 'Classification of the manufacturers role in the supply strategy for this component. Preferred indicates primary source; alternate is secondary; restricted requires engineering approval for use.. Valid values are `preferred|alternate|restricted|single_source|dual_source`',
    `approval_date` DATE COMMENT 'Date on which the manufacturer was formally approved for the component following successful qualification testing and review.',
    `approval_expiry_date` DATE COMMENT 'Date on which the manufacturer approval expires and re-qualification is required. Supports periodic supplier re-evaluation per quality management requirements.',
    `approval_status` STRING COMMENT 'Current qualification status of the manufacturer for the specified component. Drives procurement eligibility and supply chain decisions.. Valid values are `approved|conditionally_approved|under_qualification|suspended|obsolete|rejected`',
    `approved_by` STRING COMMENT 'Name or employee ID of the engineering or quality authority who formally approved this manufacturer-component combination on the AML/AVL.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the formal approval was recorded in the system, providing an audit trail for quality management compliance.',
    `ce_marking_confirmed` BOOLEAN COMMENT 'Indicates whether the manufacturer has confirmed CE marking compliance for the part, required for sale in the European Economic Area.. Valid values are `true|false`',
    `country_of_manufacture` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country where the component is manufactured. Used for trade compliance, tariff classification, and supply chain risk assessment.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the approved manufacturer record was first created in the system. Provides full audit trail for quality management and data governance.',
    `export_control_classification` STRING COMMENT 'Export Control Classification Number (ECCN) or equivalent classification for the manufacturers part under applicable export control regulations (EAR/ITAR).',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether the manufacturers part complies with EU REACH regulation regarding chemical substance registration and restriction.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether the manufacturers part meets EU RoHS Directive requirements restricting hazardous substances in electrical and electronic equipment.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the approved manufacturer record. Supports change tracking, audit compliance, and data lineage in the Silver layer.',
    `last_requalification_date` DATE COMMENT 'Date of the most recent periodic requalification assessment performed for this manufacturer-component combination. Supports ongoing supplier monitoring per ISO 9001.',
    `lead_time_days` STRING COMMENT 'Standard procurement lead time in calendar days from purchase order placement to delivery for this manufacturers part. Used in MRP/MRP II planning calculations.',
    `manufacturer_code` STRING COMMENT 'Unique short code or identifier assigned to the manufacturer within the enterprise system (e.g., SAP vendor/manufacturer code). Enables cross-system linkage.',
    `manufacturer_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the manufacturers registered business location. Used for geopolitical risk assessment and trade compliance screening.. Valid values are `^[A-Z]{3}$`',
    `manufacturer_datasheet_reference` STRING COMMENT 'Document reference number or URL pointing to the manufacturers official datasheet or technical specification for the approved part.',
    `manufacturer_duns_number` STRING COMMENT 'Dun & Bradstreet Data Universal Numbering System (D-U-N-S) nine-digit identifier for the manufacturer. Used for global supplier identity verification and risk assessment.. Valid values are `^[0-9]{9}$`',
    `manufacturer_name` STRING COMMENT 'Legal or trade name of the manufacturer approved to supply the component. Used for procurement qualification and supply chain risk management.',
    `manufacturer_part_description` STRING COMMENT 'Manufacturers description of the part as stated in their datasheet or catalog. Supports incoming inspection and procurement verification.',
    `manufacturer_part_number` STRING COMMENT 'The manufacturers own part number for the component. Critical for procurement, incoming inspection, and cross-referencing with supplier documentation.',
    `minimum_order_quantity` DECIMAL(18,2) COMMENT 'Minimum quantity that must be ordered from this manufacturer per purchase order. Impacts procurement planning and inventory management.',
    `notes` STRING COMMENT 'Free-text field for additional engineering or procurement notes regarding this manufacturer approval, such as special handling instructions, known limitations, or pending actions.',
    `ppap_level` STRING COMMENT 'PPAP submission level required or achieved for this manufacturer-component combination, indicating the depth of documentation provided during qualification.. Valid values are `1|2|3|4|5|not_required`',
    `ppap_status` STRING COMMENT 'Current status of the PPAP submission for this manufacturer-component combination. Determines whether full production release is authorized.. Valid values are `approved|interim_approval|rejected|not_submitted|in_review`',
    `ppm_defect_rate` DECIMAL(18,2) COMMENT 'Measured defect rate in Parts Per Million (PPM) for incoming parts from this manufacturer. Key quality KPI for supplier performance monitoring and AQL compliance.',
    `price_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the unit price of the manufacturers part (e.g., USD, EUR, GBP). Supports multi-currency global procurement.. Valid values are `^[A-Z]{3}$`',
    `qualification_test_reference` STRING COMMENT 'Reference number or identifier of the qualification test report, First Article Inspection (FAI) record, or PPAP package that substantiates the manufacturer approval.',
    `quality_rating` DECIMAL(18,2) COMMENT 'Numeric quality performance score (0–100) assigned to this manufacturer for the component based on incoming inspection results, PPM defect rates, and audit outcomes.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `requalification_frequency_months` STRING COMMENT 'Interval in months at which this manufacturer-component approval must be periodically requalified and reviewed. Drives quality management scheduling.',
    `restricted_to_plant_code` STRING COMMENT 'SAP plant code indicating that use of this approved manufacturer is restricted to a specific manufacturing plant. Null if approved globally across all plants.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this AML/AVL entry was sourced (e.g., SAP S/4HANA MM, SAP Ariba, Siemens Teamcenter PLM).. Valid values are `SAP_S4HANA|SAP_ARIBA|TEAMCENTER|MANUAL|OTHER`',
    `ul_certification_number` STRING COMMENT 'UL certification file number issued by Underwriters Laboratories for the manufacturers part, confirming product safety compliance for North American markets.',
    `unit_price` DECIMAL(18,2) COMMENT 'Negotiated or catalog unit price for the manufacturers part. Used for cost estimation, BOM costing, and procurement benchmarking.',
    `use_restriction` STRING COMMENT 'Free-text description of any restrictions on the use of this manufacturers part, such as limited to specific plants, product lines, or applications. Null if no restrictions apply.',
    CONSTRAINT pk_approved_manufacturer PRIMARY KEY(`approved_manufacturer_id`)
) COMMENT 'Association record defining the Approved Manufacturer List (AML) and Approved Vendor List (AVL) entries for each component, specifying which manufacturers and their specific part numbers are approved for use in production. Captures component reference, manufacturer name, manufacturer part number, approval status, approval date, qualification test reference, and any use restrictions. Critical for procurement qualification and supply chain risk management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`design_review` (
    `design_review_id` BIGINT COMMENT 'Unique system-generated identifier for the design review record in the engineering data product.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: design_review.product_number is a STRING reference to the component/product being reviewed. Replacing with FK component_id → component.component_id establishes the authoritative review-to-component tr',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Key customers participate in design reviews for custom products, co-development projects, or validation of specifications. Manufacturing tracks customer involvement in design approval processes for co',
    `dfmea_id` BIGINT COMMENT 'Foreign key linking to engineering.dfmea. Business justification: design_review.dfmea_reference_number is a STRING reference to the DFMEA reviewed during this design review event. Replacing with FK dfmea_id → dfmea.dfmea_id establishes the DFMEA-to-review traceabili',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: design_review.ecn_number is a STRING reference to the ECN associated with this design review. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design review events. ec',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Design reviews require a designated lead engineer to chair the review, approve findings, and sign off on design decisions. Engineering management tracks who led each review for accountability and comp',
    `project_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_project. Business justification: design_review.project_number is a STRING reference to the engineering project this review is part of. Design reviews are phase gate events within engineering projects. Replacing with FK engineering_pr',
    `action_item_closure_due_date` DATE COMMENT 'Target date by which all open action items from this design review must be resolved and closed, enabling conditional pass tracking and escalation management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `action_items_closed_count` STRING COMMENT 'Number of action items from this design review that have been formally closed and verified, used to assess review closure progress and gate readiness.. Valid values are `^[0-9]+$`',
    `action_items_count` STRING COMMENT 'Total number of action items raised during the design review, including both open and closed items, used to track review thoroughness and follow-up compliance.. Valid values are `^[0-9]+$`',
    `agenda_summary` STRING COMMENT 'Summary of the agenda items covered during the design review, including design topics, test results, compliance checks, and risk assessments presented to the review board.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering authority or review board chairperson who formally approved the design review disposition and authorized progression to the next phase gate.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the design review disposition was formally approved and recorded in the PLM system, providing an auditable timestamp for phase gate governance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `apqp_phase` STRING COMMENT 'The APQP phase gate to which this design review is aligned, enabling traceability of design maturity against the structured APQP product development lifecycle.. Valid values are `Phase 1 - Plan and Define|Phase 2 - Product Design and Development|Phase 3 - Process Design and Development|Phase 4 - Product and Process Validation|Phase 5 - Launch Feedback and Corrective Action`',
    `ce_marking_applicable` BOOLEAN COMMENT 'Indicates whether CE Marking requirements are applicable to the product under review, triggering mandatory compliance verification steps within the design review process.. Valid values are `true|false`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the design review record was initially created in the source PLM system, used for audit trail and data lineage tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `dfa_assessment_result` STRING COMMENT 'Outcome of the Design for Assembly assessment conducted as part of the design review, evaluating whether the design supports efficient and error-free assembly operations.. Valid values are `Pass|Conditional Pass|Fail|Not Applicable|Not Assessed`',
    `dfm_assessment_result` STRING COMMENT 'Outcome of the Design for Manufacturability assessment conducted as part of the design review, indicating whether the design can be efficiently manufactured at target cost and quality.. Valid values are `Pass|Conditional Pass|Fail|Not Applicable|Not Assessed`',
    `disposition` STRING COMMENT 'Formal outcome decision of the design review, determining whether the design is approved to proceed to the next phase gate. A Conditional Pass requires resolution of open action items before progression.. Valid values are `Pass|Conditional Pass|Fail|Deferred`',
    `export_control_classification` STRING COMMENT 'Export control classification code (e.g., ECCN or EAR99) applicable to the product design under review, required for multinational compliance with export regulations for automation and electrification systems.',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether the design reviewed has been assessed and confirmed as compliant with REACH (Registration, Evaluation, Authorisation and Restriction of Chemicals) regulation requirements.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether the design reviewed has been assessed and confirmed as compliant with RoHS (Restriction of Hazardous Substances) directive requirements at the time of this review.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the design review record in the source PLM system, supporting change tracking and Silver layer incremental load processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `minutes_document_reference` STRING COMMENT 'Reference to the formal meeting minutes document capturing decisions, action items, and attendee sign-off for the design review, stored in the PLM document management system.',
    `open_issues_count` STRING COMMENT 'Number of unresolved design issues or concerns identified during the review that remain open at the time of disposition, driving conditional pass or fail outcomes.. Valid values are `^[0-9]+$`',
    `participant_count` STRING COMMENT 'Total number of participants who attended the design review, used for quorum validation and review completeness assessment per the design review procedure.. Valid values are `^[0-9]+$`',
    `participant_list` STRING COMMENT 'Comma-separated list or reference identifier of all participants (names, roles, or employee IDs) who attended the design review, supporting audit trail and quorum verification.',
    `planned_review_date` DATE COMMENT 'Originally planned date for the design review as established in the project schedule, used to measure schedule adherence and gate compliance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or engineering site responsible for the product under review, enabling regional and site-level governance reporting.. Valid values are `^[A-Z0-9]{2,10}$`',
    `regulatory_compliance_scope` STRING COMMENT 'Comma-separated list of applicable regulatory frameworks and certifications assessed during the design review (e.g., CE Marking, RoHS, REACH, UL, IEC 62443), ensuring design compliance obligations are formally reviewed at each gate.',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the lead design engineer accountable for the product design being reviewed and for resolving action items raised during the review.',
    `review_chair` STRING COMMENT 'Name or employee identifier of the individual who chaired and facilitated the design review meeting, accountable for ensuring the review process was conducted per procedure.',
    `review_date` DATE COMMENT 'Scheduled or actual calendar date on which the design review meeting was conducted.. Valid values are `^d{4}-d{2}-d{2}$`',
    `review_document_reference` STRING COMMENT 'Document management system reference or URL pointing to the formal design review package (presentation, minutes, checklists) stored in Teamcenter PLM or the enterprise document management system.',
    `review_location` STRING COMMENT 'Physical site, facility, or virtual meeting platform where the design review was conducted (e.g., plant code, conference room, or video conferencing platform name).',
    `review_number` STRING COMMENT 'Human-readable business identifier for the design review, used for cross-referencing in PLM, APQP documentation, and engineering change workflows.. Valid values are `^DR-[A-Z0-9]{4,20}$`',
    `review_type` STRING COMMENT 'Classification of the design review event corresponding to the PLM phase gate. PDR assesses early design concepts, CDR evaluates detailed design maturity, MRR confirms manufacturing readiness, and PRR validates production readiness prior to launch.. Valid values are `Preliminary Design Review|Critical Design Review|Manufacturing Readiness Review|Production Readiness Review|System Requirements Review|Test Readiness Review`',
    `revision` STRING COMMENT 'Revision level of the design review record, incremented when the review is re-opened or updated following a conditional pass or re-review cycle.. Valid values are `^[A-Z0-9]{1,5}$`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this design review record originated, enabling data lineage traceability in the Databricks Silver layer.. Valid values are `Teamcenter|SAP|Manual|Other`',
    `status` STRING COMMENT 'Current lifecycle status of the design review event, tracking progression from planning through completion or cancellation.. Valid values are `Planned|Scheduled|In Progress|Completed|Cancelled|On Hold`',
    `title` STRING COMMENT 'Descriptive title of the design review event, typically including the product name, assembly, and review type (e.g., Servo Drive Module CDR Rev B).',
    CONSTRAINT pk_design_review PRIMARY KEY(`design_review_id`)
) COMMENT 'Record of a formal design review event conducted at a PLM phase gate (PDR, CDR, MRR, PRR) to assess design maturity and readiness to proceed. Captures review ID, review type (Preliminary Design Review, Critical Design Review, Manufacturing Readiness Review), review date, participants, agenda items, action items raised, open issues, disposition (pass, conditional pass, fail), and linked product or assembly. Supports APQP phase gate governance.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`design_review_action` (
    `design_review_action_id` BIGINT COMMENT 'Unique system-generated identifier for each individual action item raised during a design review. Serves as the primary key for the design_review_action entity.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the engineering manager, quality engineer, or design review chairperson who formally approved the closure of the action item after verifying the resolution evidence.',
    `design_review_id` BIGINT COMMENT 'Foreign key linking to engineering.design_review. Business justification: design_review_action is a child record of design_review — each action item is raised during a specific design review event. Without this FK, design_review_action is disconnected from its parent review',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: design_review_action.ecn_number is a STRING reference to the ECN associated with this action item. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design review actio',
    `owner_employee_id` BIGINT COMMENT 'Employee identifier of the engineer or technical specialist assigned as the primary responsible party for resolving the action item. Drives workload reporting and escalation routing.',
    `raised_by_employee_id` BIGINT COMMENT 'Employee identifier of the individual who identified and formally raised the action item during the design review. Supports audit trail and accountability tracking.',
    `action_number` STRING COMMENT 'Human-readable business identifier for the action item, used for cross-referencing in engineering documents, APQP records, and PPAP submissions. Typically formatted as DRA-YYYY-NNNNN.. Valid values are `^DRA-[0-9]{4}-[0-9]{5}$`',
    `action_type` STRING COMMENT 'Classification of the action item by its nature. Distinguishes between corrective actions (CAPA), preventive actions, design changes, and verification/validation requirements to support APQP phase tracking.. Valid values are `corrective_action|preventive_action|improvement|clarification|risk_mitigation|design_change|verification_required|validation_required`',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time at which the action item closure was formally approved by the authorized reviewer. Provides a precise audit trail timestamp for PPAP and ISO 9001 compliance evidence.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `apqp_phase` STRING COMMENT 'The APQP phase during which this action item was raised or must be resolved. Enables phase-gate compliance tracking and ensures all open actions are addressed before advancing to the next APQP phase.. Valid values are `phase_1_plan_and_define|phase_2_product_design|phase_3_process_design|phase_4_product_validation|phase_5_launch_feedback`',
    `category` STRING COMMENT 'Engineering discipline category of the action item, enabling filtering and reporting by functional area such as DFM (Design for Manufacturability), DFA (Design for Assembly), DFMEA, safety, or regulatory compliance.. Valid values are `design_intent|tolerance_stack|material_selection|dfm|dfa|dfmea|regulatory_compliance|safety|cost_reduction|manufacturability|testability|reliability|documentation`',
    `closed_date` DATE COMMENT 'Calendar date on which the action item was formally verified, accepted, and closed by the design review chairperson or quality engineer. Used for cycle time analysis and PPAP audit evidence.. Valid values are `^d{4}-d{2}-d{2}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the engineering site or plant where the design review action was raised. Supports multi-country regulatory compliance tracking and regional reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the design review action item record was first created in the data platform. Supports data lineage, audit trail, and SLA compliance reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Detailed narrative describing the engineering concern, non-conformance, or improvement opportunity identified during the design review. Provides full context for the action owner.',
    `due_date` DATE COMMENT 'Target completion date by which the action owner must resolve and close the action item. Drives escalation workflows and APQP phase-gate readiness assessments.. Valid values are `^d{4}-d{2}-d{2}$`',
    `escalation_date` DATE COMMENT 'Date on which the action item was formally escalated to engineering management or program leadership. Populated only when escalation_flag is true.. Valid values are `^d{4}-d{2}-d{2}$`',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether the action item has been formally escalated due to overdue status, safety criticality, or blocking impact on APQP phase-gate progression. Triggers management notification workflows.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent update to the design review action item record. Used for incremental data loading, change detection, and audit trail maintenance in the Databricks lakehouse silver layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `owner_department` STRING COMMENT 'Organizational department of the action item owner (e.g., Mechanical Engineering, Electrical Engineering, Quality Assurance). Enables departmental workload and accountability reporting.',
    `owner_name` STRING COMMENT 'Full name of the engineer or technical specialist responsible for resolving the action item. Retained for display and reporting purposes independent of HR system lookups.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility responsible for producing the product under design review. Enables plant-level reporting of open design actions and their impact on production readiness.',
    `ppap_relevant` BOOLEAN COMMENT 'Indicates whether this action item must be resolved and evidenced as part of the PPAP submission package. When true, the action closure is a prerequisite for PPAP level approval.. Valid values are `true|false`',
    `priority` STRING COMMENT 'Business priority level assigned to the action item, indicating urgency and impact on the design review outcome. Critical items must be resolved before design release; high items before PPAP submission.. Valid values are `critical|high|medium|low`',
    `product_line` STRING COMMENT 'The product line or product family to which the design under review belongs (e.g., Automation Systems, Electrification Solutions, Smart Infrastructure). Enables cross-product-line trend analysis of design review findings.',
    `raised_date` DATE COMMENT 'Calendar date on which the action item was formally identified and recorded during the design review session. Used for aging analysis and SLA compliance tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `regulatory_compliance_flag` BOOLEAN COMMENT 'Indicates whether the action item is linked to a regulatory compliance requirement such as CE Marking, RoHS, REACH, UL certification, or IEC standard conformance. Compliance-flagged actions require regulatory engineer sign-off.. Valid values are `true|false`',
    `resolution_notes` STRING COMMENT 'Detailed narrative describing the corrective or preventive actions taken to resolve the engineering issue. Captures the technical solution, design changes made, and verification evidence. Required for PPAP submission packages.',
    `revised_due_date` DATE COMMENT 'Updated target completion date when the original due date is extended due to technical complexity, resource constraints, or scope changes. Requires documented justification for audit trail purposes.. Valid values are `^d{4}-d{2}-d{2}$`',
    `risk_level` STRING COMMENT 'Assessed risk level of the unresolved action item on product quality, safety, schedule, or regulatory compliance. Derived from DFMEA risk assessment methodology and used to prioritize resolution sequencing.. Valid values are `critical|high|medium|low|negligible`',
    `safety_critical` BOOLEAN COMMENT 'Indicates whether the action item relates to a safety-critical design characteristic or function. Safety-critical actions require mandatory escalation, expedited resolution, and documented sign-off by the Chief Engineer.. Valid values are `true|false`',
    `severity_rating` STRING COMMENT 'Numeric severity rating (1-10 scale) aligned with DFMEA methodology, indicating the potential impact of the failure mode associated with this action item on the end customer or product function. 10 = most severe.. Valid values are `^([1-9]|10)$`',
    `source` STRING COMMENT 'Origin of the action item, indicating which engineering activity or process generated the issue. Supports traceability back to DFMEA, PFMEA, FAI (First Article Inspection), or prototype testing activities.. Valid values are `design_review|dfmea|pfmea|fai|prototype_test|customer_feedback|regulatory_audit|internal_audit|supplier_feedback|simulation_analysis`',
    `status` STRING COMMENT 'Current lifecycle status of the design review action item, tracking progress from initial identification through resolution and formal closure. Drives APQP gate readiness assessments.. Valid values are `open|in_progress|pending_review|resolved|closed|cancelled|on_hold`',
    `teamcenter_action_code` STRING COMMENT 'Native identifier of the action item record in Siemens Teamcenter PLM, the system of record for design review management and change control. Enables bidirectional traceability between the lakehouse silver layer and the PLM source system.',
    `title` STRING COMMENT 'Short, descriptive title summarizing the engineering issue or action item raised during the design review. Used for quick identification in dashboards and reports.',
    `verification_evidence_reference` STRING COMMENT 'Document reference number or link to the evidence package (test report, updated drawing, simulation result, inspection record) that demonstrates the action item has been effectively resolved.',
    `verification_method` STRING COMMENT 'Method used to verify that the resolution of the action item is effective and the engineering concern has been adequately addressed. Supports design verification evidence requirements for PPAP and regulatory submissions.. Valid values are `analysis|simulation|test|inspection|review|prototype_build|drawing_update|calculation|none_required`',
    CONSTRAINT pk_design_review_action PRIMARY KEY(`design_review_action_id`)
) COMMENT 'Individual action item raised during a design review, capturing the action description, owner, due date, priority, resolution notes, and closure status. Enables tracking of open engineering issues through to resolution and provides an audit trail for APQP and PPAP compliance. Linked to the parent design review record.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`plm_lifecycle_state` (
    `plm_lifecycle_state_id` BIGINT COMMENT 'Unique surrogate identifier for each authorized lifecycle state record within the Teamcenter PLM governance framework.',
    `allowed_transitions` STRING COMMENT 'Pipe-delimited list of target state codes to which a PLM object may transition from this state (e.g., IN_REVIEW|RELEASED|OBSOLETE). Defines the authorized state machine edges for workflow enforcement.',
    `applicable_object_types` STRING COMMENT 'Pipe-delimited list of PLM-managed object types to which this lifecycle state applies (e.g., Component|BOM|Drawing|CAD_Model|Document). Governs which object classes can be assigned this state.',
    `apqp_phase_alignment` STRING COMMENT 'Maps this lifecycle state to the corresponding APQP phase, enabling traceability between PLM object maturity and the formal product quality planning process used for new product introduction.. Valid values are `phase_1_plan_define|phase_2_product_design|phase_3_process_design|phase_4_product_process_validation|phase_5_launch|not_applicable`',
    `color_code_hex` STRING COMMENT 'Hexadecimal color code used to visually represent this lifecycle state in PLM dashboards, engineering portals, and reporting tools. Supports intuitive visual differentiation of product data maturity stages.. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lifecycle state configuration record was first created in the data product. Provides audit trail for governance and compliance purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `downstream_system_trigger` STRING COMMENT 'Identifies downstream operational systems that are triggered upon a PLM object entering this lifecycle state (e.g., SAP_MM_Material_Master|SAP_PP_BOM|Opcenter_MES). Supports IT/OT convergence and PLM-ERP integration governance.',
    `ecn_required_for_entry` BOOLEAN COMMENT 'Indicates whether a valid Engineering Change Notice (ECN) or Engineering Change Order (ECO) must be referenced before a PLM object can be transitioned into this lifecycle state. Enforces formal change control governance.. Valid values are `true|false`',
    `ecn_required_for_exit` BOOLEAN COMMENT 'Indicates whether a valid Engineering Change Notice (ECN) or Engineering Change Order (ECO) must be referenced to transition a PLM object out of this lifecycle state. Typically applies to released or frozen states.. Valid values are `true|false`',
    `effective_from_date` DATE COMMENT 'Date from which this lifecycle state configuration is valid and available for use in PLM workflows. Supports versioned governance of lifecycle state definitions over time.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'Date after which this lifecycle state configuration is no longer valid for new PLM object assignments. Null indicates the state is currently active with no planned expiry.. Valid values are `^d{4}-d{2}-d{2}$`',
    `export_control_check_required` BOOLEAN COMMENT 'Indicates whether an export control classification review (e.g., EAR, ITAR, dual-use goods assessment) must be completed before a PLM object can be transitioned into this lifecycle state.. Valid values are `true|false`',
    `icon_reference` STRING COMMENT 'Reference identifier or file path for the icon image associated with this lifecycle state in the PLM user interface. Used for visual representation in Teamcenter and integrated engineering portals.',
    `is_frozen_state` BOOLEAN COMMENT 'Indicates whether PLM objects in this state are frozen (read-only) and cannot be directly modified. Changes must be initiated via an Engineering Change Notice (ECN) or Engineering Change Order (ECO) process.. Valid values are `true|false`',
    `is_initial_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state is the default starting state assigned to newly created PLM objects. Only one state per applicable object type should be flagged as the initial state.. Valid values are `true|false`',
    `is_released_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state constitutes a formal release milestone, meaning the PLM object is authorized for use in production, procurement, or downstream processes such as BOM activation or MES execution.. Valid values are `true|false`',
    `is_terminal_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state is a terminal (end) state from which no further forward transitions are permitted (e.g., Obsolete, Archived). Terminal states represent the end of the active product data lifecycle.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 language code for the locale in which the state_name and state_description are expressed (e.g., en, de, zh-CN). Supports multinational PLM deployments with multi-language state label requirements.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this lifecycle state configuration record. Used for change tracking, data lineage, and incremental data pipeline processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `maturity_level` STRING COMMENT 'Standardized maturity level classification associated with this lifecycle state, indicating the degree of completeness and validation of the product data. Used for portfolio-level maturity reporting and APQP phase alignment.. Valid values are `concept|preliminary|detailed|validated|production_ready|obsolete`',
    `max_dwell_days` STRING COMMENT 'Maximum number of calendar days a PLM object is permitted to remain in this lifecycle state before an escalation or alert is triggered. Supports governance of stale or stuck product data records.. Valid values are `^[0-9]+$`',
    `minimum_approver_count` STRING COMMENT 'Minimum number of distinct approvers required to authorize a transition into this lifecycle state. Supports multi-signatory approval requirements for safety-critical or regulatory-relevant product data.. Valid values are `^[0-9]+$`',
    `notification_recipient_roles` STRING COMMENT 'Pipe-delimited list of organizational roles that receive automated notifications upon a PLM object entering this lifecycle state (e.g., Procurement|Manufacturing_Engineering|Quality_Assurance).',
    `notification_required` BOOLEAN COMMENT 'Indicates whether automated notifications must be sent to stakeholders (e.g., engineering team, quality, procurement) when a PLM object transitions into this lifecycle state.. Valid values are `true|false`',
    `plm_workflow_template_name` STRING COMMENT 'Name of the Teamcenter PLM workflow template associated with transitions into this lifecycle state. Identifies the formal approval and review workflow process definition used to govern state entry.',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process (PPAP) submission is required as a prerequisite for transitioning a PLM object into this lifecycle state. Relevant for states representing production readiness.. Valid values are `true|false`',
    `quality_gate_required` BOOLEAN COMMENT 'Indicates whether a formal quality gate review (e.g., APQP phase gate, design review, DFMEA completion check) must be passed before a PLM object can enter this lifecycle state.. Valid values are `true|false`',
    `regulatory_review_required` BOOLEAN COMMENT 'Indicates whether regulatory compliance review (e.g., CE Marking, RoHS/REACH, UL certification, export control classification) must be completed before a PLM object can enter this lifecycle state.. Valid values are `true|false`',
    `required_approval_roles` STRING COMMENT 'Pipe-delimited list of organizational roles or job functions that must provide approval before a PLM object can enter this lifecycle state (e.g., Design_Engineer|Quality_Manager|Chief_Engineer). Enforces the approval governance matrix.',
    `sequence_order` STRING COMMENT 'Numeric ordering value that defines the canonical progression sequence of lifecycle states from concept through obsolescence. Used for sorting and maturity progression reporting.. Valid values are `^[0-9]+$`',
    `sla_transition_days` STRING COMMENT 'Target number of business days within which a PLM object should complete the review and approval process to transition out of this lifecycle state. Used for engineering workflow performance monitoring against SLA targets.. Valid values are `^[0-9]+$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this lifecycle state configuration was sourced (e.g., Teamcenter). Supports data lineage tracking in the Databricks Silver Layer lakehouse.. Valid values are `Teamcenter|SAP_S4HANA|Manual|Other`',
    `state_category` STRING COMMENT 'High-level category grouping lifecycle states for reporting and analytics. Enables aggregation of states into broader maturity phases (e.g., all review-type states grouped under review).. Valid values are `concept|development|review|approved|released|production|obsolete|archived`',
    `state_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the lifecycle state within the PLM system (e.g., CONCEPT, IN_REVIEW, RELEASED, OBSOLETE). Used as the business key for state lookups and workflow routing.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `state_description` STRING COMMENT 'Detailed narrative description of the lifecycle state, including its business meaning, entry criteria, and the maturity level it represents within the product data governance framework.',
    `state_name` STRING COMMENT 'Human-readable name of the lifecycle state as displayed in the Teamcenter PLM user interface and engineering reports (e.g., Concept, Under Review, Released for Production, Obsolete).',
    `status` STRING COMMENT 'Operational status of this lifecycle state configuration record. Active states are available for assignment to PLM objects; Inactive states are suspended; Deprecated states are retained for historical reference only.. Valid values are `active|inactive|deprecated`',
    `teamcenter_policy_name` STRING COMMENT 'Name of the Teamcenter PLM lifecycle policy (policy object) under which this state is defined. A lifecycle policy groups related states and transition rules for a specific object type family.',
    `teamcenter_state_uid` STRING COMMENT 'Native Siemens Teamcenter PLM system unique identifier (UID) for this lifecycle state object. Used for cross-system traceability and integration with Teamcenter APIs and downstream PLM-ERP interfaces.',
    CONSTRAINT pk_plm_lifecycle_state PRIMARY KEY(`plm_lifecycle_state_id`)
) COMMENT 'Reference record defining the authorized lifecycle states and state transition rules for PLM-managed objects (components, BOMs, drawings, CAD models) within the Teamcenter PLM workflow. Captures state code, state name, allowed transitions, required approvals, and applicable object types. Provides the governance framework for product data maturity progression from concept through obsolescence.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`project` (
    `project_id` BIGINT COMMENT 'Unique surrogate identifier for the engineering project record in the lakehouse silver layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: engineering_project.target_part_number is a STRING reference to the component/part being developed by this engineering project. Replacing with FK component_id → component.component_id establishes the ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Engineering projects consume resources from specific cost centers. Finance tracks project expenses against cost center budgets for financial control and project accounting.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Engineering projects are funded through internal orders for capital projects and R&D initiatives. Finance collects all project costs (labor, materials, equipment) against the internal order for budget',
    `it_project_id` BIGINT COMMENT 'Foreign key linking to technology.it_project. Business justification: Engineering projects often require IT infrastructure (PLM deployment, CAD upgrades, digital twin platforms). PMO tracks the IT project that enables the engineering deliverables for budget and resource',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Engineering projects require a designated project manager for accountability, resource allocation, and stakeholder communication. PMO tracks project ownership and performance metrics by manager.',
    `rd_project_id` BIGINT COMMENT 'Foreign key linking to research.rd_project. Business justification: Engineering projects originate from R&D projects that reach technology readiness for commercialization. Engineering tracks source R&D project for traceability of design decisions, test data, and IP de',
    `actual_completion_date` DATE COMMENT 'The date on which all engineering project deliverables were completed and the project was formally closed. Used for on-time delivery KPI measurement and lessons-learned analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `actual_cost` DECIMAL(18,2) COMMENT 'Total actual costs incurred on the engineering project to date, as collected in SAP PS cost objects. Compared against approved_budget to track cost performance and variance.',
    `actual_start_date` DATE COMMENT 'The date on which engineering project activities formally commenced. Compared against planned_start_date to measure schedule adherence and project initiation performance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approved_budget` DECIMAL(18,2) COMMENT 'The total approved budget allocated to the engineering project, covering engineering labor, tooling, prototype materials, testing, and external services. Sourced from SAP PS budget management.',
    `apqp_phase` STRING COMMENT 'The current APQP (Advanced Product Quality Planning) phase of the engineering project per the AIAG APQP standard. Tracks quality planning milestones from planning and definition through product and process design, validation, and production launch feedback.. Valid values are `phase_1_plan_define|phase_2_product_design|phase_3_process_design|phase_4_product_validation|phase_5_launch_feedback`',
    `capex_opex_classification` STRING COMMENT 'Financial classification of the engineering project spend as CAPEX (Capital Expenditure) for assets that will be capitalized, OPEX (Operational Expenditure) for period costs, or mixed for projects with both components. Drives accounting treatment under IFRS IAS 38 and GAAP ASC 730.. Valid values are `CAPEX|OPEX|mixed`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary country where the engineering project is being executed. Supports multi-national portfolio reporting and regulatory compliance scoping.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the engineering project record was first created in the source system (SAP PS or Teamcenter PLM). Used for audit trail, data lineage, and SLA compliance tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the project budget and cost figures (e.g., USD, EUR, CNY). Supports multi-currency reporting for multinational engineering portfolios.. Valid values are `^[A-Z]{3}$`',
    `customer_reference` STRING COMMENT 'Customer-provided project or RFQ (Request for Quotation) reference number for ETO (Engineer to Order) projects. Enables traceability from customer order through engineering design to production.',
    `description` STRING COMMENT 'Detailed narrative describing the scope, objectives, and deliverables of the engineering project. Supports search and reporting in PLM and ERP systems.',
    `dfmea_number` STRING COMMENT 'Reference number of the DFMEA (Design Failure Mode and Effects Analysis) document associated with this engineering project. Links to the engineering.dfmea product for risk tracking.',
    `estimated_development_cost` DECIMAL(18,2) COMMENT 'Initial estimate of total development cost prepared at project initiation, used for business case approval and CAPEX/OPEX classification. Compared against approved_budget and actual_cost for variance analysis.',
    `export_control_classification` STRING COMMENT 'Export Control Classification Number (ECCN) or equivalent classification for the product being developed. Required for compliance with US EAR (Export Administration Regulations) and EU dual-use regulations for automation and electrification products.',
    `gate_review_date` DATE COMMENT 'Scheduled date for the next phase-gate review meeting where project status, deliverables, and readiness to advance to the next APQP phase are formally assessed by the engineering review board.. Valid values are `^d{4}-d{2}-d{2}$`',
    `gate_review_outcome` STRING COMMENT 'Outcome of the most recently completed phase-gate review. approved_with_conditions indicates conditional advancement with open action items. Used for project governance and portfolio health reporting.. Valid values are `approved|approved_with_conditions|deferred|rejected|pending`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the engineering project record in the source system. Used for incremental data loading, change detection, and audit trail maintenance in the lakehouse.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead_engineer` STRING COMMENT 'Name or employee identifier of the chief engineer or technical lead responsible for the engineering design and technical deliverables of the project.',
    `name` STRING COMMENT 'Descriptive name of the engineering project, typically reflecting the product or platform being developed (e.g., Gen-4 Motor Drive Platform NPI, ETO Switchgear Assembly Rev B).',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the engineering project, sourced from SAP PS (Project System). Used for cross-system referencing across SAP S/4HANA, Teamcenter PLM, and Opcenter MES.. Valid values are `^[A-Z]{2,4}-[0-9]{4,8}(-[A-Z0-9]+)?$`',
    `owning_department` STRING COMMENT 'Name of the engineering department or business unit that owns and is accountable for the project (e.g., Drives Engineering, Electrification R&D, Automation Systems). Maps to SAP PS responsible cost center.',
    `phase` STRING COMMENT 'Current development phase of the engineering project aligned to the APQP (Advanced Product Quality Planning) gate model. Tracks progression from concept ideation through design, prototype build, design validation, product launch, and handover to production.. Valid values are `concept|design|prototype|validation|launch|production_transfer|closed`',
    `planned_start_date` DATE COMMENT 'The scheduled start date for the engineering project as defined in the project plan. Used for resource planning, milestone scheduling, and portfolio timeline reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the primary manufacturing facility where the product being developed will be produced. Used for BOM and routing assignments in SAP S/4HANA.. Valid values are `^[A-Z0-9]{4}$`',
    `ppap_level` STRING COMMENT 'The PPAP (Production Part Approval Process) submission level required (1 through 5), defining the extent of documentation and samples to be submitted to the customer for approval. Level 3 is the default full submission.. Valid values are `1|2|3|4|5`',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a PPAP (Production Part Approval Process) submission is required for this engineering project prior to production launch. Mandatory for automotive and regulated industrial customers.. Valid values are `true|false`',
    `priority` STRING COMMENT 'Business priority level assigned to the engineering project, used for resource allocation decisions and portfolio management reporting in SAP PS.. Valid values are `critical|high|medium|low`',
    `product_line` STRING COMMENT 'The product line or product family that the engineering project is developing or enhancing (e.g., Industrial Drives, Smart Switchgear, Building Automation Controllers). Supports portfolio-level reporting.',
    `program_manager` STRING COMMENT 'Name or employee identifier of the program manager accountable for overall delivery of the engineering project. Sourced from SAP PS responsible person field.',
    `regulatory_compliance_scope` STRING COMMENT 'Comma-separated list of regulatory standards and certifications that the product being developed must comply with (e.g., CE,RoHS,REACH,UL,IEC 62443). Drives compliance testing and documentation requirements.',
    `sap_ps_project_code` STRING COMMENT 'The SAP PS internal project definition identifier (PROJ-PSPNR) used for cost collection, scheduling, and resource management in SAP S/4HANA Project System module.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this engineering project record was sourced (SAP PS for project management data, Teamcenter for PLM-originated projects, or MANUAL for records entered directly into the lakehouse).. Valid values are `SAP_PS|TEAMCENTER|MANUAL`',
    `status` STRING COMMENT 'Current lifecycle status of the engineering project. Drives workflow routing in SAP PS and Teamcenter PLM. on_hold indicates a temporary suspension; closed indicates administrative closure after completion.. Valid values are `draft|active|on_hold|cancelled|completed|closed`',
    `target_launch_date` DATE COMMENT 'The committed date by which the product must be launched to market or transferred to production. A key milestone for NPI and ETO projects, used in customer commitments and sales pipeline planning.. Valid values are `^d{4}-d{2}-d{2}$`',
    `target_market` STRING COMMENT 'The intended market segment or industry vertical for the product being developed (e.g., Automotive, Building Automation, Oil and Gas, Transportation). Informs regulatory requirements and customer-specific design standards.',
    `target_unit_cost` DECIMAL(18,2) COMMENT 'The target unit manufacturing cost (COGS component) for the product being developed, established at project initiation as part of the business case. Used to drive DFM/DFA optimization and cost reduction engineering decisions.',
    `teamcenter_project_code` STRING COMMENT 'Unique identifier of the corresponding project record in Siemens Teamcenter PLM. Enables bi-directional traceability between SAP PS project management and PLM design data.',
    `type` STRING COMMENT 'Classification of the engineering project by its strategic intent. NPI (New Product Introduction) covers entirely new products; ETO (Engineer to Order) covers customer-specific designs; platform_development covers shared architecture programs; cost_reduction covers value engineering initiatives; sustaining_engineering covers ongoing product support.. Valid values are `NPI|ETO|ATO|platform_development|cost_reduction|sustaining_engineering|regulatory_compliance|product_variant`',
    CONSTRAINT pk_project PRIMARY KEY(`project_id`)
) COMMENT 'Master record for engineering development projects managing the design and development of new products, product variants, or major engineering changes. Captures project number, project name, project type (NPI, ETO, platform development, cost reduction), program manager, target launch date, current phase (concept, design, prototype, validation, launch), budget, and linkage to the product being developed. Supports SAP PS project management integration.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`engineering_change_request` (
    `engineering_change_request_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each Engineering Change Request record in the lakehouse silver layer.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Customer accounts frequently request engineering changes for custom requirements, product modifications, or issue resolution. Engineering teams track which customer initiated each change request for p',
    `affected_bom_flag` BOOLEAN COMMENT 'Indicates whether the engineering change request is expected to result in modifications to one or more Bills of Materials. Triggers BOM impact assessment in Teamcenter and SAP S/4HANA.. Valid values are `true|false`',
    `affected_drawing_flag` BOOLEAN COMMENT 'Indicates whether the engineering change request is expected to require revisions to one or more engineering drawings or CAD models.. Valid values are `true|false`',
    `affected_part_description` STRING COMMENT 'Human-readable description of the affected part, component, or assembly to provide context without requiring a lookup to the component master.',
    `affected_part_number` STRING COMMENT 'Part number or material number of the primary product, component, or assembly affected by the requested engineering change. Sourced from SAP S/4HANA MM or Teamcenter PDM.',
    `affected_part_revision` STRING COMMENT 'Current revision level of the affected part or assembly at the time the change request is submitted. Establishes the baseline from which the change will be made.. Valid values are `^[A-Z]{1,3}[0-9]{0,2}$`',
    `business_justification` STRING COMMENT 'Formal business case or justification for the engineering change, including cost-benefit rationale, risk mitigation value, regulatory obligation, or customer commitment.',
    `cost_impact_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated cost impact amount (e.g., USD, EUR, GBP). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or organizational unit where the change request originates. Supports regional regulatory compliance scoping and multi-country reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the Engineering Change Request record was first created in the source system or ingested into the lakehouse. Used for audit trail and data lineage.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether the customer must be formally notified of the engineering change prior to or upon implementation. Driven by contractual SLA obligations or regulatory requirements.. Valid values are `true|false`',
    `disposition` STRING COMMENT 'Final or current disposition decision made by the engineering review board for the change request. Accepted requests initiate an ECN; merged requests are consolidated into an existing ECN.. Valid values are `accepted|rejected|deferred|merged|cancelled`',
    `disposition_date` DATE COMMENT 'Date on which the disposition decision (accepted, rejected, deferred, merged) was formally recorded. Used for cycle time and review board performance analytics.. Valid values are `^d{4}-d{2}-d{2}$`',
    `disposition_rationale` STRING COMMENT 'Narrative explanation provided by the engineering review board justifying the disposition decision. Required for rejected or deferred requests to communicate feedback to the requestor.',
    `estimated_cost_impact` DECIMAL(18,2) COMMENT 'Estimated financial impact (positive or negative) of implementing the engineering change, expressed in the designated currency. Used for business case evaluation and CAPEX/OPEX planning.',
    `initiated_ecn_number` STRING COMMENT 'ECN number of the Engineering Change Notice initiated as a result of this accepted change request. Provides traceability from request to formal change execution in Teamcenter.. Valid values are `^ECN-[0-9]{4}-[0-9]{6}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the Engineering Change Request record in the source system or lakehouse. Supports incremental data loading and change data capture.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `merged_into_ecn_number` STRING COMMENT 'ECN number of an existing Engineering Change Notice into which this request was merged when the disposition is merged. Prevents duplicate change execution for related requests.. Valid values are `^ECN-[0-9]{4}-[0-9]{6}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility primarily affected by or responsible for implementing the engineering change. Supports multi-plant impact scoping.',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process submission is required as part of implementing this engineering change. Applicable for automotive and high-reliability manufacturing contexts.. Valid values are `true|false`',
    `priority_score` STRING COMMENT 'Numeric priority score (1–100) assigned during triage to rank the change request relative to others in the queue. Higher scores indicate greater business impact or urgency.. Valid values are `^([1-9]|[1-9][0-9]|100)$`',
    `problem_description` STRING COMMENT 'Detailed narrative describing the problem, deficiency, or opportunity that is driving the engineering change request. Forms the basis for impact assessment and solution design.',
    `product_line` STRING COMMENT 'Product line or product family to which the affected component or assembly belongs (e.g., automation systems, electrification solutions, smart infrastructure). Used for portfolio-level change impact reporting.',
    `proposed_solution` STRING COMMENT 'Description of the proposed engineering change or corrective action intended to resolve the identified problem. Reviewed during the ECR disposition process.',
    `reason_code` STRING COMMENT 'Standardized reason code categorizing the root cause or business driver behind the change request. Used for trend analysis, CAPA linkage, and regulatory reporting.. Valid values are `quality_defect|cost_reduction|regulatory_compliance|customer_requirement|safety_improvement|obsolescence|design_improvement|supplier_change|warranty_issue|field_failure|process_improvement|standardization`',
    `regulatory_impact` BOOLEAN COMMENT 'Indicates whether the requested change affects regulatory compliance status, including CE marking, RoHS/REACH compliance, UL certification, or other applicable certifications.. Valid values are `true|false`',
    `request_date` DATE COMMENT 'Calendar date on which the Engineering Change Request was formally submitted. Used for aging analysis, SLA compliance tracking, and cycle time measurement.. Valid values are `^d{4}-d{2}-d{2}$`',
    `request_number` STRING COMMENT 'Business-facing unique identifier for the Engineering Change Request, formatted as ECR-YYYY-NNNNNN. Used for cross-system referencing and stakeholder communication.. Valid values are `^ECR-[0-9]{4}-[0-9]{6}$`',
    `request_type` STRING COMMENT 'Classification of the type of engineering change being requested. Determines the review workflow, required approvals, and downstream impact assessment scope.. Valid values are `design_change|process_change|material_change|software_change|documentation_change|regulatory_change|cost_reduction|safety_improvement|customer_driven|supplier_driven`',
    `requestor_department` STRING COMMENT 'Organizational department or functional area from which the change request originated. Used to analyze change request volume and patterns by originating function.. Valid values are `engineering|quality|production|procurement|service|sales|customer|supplier|regulatory|r_and_d|other`',
    `requestor_name` STRING COMMENT 'Full name of the individual who submitted the Engineering Change Request. May be an internal employee (engineering, quality, production, service) or an external stakeholder (customer, supplier).',
    `requestor_type` STRING COMMENT 'Classification of the requestor as internal (employee) or external (customer, supplier, regulatory body, field service). Determines the review and communication workflow.. Valid values are `internal|customer|supplier|regulatory_body|field_service`',
    `required_implementation_date` DATE COMMENT 'Target date by which the requestor requires the engineering change to be implemented. Drives urgency classification and scheduling of the downstream ECN/ECO workflow.. Valid values are `^d{4}-d{2}-d{2}$`',
    `safety_impact` BOOLEAN COMMENT 'Indicates whether the requested engineering change has a potential impact on product safety, operator safety, or end-user safety. Triggers mandatory safety review and may require regulatory notification.. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Operational system of record from which the Engineering Change Request originated or was ingested into the lakehouse. Supports data lineage and reconciliation.. Valid values are `teamcenter|sap_s4hana|salesforce|manual|opcenter|other`',
    `source_system_key` STRING COMMENT 'Native primary key or identifier of the Engineering Change Request record in the originating source system (e.g., Teamcenter Change Request ID). Enables reverse traceability to the system of record.',
    `status` STRING COMMENT 'Current lifecycle status of the Engineering Change Request, tracking its progression from initial submission through disposition. Drives workflow routing in Teamcenter Change Management.. Valid values are `draft|submitted|under_review|accepted|rejected|deferred|merged|cancelled|closed`',
    `title` STRING COMMENT 'Short, descriptive title summarizing the nature of the requested engineering change. Used in dashboards, reports, and workflow notifications.',
    `urgency` STRING COMMENT 'Urgency classification indicating the business priority and required response timeline for the change request. Critical urgency may indicate safety, regulatory, or production-stoppage scenarios.. Valid values are `critical|high|medium|low`',
    CONSTRAINT pk_engineering_change_request PRIMARY KEY(`engineering_change_request_id`)
) COMMENT 'Record of an informal or formal request submitted by any stakeholder (customer, production, quality, service) to initiate an engineering change. Captures request number, requestor, request date, affected product or component, problem description, proposed solution, business justification, urgency classification, and disposition (accepted, rejected, deferred, merged into ECN). Feeds the ECN initiation workflow in Teamcenter Change Management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`product_variant` (
    `product_variant_id` BIGINT COMMENT 'Unique surrogate identifier for each product variant record in the silver layer lakehouse. Serves as the primary key for all downstream joins and references.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: product_variant.base_product_number is a STRING reference to the base component/product this variant is derived from. Replacing with FK component_id → component.component_id establishes the authoritat',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.bom. Business justification: product_variant.variant_bom_number is a STRING reference to the BOM that defines this product variants structure. Replacing with FK bom_id → bom.bom_id establishes the authoritative variant-to-BOM tr',
    `sales_opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Custom product variants in manufacturing are created for specific sales opportunities requiring unique configurations. Engineering links variants to opportunities for traceability and cost allocation.',
    `ce_marking_status` STRING COMMENT 'Current status of CE marking certification for this product variant, confirming conformity with applicable EU directives (e.g., Low Voltage Directive, Machinery Directive, EMC Directive). Required for sale in the European Economic Area.. Valid values are `certified|pending|not_applicable|expired`',
    `communication_protocol` STRING COMMENT 'Industrial communication protocol supported by this product variant for integration with PLCs, SCADA systems, and IIoT platforms. Determines compatibility with factory automation architectures.. Valid values are `PROFINET|EtherNet/IP|Modbus TCP|CANopen|PROFIBUS|EtherCAT|OPC-UA|IO-Link|none`',
    `configuration_code` STRING COMMENT 'Encoded string representing the full combination of selected configuration options (e.g., voltage, power, protocol, enclosure) that define this variant. Used in SAP variant configuration (VC) and order management for ATO/ETO fulfillment.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the primary country of manufacture for this product variant. Used for customs declarations, trade compliance, and country-of-origin labeling requirements.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this product variant record was first created in the source system (SAP S/4HANA or Siemens Teamcenter PLM). Used for audit trail and data lineage tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Detailed technical and commercial description of the product variant, including key differentiating characteristics such as configuration options, intended application, and performance highlights.',
    `enclosure_class` STRING COMMENT 'Ingress protection (IP) or NEMA enclosure classification of the product variant, indicating resistance to dust, water, and environmental hazards. Critical for application suitability and regulatory compliance.. Valid values are `IP20|IP44|IP54|IP65|IP66|IP67|IP68|NEMA1|NEMA4|NEMA4X|NEMA12`',
    `export_control_classification` STRING COMMENT 'Export Control Classification Number (ECCN) or equivalent classification assigned to this product variant under US Export Administration Regulations (EAR) or EU dual-use regulations. Controls export licensing requirements.',
    `fulfillment_model` STRING COMMENT 'Manufacturing and fulfillment strategy applicable to this variant: Make to Stock (MTS), Make to Order (MTO), Assemble to Order (ATO), or Engineer to Order (ETO). Drives production planning, lead time commitments, and ATP/CTP logic in SAP S/4HANA.. Valid values are `MTS|MTO|ATO|ETO`',
    `harmonized_tariff_code` STRING COMMENT 'Harmonized System (HS) tariff code assigned to this product variant for customs classification in international trade. Used for import/export declarations, duty calculation, and trade compliance reporting.. Valid values are `^d{6,10}$`',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether this product variant complies with EU REACH Regulation (EC) No 1907/2006 regarding chemical substance registration and restriction. Required for EU market access and supply chain transparency.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether this product variant complies with the EU RoHS Directive (2011/65/EU) restricting the use of hazardous substances in electrical and electronic equipment. Mandatory for EU market access.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 language code for the language in which the variant name and description are maintained (e.g., en, de, zh-CN). Supports multi-language product catalog management for global operations.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this product variant record in the source system. Used for change detection, incremental data loading, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `list_price` DECIMAL(18,2) COMMENT 'Published list price per unit for this product variant as maintained in SAP S/4HANA SD pricing conditions. Serves as the baseline for customer quotations, pricing agreements, and revenue reporting.. Valid values are `^d{1,14}(.d{1,4})?$`',
    `list_price_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the list price is expressed. Supports global pricing management across multiple sales regions.. Valid values are `^[A-Z]{3}$`',
    `market_applicability` STRING COMMENT 'Comma-separated list of target markets or regions where this product variant is approved for sale and use (e.g., EU, North America, Asia-Pacific). Drives regional catalog availability and regulatory compliance checks.',
    `name` STRING COMMENT 'Short commercial name of the product variant used in catalogs, sales orders, and customer-facing materials. Describes the variant in human-readable form.',
    `plant_code` STRING COMMENT 'SAP S/4HANA plant code identifying the primary manufacturing plant responsible for producing this product variant. Drives production planning, MRP, and inventory management at the plant level.. Valid values are `^[A-Z0-9]{4}$`',
    `power_rating_kw` DECIMAL(18,2) COMMENT 'Nominal power rating of the product variant expressed in kilowatts (kW). Core technical specification used for product selection, energy compliance reporting, and ISO 50001 energy management.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `product_category` STRING COMMENT 'Engineering and commercial classification of the product variant within the product hierarchy (e.g., frequency inverter, circuit breaker, PLC module, electrification panel). Aligns with SAP material group.',
    `product_line` STRING COMMENT 'Commercial product line or product family to which this variant belongs (e.g., automation drives, low-voltage switchgear, smart building controllers). Used for portfolio management and sales reporting.',
    `release_date` DATE COMMENT 'Date on which this product variant was formally released from engineering into production and commercial availability, following completion of APQP/PPAP processes and ECO approval.. Valid values are `^d{4}-d{2}-d{2}$`',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the lead engineer responsible for the design and lifecycle management of this product variant in Siemens Teamcenter PLM. Used for accountability and change management workflows.',
    `revision_level` STRING COMMENT 'Current engineering revision level of the product variant as maintained in Siemens Teamcenter PLM. Incremented upon approved Engineering Change Orders (ECOs). Critical for BOM and drawing traceability.. Valid values are `^[A-Z0-9.]{1,10}$`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this product variant record originates (e.g., SAP_S4HANA, TEAMCENTER_PLM). Supports data lineage, reconciliation, and master data governance.. Valid values are `SAP_S4HANA|TEAMCENTER_PLM|OPCENTER_MES|MANUAL`',
    `standard_cost` DECIMAL(18,2) COMMENT 'Standard manufacturing cost per unit for this product variant as calculated in SAP S/4HANA CO (Controlling) module. Used for inventory valuation, COGS reporting, and profitability analysis. Expressed in the standard cost currency.. Valid values are `^d{1,14}(.d{1,4})?$`',
    `standard_cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the standard cost is expressed (e.g., USD, EUR, CNY). Supports multi-currency operations across global manufacturing sites.. Valid values are `^[A-Z]{3}$`',
    `status` STRING COMMENT 'Current lifecycle status of the product variant as managed in PLM and ERP. Controls whether the variant can be ordered, produced, or procured. Aligns with SAP material status and Teamcenter lifecycle state.. Valid values are `in_development|released|phase_out|obsolete|blocked|under_review`',
    `target_industry_segment` STRING COMMENT 'Primary industry segment for which this product variant is designed and marketed (e.g., factory automation, building automation, transportation). Supports portfolio segmentation and go-to-market strategy.. Valid values are `factory_automation|building_automation|transportation|energy|process_industry|discrete_manufacturing|infrastructure|marine|other`',
    `ul_certification_number` STRING COMMENT 'UL certification file number assigned to this product variant by Underwriters Laboratories, confirming compliance with North American safety standards. Required for sale in the US and Canadian markets.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for this product variant as defined in SAP S/4HANA MM (e.g., EA for each, PC for piece, SET for set). Used in all inventory, procurement, and order management transactions.. Valid values are `EA|PC|SET|KIT|M|KG|L`',
    `valid_from_date` DATE COMMENT 'Date from which this product variant is commercially valid and available for ordering, production, and sale. Used for effectivity management in SAP S/4HANA and Teamcenter PLM.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'Date until which this product variant remains commercially valid. After this date, the variant is no longer available for new orders. Supports phase-out planning and end-of-life management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `variant_code` STRING COMMENT 'Business-facing alphanumeric code uniquely identifying the product variant within the product catalog. Used in order management, BOM references, and customer-facing documentation. Sourced from SAP S/4HANA MM module material number for configurable variants.. Valid values are `^[A-Z0-9-]{3,40}$`',
    `variant_number` STRING COMMENT 'Internal engineering variant number as maintained in Siemens Teamcenter PLM, used to cross-reference the variant across PLM and ERP systems. May differ from the commercial variant code.. Valid values are `^[A-Z0-9-.]{3,50}$`',
    `variant_type` STRING COMMENT 'Classification of the variant by its engineering origin: standard (catalog item), custom (customer-specific modification), engineered (Engineer to Order), configurable (Assemble to Order with option selection), or phantom (planning-only variant).. Valid values are `standard|custom|engineered|configurable|phantom`',
    `voltage_rating` STRING COMMENT 'Nominal voltage rating of the product variant (e.g., 24V DC, 400V AC, 690V AC). Key configuration option differentiating variants within the same base product for automation and electrification solutions.',
    `weight_kg` DECIMAL(18,2) COMMENT 'Gross weight of the product variant in kilograms, including packaging. Used for logistics planning, freight cost calculation, and shipping documentation.. Valid values are `^d{1,7}(.d{1,3})?$`',
    CONSTRAINT pk_product_variant PRIMARY KEY(`product_variant_id`)
) COMMENT 'Master record defining configurable product variants and option combinations for automation systems and electrification solutions offered in multiple configurations. Captures variant code, variant description, base product reference, configuration options (voltage, power rating, communication protocol, enclosure class), variant-specific BOM reference, and market applicability. Supports ATO (Assemble to Order) and ETO (Engineer to Order) fulfillment models.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`substitute_component` (
    `substitute_component_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the substitute component association record in the Databricks Silver Layer.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: substitute_component.ecn_number is a STRING reference to the ECN that authorized this substitution. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for approved substitut',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.bom. Business justification: substitute_component.applicable_bom_number is a STRING reference to the BOM where this substitution is applicable. Replacing with FK bom_id → bom.bom_id establishes the authoritative substitution-to-B',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: substitute_component.primary_component_number is a STRING reference to the primary component being substituted. Replacing with FK primary_component_id → component.component_id establishes the authorit',
    `approved_by` STRING COMMENT 'Name or employee identifier of the authorized engineer or manager who approved this substitute component association for use in production.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the substitute component association was formally approved, providing an audit trail for quality management and regulatory compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `bom_usage` STRING COMMENT 'Specifies the BOM usage context in which this substitution is applicable, aligning with SAP BOM usage categories (e.g., production BOM, engineering BOM, costing BOM).. Valid values are `production|engineering|costing|plant_maintenance|universal`',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the standard cost delta value, supporting multi-currency operations across global manufacturing sites.. Valid values are `^[A-Z]{3}$`',
    `cost_impact_indicator` STRING COMMENT 'Indicates the directional cost impact of using the substitute component compared to the primary component, supporting cost management and COGS analysis without storing calculated values.. Valid values are `cost_increase|cost_decrease|cost_neutral|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this substitute component association record was first created in the system, providing a full audit trail for data governance and compliance purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `export_control_flag` BOOLEAN COMMENT 'Indicates whether the substitute component is subject to export control regulations (e.g., EAR, ITAR), which may restrict its use in certain geographies or customer applications and require additional compliance review.. Valid values are `true|false`',
    `form_fit_function_flag` BOOLEAN COMMENT 'Indicates whether the substitute component is a true form, fit, and function equivalent to the primary component, meaning it can be used without any design or process modification. Critical for engineering change and quality management decisions.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this substitute component association record was most recently updated, supporting change tracking, delta processing, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead_time_delta_days` STRING COMMENT 'The difference in procurement or manufacturing lead time in days between the substitute component and the primary component (substitute lead time minus primary lead time). Negative values indicate faster availability. Used in MRP scheduling and supply chain resilience planning.',
    `mrp_relevance_flag` BOOLEAN COMMENT 'Indicates whether this substitute component record is active and visible to the MRP engine for automatic exception handling and alternate material selection during planning runs.. Valid values are `true|false`',
    `originating_department` STRING COMMENT 'The business department that originated the substitute component request, used for workflow routing, accountability tracking, and cross-functional reporting.. Valid values are `engineering|procurement|supply_chain|quality|production_planning|manufacturing`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or site where this substitute component association is valid. Substitutions may be plant-specific due to local supplier availability or process constraints.. Valid values are `^[A-Z0-9]{4}$`',
    `priority_rank` STRING COMMENT 'Numeric rank indicating the preference order when multiple substitutes exist for the same primary component. Lower values indicate higher preference (1 = most preferred). Used by MRP to sequence substitute selection.. Valid values are `^[1-9][0-9]*$`',
    `quantity_conversion_factor` DECIMAL(18,2) COMMENT 'Multiplier applied to the original BOM quantity when using the substitute component. A value of 1.0 means the substitute is used in the same quantity; values other than 1.0 indicate a quantity adjustment is required (e.g., 2.0 means twice as many substitutes are needed).',
    `record_number` STRING COMMENT 'Business-facing unique identifier for the substitute component association record, used for cross-system referencing and audit trails.. Valid values are `^SUB-[A-Z0-9]{3,20}$`',
    `regulatory_compliance_impact` STRING COMMENT 'Indicates whether using this substitute component triggers a regulatory compliance review, such as RoHS, REACH, CE Marking, or UL certification re-assessment. Ensures regulatory obligations are not inadvertently violated during substitution.. Valid values are `no_impact|rohs_review_required|reach_review_required|ce_marking_review_required|ul_review_required|multiple_reviews_required`',
    `requested_by` STRING COMMENT 'Name or employee identifier of the person who initiated the request to establish this substitute component association, typically a supply chain planner, procurement specialist, or design engineer.',
    `requires_engineering_approval` BOOLEAN COMMENT 'Indicates whether use of this substitute component requires explicit engineering sign-off prior to production use, beyond the standard approval captured in the status field.. Valid values are `true|false`',
    `requires_quality_revalidation` BOOLEAN COMMENT 'Indicates whether use of this substitute component triggers a quality revalidation activity such as First Article Inspection (FAI), updated control plan, or re-qualification testing before production release.. Valid values are `true|false`',
    `restriction_notes` STRING COMMENT 'Detailed notes describing any restrictions, limitations, or special handling instructions associated with using this substitute component, including regulatory, safety, or performance constraints.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this substitute component association record was sourced, supporting data lineage and reconciliation in the Databricks Silver Layer.. Valid values are `SAP_S4HANA|TEAMCENTER|OPCENTER|MANUAL|ARIBA`',
    `source_system_key` STRING COMMENT 'The natural or surrogate key of this record in the originating source system (e.g., SAP substitute material record key), enabling reverse lookup and delta processing in the Silver Layer ingestion pipeline.',
    `standard_cost_delta` DECIMAL(18,2) COMMENT 'The difference in standard cost per unit between the substitute component and the primary component (substitute cost minus primary cost). Negative values indicate cost savings. Used for financial impact assessment and BOM costing.',
    `status` STRING COMMENT 'Current lifecycle and approval status of the substitute component record, governing whether it may be used in production planning and Material Requirements Planning (MRP) runs.. Valid values are `draft|pending_approval|approved|rejected|superseded|expired|withdrawn`',
    `substitution_reason_code` STRING COMMENT 'Standardized reason code explaining why this substitute component was identified and approved. Supports root cause analysis, supply chain resilience reporting, and procurement strategy decisions.. Valid values are `obsolescence|supply_shortage|cost_reduction|quality_improvement|regulatory_compliance|lead_time_reduction|supplier_change|engineering_change|emergency_procurement`',
    `substitution_type` STRING COMMENT 'Classification of the substitution relationship: full indicates the substitute is interchangeable in all contexts; conditional requires specific conditions to be met; temporary is time-bounded; emergency is approved only for urgent supply disruptions.. Valid values are `full|conditional|temporary|emergency`',
    `teamcenter_item_code` STRING COMMENT 'Reference identifier for this substitute component association record in Siemens Teamcenter PLM, enabling cross-system traceability between the Databricks Silver Layer and the PLM system of record.',
    `unit_of_measure` STRING COMMENT 'Unit of measure applicable to the substitute component quantity, which may differ from the primary components unit of measure when a conversion is required.. Valid values are `EA|KG|M|M2|M3|L|PC|SET|BOX|ROLL|MTR`',
    `use_condition` STRING COMMENT 'Free-text or structured description of the specific conditions under which this substitute may be used, such as only when primary component stock is zero, applicable for customer orders above 100 units, or valid only for non-safety-critical assemblies.',
    `valid_from_date` DATE COMMENT 'The date from which this substitute component association becomes effective and may be used in production planning and BOM resolution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'The date after which this substitute component association expires and is no longer valid for use. Null indicates no expiry. Used to manage temporary substitutions and time-bounded approvals.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_substitute_component PRIMARY KEY(`substitute_component_id`)
) COMMENT 'Association record defining approved substitute or alternate components that can replace a primary component in a BOM when the primary is unavailable or obsolete. Captures the primary component reference, substitute component reference, substitution type (full, conditional, temporary), applicable BOM context, approval status, and any use restrictions or quantity adjustments. Supports MRP exception handling and supply chain resilience.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`tooling_equipment` (
    `tooling_equipment_id` BIGINT COMMENT 'Unique surrogate identifier for each tooling and equipment master record in the engineering domain. Serves as the primary key for all downstream references.',
    `asset_register_id` BIGINT COMMENT 'Foreign key linking to finance.asset_register. Business justification: Tooling and equipment are capitalized assets tracked in the fixed asset register. Finance manages depreciation, book value, and asset lifecycle for financial reporting and tax compliance.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: tooling_equipment.part_number is a STRING reference to the component this tooling is designed to manufacture. Replacing with FK component_id → component.component_id establishes the authoritative tool',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Tooling is assigned to specific cost centers for depreciation allocation and maintenance cost tracking. Finance allocates asset depreciation to the owning cost center monthly.',
    `drawing_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_drawing. Business justification: tooling_equipment.drawing_number is a STRING reference to the engineering drawing for this tool design. Replacing with FK engineering_drawing_id → engineering_drawing.engineering_drawing_id establishe',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: tooling_equipment.ecn_number is a STRING reference to the ECN associated with this tooling design or modification. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for too',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Tooling and fixtures are physical assets requiring maintenance, calibration, and tracking. Links engineering tooling design to asset management for preventive maintenance, condition monitoring, and li',
    `it_asset_id` BIGINT COMMENT 'Foreign key linking to technology.it_asset. Business justification: Smart tooling and CNC equipment are IT assets requiring tracking for maintenance, depreciation, and lifecycle management. IT asset management maintains the master record for all capital equipment incl',
    `location_id` BIGINT COMMENT 'Foreign key linking to logistics.logistics_location. Business justification: Tooling equipment must track its physical storage location for inventory management and deployment planning. Manufacturing engineers use this daily to locate dies, molds, and fixtures when setting up ',
    `rd_project_id` BIGINT COMMENT 'Foreign key linking to research.rd_project. Business justification: Specialized tooling developed for R&D projects transitions to production tooling. Engineering tracks source R&D project to understand tooling design rationale, capabilities, and limitations for manufa',
    `certification_id` BIGINT COMMENT 'Foreign key linking to workforce.certification. Business justification: Specialized tooling and equipment (laser systems, pressure vessels, robotics) require operator certifications for safety compliance and insurance requirements. Manufacturing engineering tracks certifi',
    `acquisition_cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the acquisition cost amount (e.g., USD, EUR, CNY). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `associated_process_operation` STRING COMMENT 'The manufacturing process operation or Bill of Process (BoP) operation step for which this tool is designed or assigned (e.g., OP010 - Stamping, OP030 - CMM Inspection).',
    `calibration_interval_days` STRING COMMENT 'Frequency of required calibration expressed in calendar days. Applicable only when calibration_required is true. Drives the calibration schedule in the QMS.. Valid values are `^[0-9]+$`',
    `calibration_required` BOOLEAN COMMENT 'Indicates whether this tooling or equipment item requires periodic calibration per quality management system requirements. Drives calibration scheduling and compliance tracking.. Valid values are `true|false`',
    `commissioning_date` DATE COMMENT 'Date on which the tooling was formally accepted, qualified, and placed into active production service. Marks the start of tool life cycle tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `country_of_use` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country where this tooling is deployed. Supports multinational compliance, export control, and regional regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the tooling equipment master record was first created in the data platform. Used for audit trail and data lineage tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `cycles_used` STRING COMMENT 'Cumulative number of production cycles, shots, or strokes consumed against the rated tool life. Used to calculate remaining tool life and trigger preventive maintenance.. Valid values are `^[0-9]+$`',
    `description` STRING COMMENT 'Detailed technical description of the tooling or equipment, including its function, design intent, and applicable manufacturing process.',
    `design_revision` STRING COMMENT 'Current engineering design revision level of the tooling item, aligned with the PLM/PDM revision control system. Changes are tracked via ECN/ECO workflows.. Valid values are `^[A-Z0-9]{1,10}$`',
    `last_calibration_date` DATE COMMENT 'Date on which the most recent calibration was performed. Used to calculate next calibration due date and assess current compliance status.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_maintenance_date` DATE COMMENT 'Date on which the most recent preventive or corrective maintenance was completed on this tooling item.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the tooling equipment master record. Used for change tracking, data freshness monitoring, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `maintenance_interval_days` STRING COMMENT 'Scheduled preventive maintenance interval in calendar days for this tooling item. Drives work order generation in Maximo EAM and SAP PM.. Valid values are `^[0-9]+$`',
    `manufacture_date` DATE COMMENT 'Date on which the tooling item was manufactured or first commissioned. Used to calculate tool age, depreciation, and remaining useful life.. Valid values are `^d{4}-d{2}-d{2}$`',
    `name` STRING COMMENT 'Descriptive name of the tooling or equipment item (e.g., Progressive Die Stamping Tool, CMM Fixture Assembly, Injection Mold - Housing Cover).',
    `next_calibration_due_date` DATE COMMENT 'Scheduled date by which the next calibration must be completed to maintain compliance with quality management system requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `ownership_type` STRING COMMENT 'Indicates whether the tooling is owned by the manufacturing company, a customer (customer-supplied tooling), a supplier, or leased. Drives asset accounting treatment and liability.. Valid values are `company_owned|customer_owned|supplier_owned|leased`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this tooling or equipment is primarily assigned and managed.. Valid values are `^[A-Z0-9]{2,10}$`',
    `ppap_status` STRING COMMENT 'Approval status of the tooling under the Production Part Approval Process (PPAP). Required for automotive and industrial customers before production release.. Valid values are `not_required|pending|submitted|approved|rejected|conditionally_approved`',
    `responsible_engineer` STRING COMMENT 'Name or employee ID of the engineering owner responsible for the design, qualification, and lifecycle management of this tooling item.',
    `retirement_date` DATE COMMENT 'Date on which the tooling was formally retired or scrapped. Populated when status transitions to retired or scrapped. Used for asset lifecycle reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this tooling master record originates (e.g., SAP PM, Siemens Teamcenter, Maximo EAM).. Valid values are `SAP_PM|Teamcenter|Maximo|Opcenter|Manual|Other`',
    `source_system_key` STRING COMMENT 'The native primary key or equipment number from the originating source system (e.g., SAP PM Equipment Number, Teamcenter Item ID). Enables traceability and reconciliation.',
    `status` STRING COMMENT 'Current operational status of the tooling or equipment. Drives availability for production scheduling and triggers maintenance or procurement workflows.. Valid values are `active|under_repair|under_calibration|in_qualification|retired|scrapped|on_order|in_storage`',
    `supplier_name` STRING COMMENT 'Name of the external vendor or toolmaker who manufactured or supplied this tooling item. Used for supplier performance tracking and warranty claims.',
    `supplier_tool_number` STRING COMMENT 'The toolmakers or suppliers own reference number for this tooling item. Required for warranty claims, spare part ordering, and supplier communications.',
    `tool_category` STRING COMMENT 'Broader classification grouping tools by their lifecycle stage and investment level. Hard tooling is production-grade; soft tooling is used for prototyping or low-volume runs.. Valid values are `hard_tooling|soft_tooling|check_fixture|test_rig|prototype_tooling|production_tooling|mro_tooling`',
    `tool_life_cycles` STRING COMMENT 'Maximum rated tool life expressed in number of production cycles, shots, or strokes before the tool requires refurbishment or replacement. Used for predictive maintenance scheduling.. Valid values are `^[0-9]+$`',
    `tool_material` STRING COMMENT 'Primary material used in the construction of the tooling (e.g., H13 Tool Steel, P20 Steel, Aluminum 7075, Carbide, Hardened Steel). Influences tool life and maintenance requirements.',
    `tool_number` STRING COMMENT 'Business-assigned alphanumeric identifier for the tooling or equipment item, used across engineering, production, and maintenance systems. Corresponds to the tool number in SAP PM and Siemens Teamcenter.. Valid values are `^TL-[A-Z0-9]{3,20}$`',
    `tool_type` STRING COMMENT 'Classification of the tooling or equipment by its functional category. Drives maintenance schedules, calibration requirements, and tool life tracking policies.. Valid values are `die|mold|jig|fixture|gauge|test_equipment|cutting_tool|forming_tool|assembly_tool|inspection_tool|welding_fixture|cnc_tool|other`',
    `tool_weight_kg` DECIMAL(18,2) COMMENT 'Physical weight of the tooling assembly in kilograms. Used for logistics planning, crane/lift requirements, and storage rack load calculations.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `work_center_code` STRING COMMENT 'Code identifying the production work center or machine group where this tooling is primarily deployed. Aligns with SAP PP work center and Siemens Opcenter MES resource definitions.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    CONSTRAINT pk_tooling_equipment PRIMARY KEY(`tooling_equipment_id`)
) COMMENT 'Master record for specialized manufacturing tooling, jigs, fixtures, molds, and test equipment designed or managed by the engineering function. Captures tool number, tool type, associated process operation, design revision, tool material, tool life (shots or cycles), current status (active, under repair, retired), storage location, and calibration requirement flag. Distinct from production asset records owned by the asset domain.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`engineering_regulatory_certification` (
    `engineering_regulatory_certification_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory certification record in the lakehouse silver layer.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory certification costs (testing, agency fees, compliance) are charged to specific engineering cost centers. Finance tracks certification expenses for product cost allocation and budget managem',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: regulatory_certification.ecn_number is a STRING reference to the ECN associated with this certification update. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for regula',
    `product_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.product_certification. Business justification: Engineering tracks which product certifications (UL, CE, CSA) apply to components/products. Compliance manages the actual certification records, audits, and renewals. Engineering references these for ',
    `certificate_document_ref` STRING COMMENT 'Storage path, URL, or document management system reference to the scanned or digital copy of the official certificate or declaration document. Enables direct access to the source document for customer requests and audits.',
    `certificate_number` STRING COMMENT 'Official certificate or declaration reference number assigned by the certifying body or issuing authority. Used as the primary business identifier for tracking and referencing the certification externally.',
    `certification_standard` STRING COMMENT 'Specific standard, directive, or regulation under which the certification was granted (e.g., IEC 61131-3, ISO 9001:2015, EN 61000-4-2, UL 508A). Provides the normative reference for the certification scope.',
    `certification_type` STRING COMMENT 'Classification of the regulatory certification or compliance declaration. Identifies the specific regulatory framework or standard under which the certification was issued (e.g., CE Marking for EU market access, UL for North American safety, RoHS for hazardous substance restriction).. Valid values are `CE Marking|UL Certification|RoHS Declaration of Conformity|REACH SVHC Declaration|IEC Compliance|ISO Certification|OSHA Compliance|EPA Compliance|ANSI Certification|CSA Certification|TUV Certification|Other`',
    `certifying_body` STRING COMMENT 'Name of the accredited third-party organization, notified body, or regulatory authority that issued or recognized the certification (e.g., TÜV Rheinland, Bureau Veritas, UL LLC, BSI Group, SGS). Critical for validating certification authenticity.',
    `certifying_body_accreditation_number` STRING COMMENT 'Official accreditation number of the certifying body as registered with the relevant national accreditation authority (e.g., UKAS, DAkkS, A2LA). Validates the authority of the issuing body.',
    `country_of_certification` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country in which the certification was issued or the certifying body is domiciled. Relevant for mutual recognition agreements and cross-border regulatory acceptance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory certification record was first created in the system. Supports audit trail and data lineage requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `customer_facing_flag` BOOLEAN COMMENT 'Indicates whether this certification document is eligible to be shared with customers in response to documentation requests (e.g., via Salesforce CRM Service Cloud). Drives automated fulfillment of customer compliance documentation requests.. Valid values are `true|false`',
    `declaration_type` STRING COMMENT 'Indicates whether the compliance declaration is self-declared by the manufacturer or issued by an accredited third-party or notified body. Determines the level of independent verification and regulatory weight of the certification.. Valid values are `self_declaration|third_party_certification|notified_body_assessment|type_examination|type_approval|other`',
    `export_control_applicable` BOOLEAN COMMENT 'Indicates whether this certification has implications for export control compliance (e.g., dual-use goods, EAR/ITAR-controlled products). When true, the certification must be reviewed as part of export license determination.. Valid values are `true|false`',
    `geographic_market_scope` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes or regional market designations (e.g., EEA, USA, CAN) for which this certification grants market access. Drives export compliance and trade documentation.',
    `issue_date` DATE COMMENT 'Date on which the certification was officially issued or granted by the certifying body. Establishes the start of the certifications validity period.. Valid values are `^d{4}-d{2}-d{2}$`',
    `language_code` STRING COMMENT 'ISO 639-1 language code of the certification document (e.g., en, de, fr, zh). Supports multilingual documentation management for global market compliance.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this regulatory certification record. Used for change detection, incremental data loading, and audit trail maintenance in the lakehouse.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `last_surveillance_date` DATE COMMENT 'Date of the most recent surveillance audit or periodic review conducted by the certifying body to confirm continued compliance. Applicable for certifications requiring ongoing surveillance (e.g., ISO 9001, ISO 14001).. Valid values are `^d{4}-d{2}-d{2}$`',
    `legal_entity_name` STRING COMMENT 'Name of the legal entity (company or subsidiary) in whose name the certification is issued. Critical for multinational operations where certifications may be held by different legal entities across jurisdictions.',
    `next_surveillance_date` DATE COMMENT 'Scheduled date for the next surveillance audit or periodic review by the certifying body. Used for compliance calendar management and audit preparation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `owning_department` STRING COMMENT 'Name of the engineering or regulatory affairs department responsible for this certification (e.g., Product Compliance, Regulatory Affairs, Systems Engineering). Supports organizational accountability and workflow routing.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or legal entity responsible for maintaining this certification. Supports multi-site compliance management across global manufacturing operations.',
    `product_family` STRING COMMENT 'Product family or product line grouping to which the certified product belongs (e.g., SIMATIC S7 PLC Series, SINAMICS Drive Family). Enables portfolio-level compliance reporting.',
    `reach_compliant` BOOLEAN COMMENT 'Indicates whether the certified product complies with REACH Regulation (EC) No 1907/2006 requirements, including SVHC (Substances of Very High Concern) declaration obligations. Required for EU chemical compliance.. Valid values are `true|false`',
    `regulatory_directive` STRING COMMENT 'Specific EU directive, national regulation, or international regulatory instrument that mandates this certification (e.g., Low Voltage Directive 2014/35/EU, Machinery Directive 2006/42/EC, EMC Directive 2014/30/EU, RoHS Directive 2011/65/EU). Provides the legal basis for the certification requirement.',
    `renewal_due_date` DATE COMMENT 'Target date by which the certification renewal process must be initiated to avoid a lapse in validity. Typically set a defined number of days before the expiry date based on the certifying bodys renewal lead time.. Valid values are `^d{4}-d{2}-d{2}$`',
    `responsible_engineer` STRING COMMENT 'Name or employee ID of the engineer or compliance specialist responsible for managing and maintaining this certification. Accountable for renewal, surveillance, and customer documentation requests.',
    `rohs_compliant` BOOLEAN COMMENT 'Indicates whether the certified product meets the requirements of the RoHS Directive (2011/65/EU) restricting the use of hazardous substances in electrical and electronic equipment. Mandatory for EU market access.. Valid values are `true|false`',
    `scope_description` STRING COMMENT 'Detailed description of the scope of the certification, including specific product configurations, variants, models, or use cases covered. Defines the boundaries of the certifications applicability.',
    `source_system` STRING COMMENT 'Operational system of record from which this certification record was sourced (e.g., Siemens Teamcenter PLM, SAP S/4HANA QM). Supports data lineage tracking in the lakehouse silver layer.. Valid values are `Teamcenter|SAP_S4HANA|Manual|Other`',
    `source_system_key` STRING COMMENT 'Primary key or unique identifier of this certification record in the originating source system (e.g., Teamcenter document ID, SAP QM certificate number). Enables traceability and reconciliation between the lakehouse and source systems.',
    `standard_clause` STRING COMMENT 'Specific clause, section, or annex of the referenced standard or directive that the certification addresses. Enables granular compliance tracking at the clause level.',
    `status` STRING COMMENT 'Current validity status of the regulatory certification. Drives export compliance checks, customer documentation fulfillment, and market access eligibility. Active certifications are required for product shipment to regulated markets.. Valid values are `active|expired|suspended|withdrawn|pending|under_review|revoked`',
    `svhc_above_threshold` BOOLEAN COMMENT 'Indicates whether the product contains SVHC substances above the 0.1% w/w threshold as defined by REACH Article 59. When true, a SVHC declaration must be provided to customers and downstream users upon request.. Valid values are `true|false`',
    `technical_file_reference` STRING COMMENT 'Document management reference or PLM document ID for the technical file or declaration of conformity dossier maintained to support this certification. Required for CE Marking and other EU regulatory frameworks.',
    `test_report_number` STRING COMMENT 'Reference number of the test report or technical assessment report that forms the evidentiary basis for the certification. Links to the design validation test records and technical file.',
    CONSTRAINT pk_engineering_regulatory_certification PRIMARY KEY(`engineering_regulatory_certification_id`)
) COMMENT 'Master record tracking product-level regulatory certifications and compliance declarations required for market access. Captures certification type (CE Marking, UL, RoHS Declaration of Conformity, REACH SVHC Declaration, IEC compliance), certifying body, certificate number, issue date, expiry date, applicable product or component, geographic market scope, and current validity status. Supports export compliance and customer documentation requests.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_revision` (
    `component_revision_id` BIGINT COMMENT 'Unique surrogate identifier for each component revision record in the silver layer lakehouse. Serves as the primary key for this entity.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: component_revision.component_number is a STRING reference to the parent component this revision belongs to. Replacing with FK component_id → component.component_id establishes the authoritative revisi',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: component_revision.ecn_number is a STRING reference to the ECN that authorized this component revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for component revi',
    `eco_id` BIGINT COMMENT 'Foreign key linking to engineering.eco. Business justification: component_revision.eco_number is a STRING reference to the ECO that authorized the implementation of this component revision. Replacing with FK eco_id → eco.eco_id enforces the full ECN→ECO→revision i',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering authority who formally approved this component revision for release. Required for regulatory audit trails and quality management compliance.',
    `approved_timestamp` TIMESTAMP COMMENT 'The exact date and time when this component revision was approved by the authorized engineering reviewer. Provides a precise audit trail for regulatory compliance and change management.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `bom_revision_level` STRING COMMENT 'The revision level of the Bill of Materials (BOM) associated with this component revision. Captures the BOM state at the time of this revision for full product structure genealogy.. Valid values are `^[A-Z0-9]{1,10}$`',
    `cad_model_reference` STRING COMMENT 'Reference identifier to the CAD/CAM model file in Teamcenter or the PDM vault that represents the 3D geometry and design data for this component at this revision level.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this component revision record was first created in the source system (Teamcenter or SAP ECM). Used for audit trail, data lineage, and change history reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `dfmea_reference` STRING COMMENT 'Reference number of the Design Failure Mode and Effects Analysis (DFMEA) document associated with this component revision. Links the revision to its risk assessment documentation for APQP and regulatory compliance.',
    `drawing_number` STRING COMMENT 'Reference to the engineering drawing number associated with this component revision. Links to the controlled drawing document in the engineering_drawing product for full technical specification traceability.',
    `drawing_revision_level` STRING COMMENT 'The specific revision level of the engineering drawing that corresponds to this component revision, ensuring the correct drawing version is associated with the component state.. Valid values are `^[A-Z0-9]{1,10}$`',
    `effectivity_end_date` DATE COMMENT 'The date on which this component revision was superseded or became no longer effective. A null value indicates the revision is currently active. Supports time-bounded product genealogy queries.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_start_date` DATE COMMENT 'The date from which this component revision became effective for use in production, procurement, and BOM structures. Defines the start of the validity period for this revision.. Valid values are `^d{4}-d{2}-d{2}$`',
    `export_control_classification` STRING COMMENT 'Export control classification for this component revision under US EAR (Export Administration Regulations) or ITAR. Required for international trade compliance and customs documentation. May change across revisions if technology content changes.. Valid values are `EAR99|ECCN_[A-Z0-9]{5}|ITAR|NLR|AT|NS|MT|CC|RS|FC|UN|AT`',
    `is_form_fit_function_change` BOOLEAN COMMENT 'Indicates whether this revision constitutes a Form, Fit, or Function (FFF) change that affects interchangeability with the previous revision. FFF changes typically require customer notification, PPAP resubmission, and regulatory re-evaluation.. Valid values are `true|false`',
    `is_reach_compliant` BOOLEAN COMMENT 'Indicates whether this component revision complies with EU REACH regulation requirements at this specific revision level. Tracks compliance state per revision for regulatory audit and supply chain transparency.. Valid values are `true|false`',
    `is_rohs_compliant` BOOLEAN COMMENT 'Indicates whether this component revision complies with the EU Restriction of Hazardous Substances (RoHS) directive at this specific revision level. Compliance status may change across revisions due to material or supplier changes.. Valid values are `true|false`',
    `is_safety_critical` BOOLEAN COMMENT 'Indicates whether this component revision is classified as safety-critical, requiring enhanced design controls, additional validation testing, and regulatory approval before implementation.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this component revision record in the source system. Supports incremental data loading, change detection, and audit trail requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lifecycle_phase` STRING COMMENT 'The product lifecycle phase of the component at this revision level, aligned with APQP phase gates. Determines applicability for production, procurement, and service activities.. Valid values are `concept|design|prototype|pilot|production|end_of_life|obsolete`',
    `material_specification` STRING COMMENT 'The material specification or standard applicable to this component at this revision level (e.g., ASTM A36, DIN EN 10025). Captures the specification state as it existed at this revision.',
    `plant_code` STRING COMMENT 'The SAP plant code where this component revision is applicable or was first released. Supports multi-plant manufacturing operations and plant-specific revision management.',
    `ppap_level` STRING COMMENT 'The PPAP submission level (1-5) required for this component revision, as defined by the customer or internal quality standards. Determines the extent of documentation and sample submission required.. Valid values are `1|2|3|4|5`',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process (PPAP) submission is required for this revision due to the nature of the change. Driven by customer-specific requirements and the FFF change classification.. Valid values are `true|false`',
    `previous_revision_level` STRING COMMENT 'The revision level that this revision supersedes, enabling full genealogy traceability and revision chain reconstruction for audit and regulatory purposes.. Valid values are `^[A-Z0-9]{1,10}$`',
    `release_date` DATE COMMENT 'The date on which this component revision was formally released from engineering into production use, as recorded in Teamcenter PLM. Marks the transition from design to released state.. Valid values are `^d{4}-d{2}-d{2}$`',
    `revision_level` STRING COMMENT 'The alphanumeric revision identifier for this specific version of the component (e.g., A, B, C, 01, 02). Corresponds to the revision level managed in Teamcenter and SAP ECM. Each new ECN/ECO increments this value.. Valid values are `^[A-Z0-9]{1,10}$`',
    `revision_reason_code` STRING COMMENT 'Standardized reason code explaining why this revision was created. Supports root cause analysis, change trend reporting, and CAPA linkage.. Valid values are `design_improvement|defect_correction|cost_reduction|regulatory_compliance|supplier_qualification|customer_request|safety_improvement|obsolescence|process_optimization|documentation_correction`',
    `revision_reason_description` STRING COMMENT 'Free-text narrative describing the specific business or technical reason for this revision, providing context beyond the standardized reason code for audit and engineering review purposes.',
    `revision_status` STRING COMMENT 'Current lifecycle state of this component revision as managed in Teamcenter PLM. Controls whether the revision is available for use in BOMs, production, and procurement activities.. Valid values are `in_work|in_review|released|frozen|obsolete|superseded`',
    `revision_type` STRING COMMENT 'Classification of the reason category driving this revision. Used for change analytics, regulatory reporting, and APQP/PPAP documentation.. Valid values are `engineering_change|design_correction|regulatory_update|cost_reduction|supplier_change|process_change|documentation_only`',
    `sap_material_revision` STRING COMMENT 'The revision level as recorded in SAP S/4HANA MM/ECM for this component, enabling cross-system reconciliation between the PLM system of record and the ERP system.',
    `standard_cost` DECIMAL(18,2) COMMENT 'The standard cost of the component at this revision level as maintained in SAP S/4HANA CO. Captures the cost state at the time of revision for cost impact analysis and COGS reporting.. Valid values are `^d+(.d{1,4})?$`',
    `standard_cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the standard cost value (e.g., USD, EUR, CNY). Supports multi-currency operations across global manufacturing plants.. Valid values are `^[A-Z]{3}$`',
    `teamcenter_item_revision_code` STRING COMMENT 'The native item revision identifier from Siemens Teamcenter PLM, used for cross-system traceability and data lineage back to the authoritative PLM source of record.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure for this component at this revision level, as defined in SAP S/4HANA MM. Used for BOM quantity calculations, procurement, and inventory management.. Valid values are `EA|KG|M|M2|M3|L|SET|PCE|FT|LB`',
    `weight_kg` DECIMAL(18,2) COMMENT 'The mass of the component in kilograms at this revision level. May change across revisions due to design modifications, material changes, or DFM/DFA optimization activities.. Valid values are `^d+(.d{1,4})?$`',
    CONSTRAINT pk_component_revision PRIMARY KEY(`component_revision_id`)
) COMMENT 'Historical record capturing each revision of a component or part master, preserving the full technical state at each revision level including specification values, BOM linkages, drawing references, and the reason for revision. Enables full product genealogy traceability and supports regulatory audit requirements. Sourced from Teamcenter revision management and SAP ECM revision history.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_carrier_qualification` (
    `component_carrier_qualification_id` BIGINT COMMENT 'Primary key for component_carrier_qualification',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to the approved freight carrier',
    `component_id` BIGINT COMMENT 'Foreign key linking to the engineered component being qualified for transport',
    `supplier_qualification_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each component-carrier qualification record',
    `approved_date` DATE COMMENT 'Date when the carrier was approved to transport this specific component, following qualification testing and compliance verification',
    `handling_instructions` STRING COMMENT 'Detailed handling procedures the carrier must follow for this component (e.g., orientation restrictions, stacking limits, loading sequence, equipment requirements)',
    `incident_count` BIGINT COMMENT 'Number of damage or handling incidents reported for this specific component-carrier combination. Used in qualification review and carrier performance scoring.',
    `last_audit_date` DATE COMMENT 'Date of the most recent compliance audit or performance review for this component-carrier qualification',
    `max_shock_rating` DECIMAL(18,2) COMMENT 'Maximum shock or impact force (in G-force) the component can withstand during transport by this carrier. Used to validate carrier handling procedures and equipment.',
    `notes` STRING COMMENT 'Free-text notes capturing special conditions, restrictions, or historical context for this component-carrier qualification',
    `packaging_requirements` STRING COMMENT 'Specific packaging specifications required for this component when transported by this carrier (e.g., anti-static bags, shock-absorbing foam, climate-controlled containers, UN-certified hazmat packaging)',
    `qualification_expiry_date` DATE COMMENT 'Date when this carrier qualification expires and requires re-certification for continued transport of this component',
    `qualification_status` STRING COMMENT 'Current status of the carrier qualification for this component (PENDING, APPROVED, SUSPENDED, REVOKED, EXPIRED). Drives carrier selection logic in TMS route planning.',
    `temperature_range` STRING COMMENT 'Allowable temperature range during transport for this component-carrier combination (e.g., 15-25°C, -20 to +60°C). Used to validate carrier equipment capabilities.',
    CONSTRAINT pk_component_carrier_qualification PRIMARY KEY(`component_carrier_qualification_id`)
) COMMENT 'This association product represents the qualification and approval relationship between engineered components and freight carriers. It captures the carrier qualification process for components with special handling requirements (fragile electronics, precision machined parts, hazardous materials). Each record links one component to one approved carrier with qualification status, handling instructions, packaging requirements, and environmental constraints that exist only in the context of this specific component-carrier pairing.. Existence Justification: In industrial manufacturing logistics, components with special handling requirements (fragile electronics, precision machined parts, hazardous materials) require carrier qualification before transport. A single component can be approved for transport by multiple carriers (providing redundancy and competitive routing options), and each carrier is qualified to handle many different component types. The qualification relationship itself carries operational data including approval dates, qualification status, component-specific packaging requirements, handling instructions, environmental constraints (temperature, shock ratings), and performance tracking (incident counts, audit dates).';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_certification` (
    `component_certification_id` BIGINT COMMENT 'Unique surrogate key identifying each component-certification relationship record',
    `component_id` BIGINT COMMENT 'Foreign key linking to the engineered component being certified',
    `engineering_regulatory_certification_id` BIGINT COMMENT 'Foreign key to engineering.regulatory_certification.regulatory_certification_id',
    `certification_status` STRING COMMENT 'Current validity status of this specific component-certification pairing. Drives export compliance checks and customer documentation eligibility.',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this component-certification relationship record was created in the system',
    `expiry_date` DATE COMMENT 'Date on which this component-certification relationship expires and the component can no longer be sold or used under this certification in the specified markets. Drives renewal workflows.',
    `geographic_market_scope` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes or regional market designations where this specific component-certification pairing is valid. Enables market-specific compliance tracking.',
    `issue_date` DATE COMMENT 'Date on which this specific component-certification relationship became valid, typically when the certification was granted or when the component was added to an existing certification scope.',
    `last_updated_date` TIMESTAMP COMMENT 'Timestamp when this component-certification relationship record was last modified',
    `product_revision` STRING COMMENT 'Specific engineering revision level of the component that is covered by this certification instance. Critical because design changes may invalidate certifications and require recertification.',
    `responsible_engineer` STRING COMMENT 'Name or employee ID of the engineer or compliance specialist responsible for managing this specific component-certification relationship, including renewal and scope maintenance.',
    `scope_description` STRING COMMENT 'Detailed description of what aspects of this component are covered by this certification, including specific features, configurations, or use cases that fall within the certification scope.',
    CONSTRAINT pk_component_certification PRIMARY KEY(`component_certification_id`)
) COMMENT 'This association product represents the certification relationship between engineered components and regulatory certifications. It captures the specific certification scope, geographic market applicability, and validity period for each component-certification pairing. Each record links one component to one regulatory certification with attributes that exist only in the context of this specific certification instance, enabling tracking of multi-market compliance, revision-specific certifications, and certification lifecycle management.. Existence Justification: In industrial manufacturing, components require multiple certifications for different markets (a motor may need CE for EU, UL for US, CSA for Canada, IECEx for hazardous locations), and each certification typically covers multiple components within a product family or platform. The business actively manages these relationships with revision-specific tracking (design changes invalidate certifications), market-specific scopes, and lifecycle management (issue dates, expiry dates, renewal workflows). This is an operational M:N relationship where the pairing itself carries critical compliance data.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_evaluation` (
    `component_evaluation_id` BIGINT COMMENT 'Unique system-generated identifier for each component evaluation record',
    `component_id` BIGINT COMMENT 'Foreign key linking to the component being evaluated in this R&D project',
    `rd_project_id` BIGINT COMMENT 'Foreign key linking to the R&D project conducting the component evaluation',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this component evaluation record was created in the system.',
    `decision_date` DATE COMMENT 'Date when the final selection decision was made for this component in this R&D project context.',
    `evaluated_by` STRING COMMENT 'Name or employee identifier of the engineer or researcher responsible for conducting and documenting this component evaluation.',
    `evaluation_end_date` DATE COMMENT 'Date when the evaluation of this component for this R&D project was completed or closed. Populated when final selection decision is made.',
    `evaluation_notes` STRING COMMENT 'Free-text notes capturing qualitative observations, test results, technical findings, and decision rationale specific to this component-project evaluation.',
    `evaluation_start_date` DATE COMMENT 'Date when the evaluation of this component for this specific R&D project was initiated. Marks the beginning of the assessment and testing process.',
    `evaluation_status` STRING COMMENT 'Current status of the component evaluation within the R&D project lifecycle. Tracks progression from initial consideration through testing to final selection decision.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this component evaluation record was last modified.',
    `performance_rating` DECIMAL(18,2) COMMENT 'Quantitative performance score assigned to this component based on testing results within this specific R&D project context. Scale typically 0.00-5.00 or 0.00-10.00 depending on organizational standards.',
    `selection_decision` STRING COMMENT 'Final decision outcome for this component evaluation indicating whether the component was selected for use in the R&D project.',
    `test_priority` STRING COMMENT 'Priority level assigned to this component evaluation within the R&D project, determining resource allocation and testing sequence for technology selection decisions.',
    CONSTRAINT pk_component_evaluation PRIMARY KEY(`component_evaluation_id`)
) COMMENT 'This association product represents the evaluation relationship between components and R&D projects. It captures the testing, assessment, and selection process where engineering components are evaluated for potential use in R&D innovation initiatives. Each record links one component to one R&D project with evaluation-specific attributes including test status, priority, performance ratings, and evaluation timeline that exist only in the context of this assessment relationship.. Existence Justification: In industrial manufacturing R&D operations, component evaluation is a formal business process where R&D projects systematically assess multiple existing components for potential use in new automation and electrification solutions, and individual components are evaluated across multiple concurrent R&D projects as technology selection candidates. The business actively manages these evaluations with specific status tracking, priority assignment, performance ratings, and decision workflows that belong to the evaluation relationship itself, not to the component or project independently.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_measurement_plan` (
    `component_measurement_plan_id` BIGINT COMMENT 'Unique system-generated identifier for each component-gauge measurement plan record',
    `component_id` BIGINT COMMENT 'Foreign key to engineering.component identifying the component being measured',
    `gauge_id` BIGINT COMMENT 'Foreign key linking to the measurement instrument used for inspection',
    `characteristic_name` STRING COMMENT 'Specific component feature or characteristic being measured (e.g., shaft_diameter, hole_depth, surface_finish, thread_pitch). This attribute belongs to the relationship because the same component may have multiple characteristics measured by different gauges.',
    `control_method` STRING COMMENT 'Statistical or inspection control method applied to this measurement (e.g., SPC for statistical process control, go_no_go for pass/fail gauging). Explicitly identified in detection phase relationship data.',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this measurement plan record was created in the system.',
    `effective_date` DATE COMMENT 'Date from which this measurement plan becomes active and must be followed in production inspection.',
    `expiry_date` DATE COMMENT 'Date on which this measurement plan is superseded or retired, typically due to component revision changes or gauge replacement.',
    `frequency` STRING COMMENT 'Inspection sampling frequency defining how often this measurement must be performed (e.g., per_unit for 100% inspection, per_batch for sampling). Explicitly identified in detection phase relationship data.',
    `is_critical_characteristic` BOOLEAN COMMENT 'Indicates whether this measurement is for a critical characteristic that directly affects safety, regulatory compliance, or key functional performance. Critical characteristics require enhanced control and documentation.',
    `last_modified_by` STRING COMMENT 'User ID or name of the person who last updated this measurement plan record.',
    `last_modified_date` TIMESTAMP COMMENT 'Timestamp of the most recent update to this measurement plan record.',
    `measurement_location` STRING COMMENT 'Physical location or reference point on the component where the measurement is taken, as defined in the inspection drawing or control plan.',
    `measurement_type` STRING COMMENT 'Classification of the characteristic being measured (e.g., dimensional for length/width, electrical for resistance, mechanical for torque). Explicitly identified in detection phase relationship data.',
    `plan_status` STRING COMMENT 'Lifecycle status of the measurement plan record indicating whether it is currently in use for production inspection.',
    `sample_size` STRING COMMENT 'Number of units to be measured per inspection event when sampling inspection is used. Explicitly identified in detection phase relationship data.',
    `tolerance_range` STRING COMMENT 'Acceptable tolerance specification for this measurement in the format of upper and lower limits (e.g., ±0.05mm, 10-12 ohms). Explicitly identified in detection phase relationship data.',
    `created_by` STRING COMMENT 'User ID or name of the quality engineer who created this measurement plan record.',
    CONSTRAINT pk_component_measurement_plan PRIMARY KEY(`component_measurement_plan_id`)
) COMMENT 'This association product represents the measurement control plan between engineered components and quality gauges. It captures which measurement instruments are designated to inspect which component characteristics, including the measurement methodology, tolerance specifications, sampling frequency, and control method. Each record links one component to one gauge with attributes that define the inspection protocol for that specific component-gauge pairing.. Existence Justification: In industrial manufacturing quality operations, one component requires measurement of multiple characteristics using different gauges (e.g., a shaft component measured by calipers for length, micrometers for diameter, and surface roughness testers for finish). Conversely, one gauge is used to measure the same characteristic across multiple different components (e.g., a digital caliper measuring length on shafts, brackets, and housings). The business actively manages measurement plans as operational artifacts that define inspection protocols, including which gauge measures which component characteristic, with what tolerance, frequency, and control method.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_compliance` (
    `component_compliance_id` BIGINT COMMENT 'Primary key for the component_compliance association',
    `component_id` BIGINT COMMENT 'Foreign key linking to the engineered component being assessed for compliance',
    `employee_id` BIGINT COMMENT 'Foreign key reference to the user or compliance officer who performed or approved the compliance assessment for this component-requirement relationship.',
    `regulatory_requirement_id` BIGINT COMMENT 'Foreign key linking to the regulatory requirement that must be satisfied',
    `applicable_jurisdiction` STRING COMMENT 'The specific geographic jurisdiction where this component-requirement compliance relationship applies. A component may comply with a requirement in one jurisdiction but not another due to local variations in enforcement or exemptions.',
    `assessment_notes` STRING COMMENT 'Free-text notes documenting the compliance assessment, including test results, certification references, exemption justifications, or reasons for non-compliance. Provides audit trail and context for compliance decisions.',
    `certificate_expiry_date` DATE COMMENT 'Expiration date of the compliance certificate or declaration of conformity for this component-requirement pair. After this date, recertification is required.',
    `certificate_number` STRING COMMENT 'Unique identifier or reference number of the compliance certificate, test report, or declaration of conformity issued for this component-requirement combination.',
    `certifying_body` STRING COMMENT 'Name of the third-party testing laboratory, certification body, or internal assessment team that verified compliance for this component-requirement pair (e.g., UL, TÜV, SGS, internal lab).',
    `compliance_status` STRING COMMENT 'Current compliance status of this specific component against this specific regulatory requirement in the applicable jurisdiction. Tracks whether the component meets the obligation, is under assessment, or has been granted an exemption.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this component-compliance record was first created in the compliance management system.',
    `exemption_claimed` BOOLEAN COMMENT 'Indicates whether an exemption from this regulatory requirement has been claimed for this component in this jurisdiction. Exemptions may be granted based on use case, material concentration thresholds, or other regulatory provisions.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this component-compliance record was last modified, reflecting changes to status, verification dates, or assessment notes.',
    `next_verification_due_date` DATE COMMENT 'Scheduled date for the next periodic compliance verification or recertification of this component against this requirement. Driven by the requirements compliance_frequency and regulatory obligations.',
    `verification_date` DATE COMMENT 'Date on which compliance with this regulatory requirement was last verified or assessed for this component. Used to track recertification schedules and audit trails.',
    CONSTRAINT pk_component_compliance PRIMARY KEY(`component_compliance_id`)
) COMMENT 'This association product represents the compliance relationship between engineered components and regulatory requirements. It captures jurisdiction-specific compliance status, verification evidence, and exemption claims for each component-requirement pair. Each record links one component to one regulatory requirement with attributes that exist only in the context of this specific compliance obligation.. Existence Justification: In industrial manufacturing, each engineered component must comply with multiple regulatory requirements (RoHS, REACH, UL, CE, IEC, ISO standards) across different global jurisdictions where products are sold. Conversely, each regulatory requirement applies to thousands of components across product lines. Compliance teams actively manage this matrix, tracking jurisdiction-specific compliance status, verification dates, exemption claims, and certification evidence for each component-requirement pair.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`test_requirement_verification` (
    `test_requirement_verification_id` BIGINT COMMENT 'Unique system-generated identifier for each test-requirement verification record',
    `design_validation_test_id` BIGINT COMMENT 'Foreign key linking to the design validation test that provides verification evidence',
    `regulatory_requirement_id` BIGINT COMMENT 'Foreign key linking to the regulatory requirement being verified',
    `certification_reference_number` STRING COMMENT 'Reference number or certificate ID issued by the certifying body for this specific verification, used in regulatory submissions',
    `certifying_body` STRING COMMENT 'The certification authority or notified body that recognizes this test as valid evidence for the requirement (e.g., UL, TÜV, CSA, notified body number for CE Marking)',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this verification record was created',
    `deviation_waiver_number` STRING COMMENT 'Reference to any deviation waiver or engineering change notice that allows conditional pass or acceptance despite non-conformance',
    `included_in_submission` BOOLEAN COMMENT 'Indicates whether this specific verification is included in the regulatory submission package for the requirement',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this verification record was last modified',
    `test_standard_clause` STRING COMMENT 'Specific clause, section, or sub-requirement within the test standard that addresses this regulatory requirement. This is the mapping between the test methodology and the compliance obligation.',
    `verification_date` DATE COMMENT 'Date on which this specific requirement was verified through the test. May differ from overall test completion date if requirements are verified incrementally.',
    `verification_notes` STRING COMMENT 'Additional context or notes specific to how this test verifies this requirement, including any special conditions or interpretations',
    `verification_result` STRING COMMENT 'Pass/fail status of this specific requirement verification within the broader test. A single test may verify multiple requirements with different results.',
    CONSTRAINT pk_test_requirement_verification PRIMARY KEY(`test_requirement_verification_id`)
) COMMENT 'This association product represents the verification relationship between design validation tests and regulatory requirements. It captures which specific regulatory requirements are verified by each design validation test, including the test standard clause used, the pass/fail result for that specific requirement, the test date, and the certifying body. Each record links one design validation test to one regulatory requirement with attributes that exist only in the context of this verification relationship. This is critical for certification documentation, audit evidence, and regulatory submission packages.. Existence Justification: In industrial manufacturing, a single design validation test (e.g., EMC testing, environmental stress testing) routinely verifies compliance with multiple regulatory requirements across different standards (ISO, IEC, UL, CE Marking). Conversely, a single regulatory requirement (e.g., IEC 62443 cybersecurity controls) is verified through multiple different tests (penetration testing, functional validation, stress testing). The verification relationship itself carries critical data including which test standard clause satisfies which requirement, the pass/fail result for that specific requirement, and the certifying body that recognizes the verification.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`specification_compliance_mapping` (
    `specification_compliance_mapping_id` BIGINT COMMENT 'Unique surrogate identifier for each specification-to-requirement compliance mapping record',
    `product_specification_id` BIGINT COMMENT 'Foreign key linking to the product specification record that addresses the regulatory requirement',
    `regulatory_requirement_id` BIGINT COMMENT 'Foreign key linking to the regulatory requirement being addressed by the specification',
    `compliance_method` STRING COMMENT 'Method by which compliance with this regulatory requirement is demonstrated through this specification (e.g., Design, Testing, Analysis, Inspection, Certification, Documentation, Supplier Declaration). Aligns with verification_method in product_specification but specific to this requirement.',
    `deviation_approved` BOOLEAN COMMENT 'Indicates whether a formal deviation or waiver has been approved for this specification-requirement mapping, allowing the specification to not fully meet the requirement under documented conditions. Requires approval workflow.',
    `deviation_reference` STRING COMMENT 'Reference number or document identifier for the approved deviation or waiver, if applicable. Links to formal deviation management system.',
    `last_verified_date` DATE COMMENT 'Date when compliance with this requirement was last verified for this specification. Used to track verification currency and trigger re-verification when specifications or requirements change.',
    `mapped_by` STRING COMMENT 'Name or employee identifier of the engineer or compliance specialist who created this specification-to-requirement mapping. Supports accountability and audit trail.',
    `mapped_timestamp` TIMESTAMP COMMENT 'Date and time when this specification-to-requirement mapping was created in the system. Supports compliance audit trail and traceability reporting.',
    `notes` STRING COMMENT 'Free-text notes providing additional context about this specification-to-requirement mapping, including interpretation guidance, special conditions, or cross-references to related mappings.',
    `requirement_section` STRING COMMENT 'Specific section, clause, or parameter within the product specification that addresses this regulatory requirement (e.g., Section 3.2.1, Parameter: Input Voltage Range). Enables traceability from requirement to specification detail.',
    `test_reference` STRING COMMENT 'Reference to supporting test documentation, test report number, certification document, or analysis report that provides evidence of compliance for this mapping (e.g., TR-2024-0156, Cert-CE-2024-089). Enables audit trail.',
    `verification_status` STRING COMMENT 'Current status of compliance verification for this specific specification-requirement mapping. Tracks whether the specification has been verified to meet the requirement through the defined compliance method.',
    `verified_by` STRING COMMENT 'Name or employee identifier of the engineer, quality specialist, or third-party auditor who performed the compliance verification for this mapping. Supports audit trail.',
    CONSTRAINT pk_specification_compliance_mapping PRIMARY KEY(`specification_compliance_mapping_id`)
) COMMENT 'This association product represents the compliance relationship between product specifications and regulatory requirements in the engineering and compliance lifecycle. It captures which specific sections of a product specification address which regulatory requirements, the method used to demonstrate compliance, verification status, supporting test documentation, and any approved deviations. Each record links one product specification to one regulatory requirement with attributes that exist only in the context of this compliance mapping relationship. Used extensively in design reviews, certification processes, and regulatory audits.. Existence Justification: In industrial manufacturing, product specifications must satisfy multiple regulatory requirements (RoHS, REACH, CE, IEC standards, etc.), and each regulatory requirement applies to multiple product specifications across different product families. Engineering teams actively manage compliance mappings as operational records during design reviews and certification processes, tracking which specification sections address which requirements, verification methods, test evidence, and approved deviations. This is not an analytical correlation but an operational business process.';

